    try {
      const seed = Math.floor(Math.random() * 10000);
      const safeWord = encodeURIComponent(word);
      return `https://image.pollinations.ai/prompt/minimalist%20flat%20vector%20icon%20${safeWord}%20white%20background?nologo=true&seed=${seed}&width=512&height=512`;
    } catch (e) {
      return null;
    }
  });
};

// ==========================================
// MEDIA & DATA FETCHING
// ==========================================

export const fetchMediaForWord = async (word: WordData): Promise<WordData> => {
  const updatedWord = { ...word };
  let hasChanges = false;

  // Only generate Image now. No more music fetching.
  if (!updatedWord.imageUrl) {
      const imageUrl = await generateWordImage(updatedWord.word);
      if (imageUrl) {
          updatedWord.imageUrl = imageUrl;
          hasChanges = true;
      }
  }

  return hasChanges ? updatedWord : word;
};

// STREAMING Implementation
export const streamVocabularyEnrichment = async (
  words: string[],
  onWordReceived: (word: WordData) => void
): Promise<void> => {
  if (words.length === 0) return;

  const prompt = `
    I have a list of English vocabulary words: ${words.join(', ')}.

    For EACH word, generate a JSON object.

    IMPORTANT FORMATTING RULES:
    1. Output strictly **NDJSON** (Newline Delimited JSON). 
    2. Write ONE valid JSON object per line.
    3. Do NOT wrap the output in [ ] or a list.

    Schema for each object:
    {
      "word": "string (lowercase)",
      "definition": "string (Precise and comprehensive Simplified Chinese definition. If the word has multiple distinct meanings or parts of speech, separate them with '; '. Example: 'n. 银行; v. 堆积'. Avoid ambiguous single characters.)",
      "partOfSpeech": "string (e.g. noun, verb)",
      "exampleSentence": "string (English sentence with the word replaced by '_______'. The sentence must clearly demonstrate the word's meaning context.)",
      "quote": {
        "english": "string (A short, witty joke OR a common proverb/idiom that uses this word. Must be under 25 words.)",
        "chinese": "string (Translation of the quote in Chinese)"
      }
    }

    INSTRUCTIONS FOR 'definition':
    - Be specific. Instead of "跑" for "Run", use "v. 奔跑；经营；运行".
    - Avoid machine-translation style. Use natural language suitable for a learner.

    INSTRUCTIONS FOR 'quote':
    - It must be fun or insightful.
    - If the word is common, use a famous proverb.
    - If the word is obscure, use a short, clean joke.
    - The word itself MUST appear in the English quote.
  `;

  try {
    const ai = getAi(); // Use the safe getter
    const response = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    let buffer = '';

    for await (const chunk of response) {
      const text = chunk.text;
      if (!text) continue;

      buffer += text;

      const lines = buffer.split('\n');
      buffer = lines.pop() || '';

      for (const line of lines) {
        processLine(line, onWordReceived);
      }
    }

    if (buffer.trim()) {
      processLine(buffer, onWordReceived);
    }

  } catch (error: any) {
    console.error("Gemini Streaming Error:", error);
    // Propagate the specific API Key error if present
    if (error.message && (error.message.includes('API Key') || error.message.includes('API key'))) {
        throw error;
    }
    throw new Error("生成流中断，请重试。");
  }
};

const processLine = (line: string, callback: (word: WordData) => void) => {
  const cleanLine = line.trim();
  if (!cleanLine) return;

  let jsonString = cleanLine
    .replace(/^```json/, '')
    .replace(/^```/, '')
    .replace(/```$/, '')
    .replace(/^\[/, '') 
    .replace(/,$/, '')  
    .replace(/\]$/, '');

  try {
    const item = JSON.parse(jsonString);

    if (item.word && item.definition) {
        // Handle legacy string format if necessary, though we prefer object now
        let quoteObj = undefined;
        if (item.quote) {
          if (typeof item.quote === 'string') {
             quoteObj = { english: item.quote, chinese: '' };
          } else {
             quoteObj = item.quote;
          }
        }

        const wordData: WordData = {
          id: crypto.randomUUID(),
          word: item.word.toLowerCase().trim(),
          definition: item.definition,
          exampleSentence: item.exampleSentence || "No example available.",
          partOfSpeech: item.partOfSpeech || "",
          quote: quoteObj, 

          correctCount: 0,
          imageUrl: undefined,
        };
        callback(wordData);
    }
  } catch (e) {
    // Ignore invalid lines
  }
};

export enum AppState {
  INPUT = 'INPUT',
  DASHBOARD = 'DASHBOARD',
  QUIZ = 'QUIZ'
}

export interface QuoteData {
  english: string;
  chinese: string;
}

export interface WordData {
  id: string;
  word: string;
  definition: string;
  exampleSentence: string;
  partOfSpeech: string;
  correctCount: number;
  lastPracticed?: string;
  imageUrl?: string;

  // Replaced song data with a fun quote/joke/proverb object
  quote?: QuoteData; 
}

export interface QuizResult {
  wordId: string;
  correct: boolean;
}

export interface StoredData {
  cycleStart: number;
  words: WordData[];
}

import React, { useState, useEffect, useRef } from 'react';
import { WordInput } from './components/WordInput';
import { QuizSession } from './components/QuizSession';
import { Dashboard } from './components/Dashboard';
import { WordData, AppState, StoredData } from './types';
import { streamVocabularyEnrichment, fetchMediaForWord } from './services/geminiService';
import { Toaster, toast } from 'react-hot-toast';

const STORAGE_KEY = 'lexiweek_data_v2'; // Bumped version for new schema

// Helper: Calculate the timestamp of the most recent Saturday 18:00
const getCurrentCycleStart = (): number => {
  const now = new Date();
  const day = now.getDay(); // 0 = Sun, 6 = Sat
  const hour = now.getHours();

  const cycleStart = new Date(now);
  cycleStart.setHours(18, 0, 0, 0);

  // If it is Saturday and past 18:00, the cycle started today.
  if (day === 6 && hour >= 18) {
    return cycleStart.getTime();
  }

  // Otherwise, go back to the previous Saturday
  // Sun(0) -> -1, Mon(1) -> -2 ... Fri(5) -> -6, Sat(6)before18h -> -7
  const daysToSubtract = (day === 6) ? 7 : (day + 1);
  cycleStart.setDate(cycleStart.getDate() - daysToSubtract);
  return cycleStart.getTime();
};

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.INPUT); // Default to Input first, will check storage
  const [words, setWords] = useState<WordData[]>([]);
  const [loading, setLoading] = useState(false);
  const [cycleStart, setCycleStart] = useState<number>(0);

  const hasSwitchedToDashboardRef = useRef(false);

  // 1. Initial Load & Cycle Check
  useEffect(() => {
    const currentStart = getCurrentCycleStart();
    setCycleStart(currentStart);

    const saved = localStorage.getItem(STORAGE_KEY);

    if (saved) {
      try {
        const parsed = JSON.parse(saved);

        // Handle migration from old array format to new object format
        if (Array.isArray(parsed)) {
          // Old format detected, force new input for the new system
          localStorage.removeItem(STORAGE_KEY);
          setAppState(AppState.INPUT);
          return;
        }

        const storedData = parsed as StoredData;

        // Check if data belongs to the current week cycle
        if (storedData.cycleStart === currentStart && storedData.words.length > 0) {
          setWords(storedData.words);
          setAppState(AppState.DASHBOARD);
          // toast.success('已加载本周词库', { duration: 2000, icon: '📂' });
        } else {
          // Data is stale (from last week), clear it
          if (storedData.words.length > 0) {
             toast('新的一周开始了 (周六 18:00 重置)', { icon: '📅', duration: 5000 });
          }
          setWords([]);
          setAppState(AppState.INPUT);
          localStorage.removeItem(STORAGE_KEY);
        }
      } catch (e) {
        console.error("Failed to parse saved data", e);
        setAppState(AppState.INPUT);
      }
    } else {
      setAppState(AppState.INPUT);
    }
  }, []);

  // 2. Persist Data (Auto-save)
  useEffect(() => {
    if (loading) return; // Don't save empty state while loading

    // Only save if we have words OR if we are deliberately in INPUT mode (which usually means empty)
    // But we strictly want to save valid words associated with current cycle.
    if (words.length > 0 && cycleStart > 0) {
       try {
        // Create storage object
        const dataToSave: StoredData = {
          cycleStart: cycleStart,
          words: words.map(w => {
            // Optimization: Maybe don't save huge base64 images if quota is tight,
            // but for now we try to save them to ensure offline availability.
            // If quota fails, we strip images.
            return w;
          })
        };
        localStorage.setItem(STORAGE_KEY, JSON.stringify(dataToSave));
      } catch (e) {
        // Quota exceeded fallback: strip images
        if (e instanceof DOMException && (e.name === 'QuotaExceededError' || e.name === 'NS_ERROR_DOM_QUOTA_REACHED')) {
           try {
              const dataToSave: StoredData = {
                cycleStart: cycleStart,
                words: words.map(w => {
                  // eslint-disable-next-line @typescript-eslint/no-unused-vars
                  const { imageUrl, ...rest } = w;
                  return rest;
                })
              };
              localStorage.setItem(STORAGE_KEY, JSON.stringify(dataToSave));
           } catch (retryError) { /* ignore */ }
        }
      }
    }
  }, [words, cycleStart, loading]);

  const handleUpdateWord = (wordId: string, updates: Partial<WordData>) => {
    setWords(prev => prev.map(w => {
      if (w.id !== wordId) return w;
      return { ...w, ...updates };
    }));
  };

  const handleWordsSubmit = async (rawWords: string[]) => {
    setLoading(true);
    hasSwitchedToDashboardRef.current = false;
    setWords([]);

    // Ensure we are using the fresh cycle timestamp
    const nowStart = getCurrentCycleStart();
    setCycleStart(nowStart);

    try {
      await streamVocabularyEnrichment(rawWords, async (textWord) => {
        setWords(prev => [...prev, textWord]);

        if (!hasSwitchedToDashboardRef.current) {
          hasSwitchedToDashboardRef.current = true;
          setLoading(false);
          setAppState(AppState.DASHBOARD);
          toast.success('词库生成中...');
        }

        // Background fetch (Images)
        try {
          const enrichedWord = await fetchMediaForWord(textWord);
          if (enrichedWord.imageUrl) {
            handleUpdateWord(enrichedWord.id, enrichedWord);
          }
        } catch (e) {
          console.error(`Media fetch error for ${textWord.word}`, e);
        }
      });

    } catch (error: any) {
      console.error(error);
      if (error.message && (error.message.includes('API Key') || error.message.includes('API_KEY'))) {
        toast.error(error.message, { duration: 6000 });
      } else {
        toast.error('连接超时或服务不可用，请稍后重试。');
      }
      setLoading(false);
    }
  };

  const handleManualReset = () => {
    if (window.confirm("确定要重新输入吗？通常每周只需输入一次 (周六 18:00 自动更新)。")) {
      setWords([]);
      setAppState(AppState.INPUT);
      localStorage.removeItem(STORAGE_KEY);
    }
  };

  return (
    <div className="min-h-screen w-full bg-slate-50 relative">
      <div className="fixed inset-0 z-0 bg-gradient-to-br from-indigo-50 via-purple-50 to-pink-50 opacity-80 pointer-events-none"></div>
      <div className="fixed top-0 left-0 w-full h-1 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 z-50"></div>

      <main className="relative z-10 w-full max-w-4xl mx-auto p-4 sm:p-6 lg:p-8 flex flex-col min-h-screen justify-center">
        {appState === AppState.INPUT && (
          <WordInput 
            onSubmit={handleWordsSubmit} 
            isLoading={loading} 
            hasExistingData={words.length > 0}
            onCancel={words.length > 0 ? () => setAppState(AppState.DASHBOARD) : undefined}
          />
        )}

        {appState === AppState.DASHBOARD && (
          <Dashboard 
            words={words} 
            onStartQuiz={() => setAppState(AppState.QUIZ)}
            onNewWeek={handleManualReset}
            cycleStart={cycleStart}
          />
        )}

        {appState === AppState.QUIZ && (
          <QuizSession 
            words={words}
            onComplete={() => setAppState(AppState.DASHBOARD)}
            onUpdateWord={handleUpdateWord}
            onExit={() => setAppState(AppState.DASHBOARD)}
          />
        )}
      </main>

      <Toaster position="bottom-center" />
    </div>
  );
};

export default App;

import React, { useState } from 'react';

interface WordInputProps {
  onSubmit: (words: string[]) => void;
  isLoading: boolean;
  hasExistingData: boolean;
  onCancel?: () => void;
}

export const WordInput: React.FC<WordInputProps> = ({ onSubmit, isLoading, hasExistingData, onCancel }) => {
  const [inputText, setInputText] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const words = inputText
      .split(/[\n,，]+/) // Split by newline, comma (eng), or comma (cn)
      .map(w => w.trim())
      .filter(w => w.length > 0);

    if (words.length > 0) {
      onSubmit(words);
    }
  };

  return (
    <div className="bg-white/80 backdrop-blur-md shadow-xl rounded-2xl p-6 sm:p-8 border border-white/50 animate-fade-in-up">
      <div className="text-center mb-6 sm:mb-8">
        <h1 className="text-2xl sm:text-3xl font-bold text-slate-800 mb-2">本周词汇录入</h1>
        <p className="text-sm sm:text-base text-slate-500 max-w-lg mx-auto">
          只需在每周开始时输入一次。系统会在 <span className="font-semibold text-indigo-600">周六 18:00</span> 自动重置并开启新的一周。
        </p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label htmlFor="words" className="block text-sm font-medium text-slate-700 mb-2">
            粘贴单词列表 (用逗号或换行分隔)
          </label>
          <textarea
            id="words"
            rows={8}
            className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all text-slate-700 placeholder-slate-400 bg-white font-mono text-base"
            placeholder={`serendipity\nephemeral\nresilient\n...`}
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            disabled={isLoading}
          />
        </div>

        <div className="flex flex-col sm:flex-row gap-3 sm:gap-4">
          {hasExistingData && onCancel && (
            <button
              type="button"
              onClick={onCancel}
              className="w-full sm:flex-1 px-6 py-3 rounded-xl border border-slate-200 text-slate-600 font-semibold hover:bg-slate-50 transition-colors order-2 sm:order-1"
              disabled={isLoading}
            >
              返回本周列表
            </button>
          )}
          <button
            type="submit"
            disabled={isLoading || !inputText.trim()}
            className={`w-full sm:flex-1 px-6 py-3 rounded-xl text-white font-semibold shadow-lg shadow-indigo-500/30 transition-all transform active:scale-95 order-1 sm:order-2
              ${isLoading || !inputText.trim() 
                ? 'bg-slate-400 cursor-not-allowed' 
                : 'bg-indigo-600 hover:bg-indigo-700 hover:-translate-y-0.5'}`}
          >
            {isLoading ? (
              <span className="flex items-center justify-center gap-2">
                <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                正在解析与生成...
              </span>
            ) : '生成本周词库'}
          </button>
        </div>
      </form>
    </div>
  );
};

import React from 'react';
import { WordData } from '../types';

interface DashboardProps {
  words: WordData[];
  onStartQuiz: () => void;
  onNewWeek: () => void;
  cycleStart: number;
}

export const Dashboard: React.FC<DashboardProps> = ({ words, onStartQuiz, onNewWeek, cycleStart }) => {

  const getCycleDisplay = () => {
    if (!cycleStart) return '';
    const start = new Date(cycleStart);
    const end = new Date(cycleStart);
    end.setDate(end.getDate() + 7);

    // Format: MM/DD
    const fmt = (d: Date) => `${d.getMonth() + 1}/${d.getDate()}`;
    return `${fmt(start)} - ${fmt(end)}`;
  };

  return (
    <div className="space-y-4 sm:space-y-6">
      <div className="bg-white/80 backdrop-blur-md shadow-xl rounded-2xl p-5 sm:p-8 border border-white/50">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6 gap-4">
          <div>
            <div className="flex items-center gap-2 mb-1">
                <h1 className="text-2xl sm:text-3xl font-bold text-slate-800">本周词库</h1>
                <span className="bg-indigo-50 text-indigo-600 text-xs font-semibold px-2.5 py-0.5 rounded-full border border-indigo-100">
                    {getCycleDisplay()}
                </span>
            </div>
            <p className="text-slate-500">
               {words.length} 个单词 · 自动重置于周六 18:00
            </p>
          </div>
          <div className="flex gap-3 w-full sm:w-auto">
             <button
              onClick={onNewWeek}
              className="px-3 py-2 rounded-lg text-sm font-medium text-slate-400 hover:bg-red-50 hover:text-red-500 transition-colors"
              title="强制重新输入"
            >
              修改列表
            </button>
            <button
              onClick={onStartQuiz}
              className="flex-1 sm:flex-none px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold shadow-lg shadow-indigo-500/30 hover:bg-indigo-700 hover:-translate-y-0.5 transition-all active:scale-95 flex items-center justify-center gap-2"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="5 3 19 12 5 21 5 3"></polygon></svg>
              随机考察
            </button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-3 sm:gap-4 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
          {words.map((word) => (
            <div key={word.id} className="bg-slate-50 p-4 rounded-xl border border-slate-100 hover:border-indigo-100 transition-colors group flex gap-3 items-center">
              {word.imageUrl && (
                <div className="w-16 h-16 shrink-0 rounded-lg overflow-hidden border border-slate-200 bg-white">
                  <img src={word.imageUrl} alt={word.word} className="w-full h-full object-contain" />
                </div>
              )}
              <div className="flex-1 min-w-0">
                <div className="flex justify-between items-start mb-1">
                  <h3 className="text-lg font-bold text-slate-800 capitalize group-hover:text-indigo-600 transition-colors truncate">
                    {word.word}
                  </h3>
                  {word.correctCount > 0 && (
                      <span className="text-xs bg-green-100 text-green-700 px-1.5 py-0.5 rounded font-medium">
                        已掌握 {word.correctCount}
                      </span>
                  )}
                </div>
                <p className="text-sm text-slate-600 leading-relaxed line-clamp-2">
                  {word.definition}
                </p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

import { defineConfig, loadEnv } from 'vite'
