```javascript
import { getAi } from './ai';

async function generateSummary(existingSummary, word, definition, quote, onWordReceived) {

  const prompt = `
  You are an expert software engineer, summarizing your thought process to an expert peer.
  Your focus is improving and maintaining a 'weekly vocab' app by adding a new word.

  The existing summary of your thoughts is:
  """
  ${existingSummary}
  """

  Here is a definition for a new word:
  "${word}: ${definition}"

  Here is a quote for the new word:
  "${word} - ${quote}"

  Write a concise paragraph updating the user, who is an expert in their field, on the progress of the thought process.
  Focus on more recent updates in progress, and vary your style and verbiage.
  The summary must be plain text, and must be a single paragraph.
  It must be separated from the header by two newlines (\\n\\n).

  The response must be in the following format:
  **Your header**

  Your summary
  `;

  try {
    const ai = getAi();
    const response = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: [{
        parts: [{ text: prompt }],
      }],
      generationConfig: {
        maxOutputTokens: 256,
        temperature: 0.1,
        topP: 1,
        topK: 1
      }
    });

    let buffer = '';

    for await (const chunk of response) {
      const text = chunk.text;
      if (!text) continue;

      buffer += text;

      const lines = buffer.split('\n');
      buffer = lines.pop() || '';

      for (const line of lines) {
        processLine(line, word, onWordReceived);
      }
    }

    if (buffer.trim()) {
      processLine(buffer, word, onWordReceived);
    }
  } catch (e) {
    console.error(e);
    return null;
  }
}

function processLine(line, word, onWordReceived) {
  try {
    const match = line.match(/^\*\*([^*]+)\*\*[\n\s]+([\s\S]+)$/);
    if (!match) {
      console.log(`Skipping line: ${line}`);
      return;
    }

    const header = match[1].trim();
    const summary = match[2].trim();

    onWordReceived({ header, summary, word });
  } catch (e) {
    console.error(e, line);
  }
}

export { generateSummary };
```


