  },
  { 
    id: 'spd_up', name: '疾风步', description: '移动速度 +10%', icon: '👟',
    apply: (s) => ({ ...s, speed: s.speed * 1.1 }) 
  },
  { 
    id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +15%', icon: '🔫',
    apply: (s) => ({ ...s, attackSpeed: Math.max(5, s.attackSpeed * 0.85) }) 
  },
  { 
    id: 'hp_up', name: '坚韧', description: '最大生命 +30, 恢复满血', icon: '❤️',
    apply: (s) => ({ ...s, maxHp: s.maxHp + 30, hp: s.maxHp + 30 }) 
  },
  { 
    id: 'bullet_spd', name: '强力弹药', description: '子弹飞行速度 +20%', icon: '🚀',
    apply: (s) => ({ ...s, projectileSpeed: s.projectileSpeed * 1.2 }) 
  },
  { 
    id: 'range_up', name: '磁铁', description: '拾取范围 +50%', icon: '🧲',
    apply: (s) => ({ ...s, pickupRange: s.pickupRange * 1.5 }) 
  }
];

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // -- GAME STATE REFS (Mutable for Performance) --
  const playerRef = useRef<Entity>({
    id: 'hero', x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT / 2, width: 48, height: 48, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10
  });
  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, attackSpeed: 30, projectileSpeed: 8, pickupRange: 80,
    level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});
  const mouseRef = useRef({ x: 0, y: 0 });
  const gameTimeRef = useRef(0); // Seconds
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);

  // -- ASSETS --
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});

  // -- REACT STATE (UI Only) --
  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameOver, setGameOver] = useState(false);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);

  // Initialize Assets
  useEffect(() => {
    preloadAssets();
    Object.keys(GameAssets).forEach(key => {
      const img = new Image();
      img.src = GameAssets[key];
      spritesRef.current[key] = img;
    });

    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    const handleMouseMove = (e: MouseEvent) => { mouseRef.current = { x: e.clientX, y: e.clientY }; };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousemove', handleMouseMove);

    // Start Loop
    animationFrameId.current = requestAnimationFrame(gameLoop);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousemove', handleMouseMove);
      cancelAnimationFrame(animationFrameId.current);
    };
  }, []);

  // === GAME LOOP ===
  const gameLoop = () => {
    if (gameOver) return;

    if (!isPausedRef.current) {
      update();
    }
    draw();
    animationFrameId.current = requestAnimationFrame(gameLoop);
  };

  // === UPDATE LOGIC ===
  const update = () => {
    const player = playerRef.current;
    const stats = statsRef.current;
    const canvas = canvasRef.current;
    if (!canvas) return;

    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    // 1. Player Movement
    let dx = 0;
    let dy = 0;
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    if (dx !== 0 || dy !== 0) {
      const length = Math.sqrt(dx * dx + dy * dy);
      player.x += (dx / length) * stats.speed;
      player.y += (dy / length) * stats.speed;
    }

    // Boundary check
    player.x = Math.max(0, Math.min(canvas.width, player.x));
    player.y = Math.max(0, Math.min(canvas.height, player.y));

    // 2. Spawning System
    spawnEnemies(canvas);

    // 3. Enemy Logic
    enemiesRef.current.forEach(enemy => {
      // Move towards player
      const angle = Math.atan2(player.y - enemy.y, player.x - enemy.x);
      enemy.vx = Math.cos(angle) * (enemy.type.includes('ELITE') ? 2.5 : enemy.type === 'BOSS' ? 1.5 : 2);
      enemy.vy = Math.sin(angle) * (enemy.type.includes('ELITE') ? 2.5 : enemy.type === 'BOSS' ? 1.5 : 2);

      enemy.x += enemy.vx;
      enemy.y += enemy.vy;

      // Boss Shooting
      if (enemy.type === 'BOSS' && frameCountRef.current % 120 === 0) {
          spawnBossBullets(enemy);
      }
      // Ranged Elite Shooting
      if (enemy.type === 'ELITE_RANGED' && frameCountRef.current % 180 === 0) {
          spawnEnemyBullet(enemy, player);
      }

      // Player Collision (Damage)
      const dist = Math.hypot(player.x - enemy.x, player.y - enemy.y);
      if (dist < (player.width/2 + enemy.width/2)) {
         if (frameCountRef.current % 30 === 0) { // I-frame like mechanism
             takeDamage(enemy.damage);
         }
      }
    });

    // 4. Combat (Auto-fire)
    if (frameCountRef.current % stats.attackSpeed === 0) {
      fireBullet();
    }

    // 5. Projectiles (Player)
    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx;
      p.y += p.vy;

      // Enemy Collision
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width / 2 + 10)) {
              enemy.hp -= p.damage;
              hit = true;
              break; // Single target bullet for now
            }
          }
      } else {
          // Enemy Projectile hits Player
           if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width / 2 + 10)) {
               takeDamage(p.damage);
               hit = true;
           }
      }

      // Out of bounds
      const oob = p.x < 0 || p.x > canvas.width || p.y < 0 || p.y > canvas.height;
      return !oob && !hit;
    });

    // 6. Clean up Dead Enemies & Drop XP
    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        xpGemsRef.current.push({
          id: Math.random().toString(),
          x: e.x, y: e.y, width: 20, height: 20, type: 'XP',
          vx: 0, vy: 0, hp: 1, maxHp: 1, damage: 0
        });
        return false;
      }
      return true;
    });

    // 7. XP Collection
    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const dist = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (dist < stats.pickupRange) {
        // Magnet effect
        gem.x += (player.x - gem.x) * 0.1;
        gem.y += (player.y - gem.y) * 0.1;

        if (dist < 20) {
          gainXp(1);
          return false;
        }
      }
      return true;
    });

    // Sync UI stats infrequently
    if (frameCountRef.current % 10 === 0) {
        setUiStats({...statsRef.current});
    }
  };

  // === HELPERS ===

  const spawnEnemies = (canvas: HTMLCanvasElement) => {
      const time = gameTimeRef.current;
      const spawnRate = Math.max(20, SPAWN_RATE_INITIAL - Math.floor(time / 2));

      // Boss Spawn: Minute 2 (120s)
      if (time === 120 && !enemiesRef.current.some(e => e.type === 'BOSS')) {
          spawnEntity(canvas, 'BOSS');
          return;
      }

      if (frameCountRef.current % spawnRate === 0) {
          // Difficulty scaling
          const r = Math.random();
          let type = 'MOB';
          if (time > 30 && r > 0.9) type = 'ELITE';
          if (time > 60 && r > 0.8) type = 'ELITE';

          spawnEntity(canvas, type as any);
      }
  };

  const spawnEntity = (canvas: HTMLCanvasElement, category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4); // 0: top, 1: right, 2: bottom, 3: left
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * canvas.width; y = -50; }
      else if (side === 1) { x = canvas.width + 50; y = Math.random() * canvas.height; }
      else if (side === 2) { x = Math.random() * canvas.width; y = canvas.height + 50; }
      else { x = -50; y = Math.random() * canvas.height; }

      let entity: Entity = {
          id: Math.random().toString(),
          x, y, vx: 0, vy: 0, 
          type: 'MOB', width: 40, height: 40, hp: 10, maxHp: 10, damage: 5
      };

      if (category === 'BOSS') {
          entity = { ...entity, type: 'BOSS', width: 120, height: 120, hp: 2000, maxHp: 2000, damage: 20, spriteUrl: AssetTypes.BOSS };
      } else if (category === 'ELITE') {
          const sub = Math.random();
          if (sub < 0.33) {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_MELEE, hp: 100, damage: 15, width: 60, height: 60 }; // Melee
          } else if (sub < 0.66) {
             entity = { ...entity, type: 'ELITE_RANGED' as any, spriteUrl: AssetTypes.ELITE_RANGED, hp: 60, damage: 10, width: 50, height: 50 }; // Ranged
          } else {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_TANK, hp: 150, damage: 10, width: 70, height: 70 }; // Tank
          }
      } else {
          // Mob
          const mobTypes = [AssetTypes.MOB_1, AssetTypes.MOB_2, AssetTypes.MOB_3, AssetTypes.MOB_4, AssetTypes.MOB_5];
          entity = { ...entity, type: 'MOB', spriteUrl: mobTypes[Math.floor(Math.random() * 5)], hp: 10 + (gameTimeRef.current * 0.5) };
      }

      enemiesRef.current.push(entity);
  };

  const fireBullet = () => {
    // Find closest enemy
    let closest = null;
    let minDst = Infinity;
    const p = playerRef.current;

    for (const e of enemiesRef.current) {
        const d = Math.hypot(e.x - p.x, e.y - p.y);
        if (d < minDst) {
            minDst = d;
            closest = e;
        }
    }

    if (closest) {
        const angle = Math.atan2(closest.y - p.y, closest.x - p.x);
        projectilesRef.current.push({
            id: Math.random().toString(),
            x: p.x, y: p.y, width: 10, height: 10, type: 'PROJECTILE',
            vx: Math.cos(angle) * statsRef.current.projectileSpeed,
            vy: Math.sin(angle) * statsRef.current.projectileSpeed,
            hp: 1, maxHp: 1, damage: statsRef.current.damage
        });
    }
  };

  const spawnEnemyBullet = (enemy: Entity, target: Entity) => {
      const angle = Math.atan2(target.y - enemy.y, target.x - enemy.x);
      projectilesRef.current.push({
          id: Math.random().toString(),
          x: enemy.x, y: enemy.y, width: 12, height: 12, type: 'ENEMY_PROJECTILE',
          vx: Math.cos(angle) * 4,
          vy: Math.sin(angle) * 4,
          hp: 1, maxHp: 1, damage: 10
      });
  };

  const spawnBossBullets = (boss: Entity) => {
      // Ring of 8
      for (let i = 0; i < 8; i++) {
          const angle = (Math.PI * 2 / 8) * i;
          projectilesRef.current.push({
              id: Math.random().toString(),
              x: boss.x, y: boss.y, width: 16, height: 16, type: 'ENEMY_PROJECTILE',
              vx: Math.cos(angle) * 5,
              vy: Math.sin(angle) * 5,
              hp: 1, maxHp: 1, damage: 15
          });
      }
  };

  const takeDamage = (amount: number) => {
      statsRef.current.hp -= amount;
      if (statsRef.current.hp <= 0) {
          setGameOver(true);
          isPausedRef.current = true;
      }
  };

  const gainXp = (amount: number) => {
      statsRef.current.xp += amount;
      if (statsRef.current.xp >= statsRef.current.xpToNextLevel) {
          triggerLevelUp();
      }
  };

  const triggerLevelUp = () => {
      isPausedRef.current = true;
      // Pick a random word
      const word = words[Math.floor(Math.random() * words.length)];
      setQuizWord(word);
  };

  const handleQuizResult = (correct: boolean) => {
      setQuizWord(null);
      if (correct) {
          // Show Upgrade Selection
          const options = [...UPGRADES].sort(() => 0.5 - Math.random()).slice(0, 3);
          setShowUpgrades(options);
      } else {
          // No upgrade, increase requirement slightly, resume
          statsRef.current.xp = 0;
          statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.2);
          isPausedRef.current = false;
      }
  };

  const applyUpgrade = (opt: UpgradeOption) => {
      statsRef.current = opt.apply(statsRef.current);
      statsRef.current.level += 1;
      statsRef.current.xp = 0;
      statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.2);

      setShowUpgrades(null);
      isPausedRef.current = false;
  };

  // === DRAW ===
  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Background
    ctx.fillStyle = '#f0f9ff'; // Slate-50-ish
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Grid
    ctx.strokeStyle = '#e2e8f0';
    ctx.lineWidth = 1;
    const gridSize = 50;
    for (let x = 0; x < canvas.width; x += gridSize) {
        ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, canvas.height); ctx.stroke();
    }
    for (let y = 0; y < canvas.height; y += gridSize) {
        ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(canvas.width, y); ctx.stroke();
    }

    // Draw Entity Helper
    const drawSprite = (e: Entity, fallbackColor: string) => {
        const sprite = e.spriteUrl ? spritesRef.current[e.spriteUrl] || spritesRef.current[e.type] : null;
        if (sprite && sprite.complete) {
            ctx.drawImage(sprite, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = fallbackColor;
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        }
    };

    // XP
    xpGemsRef.current.forEach(gem => {
        drawSprite(gem, '#3b82f6');
    });

    // Enemies
    enemiesRef.current.forEach(e => {
        drawSprite(e, e.type === 'BOSS' ? '#dc2626' : '#64748b');
        // HP Bar for Elites/Boss
        if (e.type !== 'MOB') {
            ctx.fillStyle = 'red';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2 - 10, e.width, 4);
            ctx.fillStyle = 'green';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2 - 10, e.width * (e.hp/e.maxHp), 4);
        }
    });

    // Player
    drawSprite(playerRef.current, '#6366f1');

    // Projectiles
    projectilesRef.current.forEach(p => {
        ctx.fillStyle = p.type === 'PROJECTILE' ? '#fbbf24' : '#ef4444';
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2);
        ctx.fill();
    });
  };

  return (
    <div className="fixed inset-0 w-full h-full overflow-hidden bg-slate-900 cursor-crosshair">
      <canvas 
        ref={canvasRef} 
        width={CANVAS_WIDTH} 
        height={CANVAS_HEIGHT}
        className="block"
      />

      {/* HUD */}
      <div className="absolute top-4 left-4 flex flex-col gap-2 pointer-events-none">
        {/* HP Bar */}
        <div className="w-64 h-6 bg-slate-700 rounded-full border-2 border-white overflow-hidden relative">
             <div className="h-full bg-red-500 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-xs font-bold text-white text-shadow">
                 HP {Math.ceil(uiStats.hp)} / {uiStats.maxHp}
             </span>
        </div>
        {/* XP Bar */}
        <div className="w-64 h-4 bg-slate-700 rounded-full border border-white/50 overflow-hidden relative">
             <div className="h-full bg-blue-500 transition-all duration-300" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white text-shadow">
                 LVL {uiStats.level}
             </span>
        </div>
      </div>

      {/* Timer */}
      <div className="absolute top-4 left-1/2 -translate-x-1/2 text-2xl font-black text-white drop-shadow-lg font-mono pointer-events-none">
          {Math.floor(gameTimeDisplay / 60).toString().padStart(2, '0')}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
      </div>

      {/* Quiz Modal */}
      {quizWord && (
          <GameQuizModal 
             word={quizWord} 
             allWords={words} 
             onResult={handleQuizResult} 
          />
      )}

      {/* Upgrade Modal */}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md animate-fade-in">
              <div className="max-w-4xl w-full p-8">
                  <h2 className="text-4xl font-black text-yellow-400 text-center mb-8 uppercase tracking-widest drop-shadow-md">Level Up! 选择升级</h2>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      {showUpgrades.map(opt => (
                          <button 
                            key={opt.id}
                            onClick={() => applyUpgrade(opt)}
                            className="bg-slate-800 border-2 border-slate-600 hover:border-yellow-400 hover:bg-slate-700 p-6 rounded-2xl flex flex-col items-center gap-4 transition-all hover:scale-105 active:scale-95 group"
                          >
                              <div className="text-6xl group-hover:animate-bounce">{opt.icon}</div>
                              <div className="text-2xl font-bold text-white">{opt.name}</div>
                              <div className="text-slate-400 text-center">{opt.description}</div>
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* Game Over Modal */}
      {gameOver && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-red-900/90 backdrop-blur-md">
              <div className="text-center p-12 bg-white rounded-3xl shadow-2xl max-w-lg w-full">
                  <h1 className="text-5xl font-black text-red-600 mb-2">YOU DIED</h1>
                  <p className="text-slate-500 mb-8 text-xl">生存时间: {Math.floor(gameTimeDisplay / 60)}分 {gameTimeDisplay % 60}秒</p>
                  <p className="text-indigo-600 font-bold mb-8">等级: {uiStats.level}</p>

                  <div className="flex gap-4 justify-center">
                    <button onClick={() => window.location.reload()} className="px-8 py-3 bg-slate-800 text-white font-bold rounded-xl hover:bg-slate-700">重试</button>
                    <button onClick={onExit} className="px-8 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700">退出</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { WordInput } from './components/WordInput';
import { GameArena } from './components/GameArena';
import { WordData, AppState, StoredData } from './types';
import { streamVocabularyEnrichment, fetchMediaForWord } from './services/geminiService';
import { Toaster, toast } from 'react-hot-toast';

const STORAGE_KEY = 'lexiweek_data_v2'; 

const getCurrentCycleStart = (): number => {
  const now = new Date();
  const day = now.getDay(); 
  const hour = now.getHours();

  const cycleStart = new Date(now);
  cycleStart.setHours(18, 0, 0, 0);

  if (day === 6 && hour >= 18) {
    return cycleStart.getTime();
  }

  const daysToSubtract = (day === 6) ? 7 : (day + 1);
  cycleStart.setDate(cycleStart.getDate() - daysToSubtract);
  return cycleStart.getTime();
};

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.INPUT); 
  const [words, setWords] = useState<WordData[]>([]);
  const [loading, setLoading] = useState(false);
  const [cycleStart, setCycleStart] = useState<number>(0);

  // 1. Initial Load
  useEffect(() => {
    const currentStart = getCurrentCycleStart();
    setCycleStart(currentStart);

    const saved = localStorage.getItem(STORAGE_KEY);

    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed)) {
          localStorage.removeItem(STORAGE_KEY);
          setAppState(AppState.INPUT);
          return;
        }

        const storedData = parsed as StoredData;

        if (storedData.cycleStart === currentStart && storedData.words.length > 0) {
          setWords(storedData.words);
          // Directly go to GAME menu input if data exists, but we treat Input screen as "Lobby"
          setAppState(AppState.INPUT); 
        } else {
          setWords([]);
          setAppState(AppState.INPUT);
          localStorage.removeItem(STORAGE_KEY);
        }
      } catch (e) {
        setAppState(AppState.INPUT);
      }
    } else {
      setAppState(AppState.INPUT);
    }
  }, []);

  // 2. Persist Data
  useEffect(() => {
    if (loading) return; 

    if (words.length > 0 && cycleStart > 0) {
       try {
        const dataToSave: StoredData = {
          cycleStart: cycleStart,
          words: words.map(w => w)
        };
        localStorage.setItem(STORAGE_KEY, JSON.stringify(dataToSave));
      } catch (e) {
         // handle quota
      }
    }
  }, [words, cycleStart, loading]);

  const handleUpdateWord = (wordId: string, updates: Partial<WordData>) => {
    setWords(prev => prev.map(w => {
      if (w.id !== wordId) return w;
      return { ...w, ...updates };
    }));
  };

  const handleWordsSubmit = async (rawWords: string[]) => {
    setLoading(true);
    setWords([]);

    const nowStart = getCurrentCycleStart();
    setCycleStart(nowStart);

    try {
      await streamVocabularyEnrichment(rawWords, async (textWord) => {
        setWords(prev => [...prev, textWord]);

        // Background fetch (Images)
        try {
          const enrichedWord = await fetchMediaForWord(textWord);
          if (enrichedWord.imageUrl) {
            handleUpdateWord(enrichedWord.id, enrichedWord);
          }
        } catch (e) {
          console.error(e);
        }
      });
      setLoading(false);
      // Wait for user to click "Start Game" in WordInput component now
    } catch (error: any) {
      console.error(error);
      toast.error('Connection failed, please try again.');
      setLoading(false);
    }
  };

  return (
    <div className="w-full h-screen bg-slate-900 overflow-hidden relative">

      {appState === AppState.INPUT && (
