                 {words.length > 0 && !loading ? (
                     <div className="bg-white rounded-2xl p-8 shadow-2xl text-center animate-fade-in-up">
                         <h1 className="text-4xl font-black text-slate-800 mb-2">准备就绪</h1>
                         <p className="text-slate-500 mb-8">本周已加载 {words.length} 个单词。准备好面对怪兽了吗？</p>

                         <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                             <button 
                                onClick={() => setAppState(AppState.GAME)}
                                className="py-4 px-8 bg-indigo-600 text-white font-bold rounded-xl text-xl shadow-lg hover:bg-indigo-700 hover:scale-105 transition-all"
                             >
                                 ⚔️ 开始生存挑战
                             </button>
                             <button 
                                onClick={() => { if(confirm('确定要清除当前单词表吗？')) { setWords([]); localStorage.removeItem(STORAGE_KEY); } }}
                                className="py-4 px-8 bg-slate-100 text-slate-600 font-bold rounded-xl text-xl hover:bg-slate-200 transition-all"
                             >
                                 ✏️ 重新输入
                             </button>
                         </div>
                     </div>
                 ) : (
                    <WordInput 
                        onSubmit={handleWordsSubmit} 
                        isLoading={loading} 
                        hasExistingData={false}
                    />
                 )}
             </div>
        </div>
      )}

      {appState === AppState.GAME && (
        <GameArena 
          words={words} 
          onExit={() => setAppState(AppState.INPUT)}
        />
      )}

      <Toaster position="top-center" />
    </div>
  );
};

