import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { AssetTypes, initGameAssets } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const FPS = 60;
const CANVAS_WIDTH = window.innerWidth;
const CANVAS_HEIGHT = window.innerHeight;
const SPAWN_RATE_INITIAL = 100; // Slower spawn (was 60)
const BASE_XP_REQUIREMENT = 3;

// Upgrade Definitions
const UPGRADES: UpgradeOption[] = [
  { 
    id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪',
    apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
  },
  { 
    id: 'spd_up', name: '疾风步', description: '移动速度 +10%', icon: '👟',
    apply: (s) => ({ ...s, speed: s.speed * 1.1 }) 
  },
  { 
    id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +15%', icon: '🔫',
    apply: (s) => ({ ...s, attackSpeed: Math.max(5, s.attackSpeed * 0.85) }) 
  },
  { 
    id: 'hp_up', name: '坚韧', description: '最大生命 +30, 恢复满血', icon: '❤️',
    apply: (s) => ({ ...s, maxHp: s.maxHp + 30, hp: s.maxHp + 30 }) 
  },
  { 
    id: 'multishot', name: '多重射击', description: '同时发射子弹数 +1', icon: '✨',
    apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
  },
  { 
    id: 'range_up', name: '磁铁', description: '拾取范围 +50%', icon: '🧲',
    apply: (s) => ({ ...s, pickupRange: s.pickupRange * 1.5 }) 
  }
];

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // -- GAME STATE REFS (Mutable for Performance) --
  const playerRef = useRef<Entity>({
    id: 'hero', x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT / 2, width: 48, height: 48, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10
  });
  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, attackSpeed: 30, projectileSpeed: 8, pickupRange: 80,
    projectileCount: 1, // Start with 1 bullet
    level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});
  const mouseRef = useRef({ x: 0, y: 0 });
  const gameTimeRef = useRef(0); // Seconds
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);

  // Quiz Pacing Logic
  const quizCooldownRef = useRef(0); 

  // -- ASSETS --
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});

  // -- REACT STATE (UI Only) --
  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameOver, setGameOver] = useState(false);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);

  // Initialize Assets & Inputs
  useEffect(() => {
    // Trigger async asset generation
    initGameAssets((key, url) => {
        const img = new Image();
        img.src = url;
        // Pre-decode for smoother performance
        img.decode().then(() => {
             spritesRef.current[key] = img;
        }).catch(() => {
             spritesRef.current[key] = img;
        });
    });

    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    const handleMouseMove = (e: MouseEvent) => { mouseRef.current = { x: e.clientX, y: e.clientY }; };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousemove', handleMouseMove);

    // Start Loop
    animationFrameId.current = requestAnimationFrame(gameLoop);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousemove', handleMouseMove);
      cancelAnimationFrame(animationFrameId.current);
    };
  }, []);

  // === GAME LOOP ===
  const gameLoop = () => {
    if (gameOver) return;

    if (!isPausedRef.current) {
      update();
    }
    draw();
    animationFrameId.current = requestAnimationFrame(gameLoop);
  };

  // === UPDATE LOGIC ===
  const update = () => {
    const player = playerRef.current;
    const stats = statsRef.current;
    const canvas = canvasRef.current;
    if (!canvas) return;

    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    // 1. Player Movement
    let dx = 0;
    let dy = 0;
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    if (dx !== 0 || dy !== 0) {
      const length = Math.sqrt(dx * dx + dy * dy);
      player.x += (dx / length) * stats.speed;
      player.y += (dy / length) * stats.speed;
    }

    // Boundary check
    player.x = Math.max(0, Math.min(canvas.width, player.x));
    player.y = Math.max(0, Math.min(canvas.height, player.y));

    // 2. Spawning System
    spawnEnemies(canvas);

    // 3. Enemy Logic
    enemiesRef.current.forEach(enemy => {
      // Move towards player
      const angle = Math.atan2(player.y - enemy.y, player.x - enemy.x);
      enemy.vx = Math.cos(angle) * (enemy.type.includes('ELITE') ? 2.5 : enemy.type === 'BOSS' ? 1.5 : 2);
      enemy.vy = Math.sin(angle) * (enemy.type.includes('ELITE') ? 2.5 : enemy.type === 'BOSS' ? 1.5 : 2);

      enemy.x += enemy.vx;
      enemy.y += enemy.vy;

      // Boss Shooting
      if (enemy.type === 'BOSS' && frameCountRef.current % 120 === 0) {
          spawnBossBullets(enemy);
      }
      // Ranged Elite Shooting
      if (enemy.type === 'ELITE_RANGED' && frameCountRef.current % 180 === 0) {
          spawnEnemyBullet(enemy, player);
      }

      // Player Collision (Damage)
      const dist = Math.hypot(player.x - enemy.x, player.y - enemy.y);
      if (dist < (player.width/2 + enemy.width/2)) {
         if (frameCountRef.current % 30 === 0) { // I-frame like mechanism
             takeDamage(enemy.damage);
         }
      }
    });

    // 4. Combat (Auto-fire)
    if (frameCountRef.current % stats.attackSpeed === 0) {
      fireBullet();
    }

    // 5. Projectiles (Player)
    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx;
      p.y += p.vy;

      // Enemy Collision
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width / 2 + 10)) {
              enemy.hp -= p.damage;
              hit = true;
              break; // Single target bullet for now
            }
          }
      } else {
          // Enemy Projectile hits Player
           if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width / 2 + 10)) {
               takeDamage(p.damage);
               hit = true;
           }
      }

      // Out of bounds
      const oob = p.x < 0 || p.x > canvas.width || p.y < 0 || p.y > canvas.height;
      return !oob && !hit;
    });

    // 6. Clean up Dead Enemies & Drop XP
    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        xpGemsRef.current.push({
          id: Math.random().toString(),
          x: e.x, y: e.y, width: 20, height: 20, type: 'XP',
          vx: 0, vy: 0, hp: 1, maxHp: 1, damage: 0
        });
        return false;
      }
      return true;
    });

    // 7. XP Collection
    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const dist = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (dist < stats.pickupRange) {
        // Magnet effect
        gem.x += (player.x - gem.x) * 0.1;
        gem.y += (player.y - gem.y) * 0.1;

        if (dist < 20) {
          gainXp(1);
          return false;
        }
      }
      return true;
    });

    // Sync UI stats infrequently
    if (frameCountRef.current % 10 === 0) {
        setUiStats({...statsRef.current});
    }
  };

  // === HELPERS ===

  const spawnEnemies = (canvas: HTMLCanvasElement) => {
      const time = gameTimeRef.current;
      // Slower spawn rate calculation
      const spawnRate = Math.max(30, SPAWN_RATE_INITIAL - Math.floor(time / 5));

      // Boss Spawn: Minute 2 (120s)
      if (time === 120 && !enemiesRef.current.some(e => e.type === 'BOSS')) {
          spawnEntity(canvas, 'BOSS');
          return;
      }

      if (frameCountRef.current % spawnRate === 0) {
          // Difficulty scaling
          const r = Math.random();
          let type = 'MOB';
          if (time > 30 && r > 0.9) type = 'ELITE';
          if (time > 60 && r > 0.8) type = 'ELITE';

          spawnEntity(canvas, type as any);
      }
  };

  const spawnEntity = (canvas: HTMLCanvasElement, category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4); // 0: top, 1: right, 2: bottom, 3: left
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * canvas.width; y = -50; }
      else if (side === 1) { x = canvas.width + 50; y = Math.random() * canvas.height; }
      else if (side === 2) { x = Math.random() * canvas.width; y = canvas.height + 50; }
      else { x = -50; y = Math.random() * canvas.height; }

      let entity: Entity = {
          id: Math.random().toString(),
          x, y, vx: 0, vy: 0, 
          type: 'MOB', width: 40, height: 40, hp: 10, maxHp: 10, damage: 5
      };

      if (category === 'BOSS') {
          entity = { ...entity, type: 'BOSS', width: 120, height: 120, hp: 2000, maxHp: 2000, damage: 20, spriteUrl: AssetTypes.BOSS };
      } else if (category === 'ELITE') {
          const sub = Math.random();
          if (sub < 0.33) {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_MELEE, hp: 100, damage: 15, width: 60, height: 60 }; // Melee
          } else if (sub < 0.66) {
             entity = { ...entity, type: 'ELITE_RANGED' as any, spriteUrl: AssetTypes.ELITE_RANGED, hp: 60, damage: 10, width: 50, height: 50 }; // Ranged
          } else {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_TANK, hp: 150, damage: 10, width: 70, height: 70 }; // Tank
          }
      } else {
          // Mob
          const mobTypes = [AssetTypes.MOB_1, AssetTypes.MOB_2, AssetTypes.MOB_3, AssetTypes.MOB_4, AssetTypes.MOB_5];
          entity = { ...entity, type: 'MOB', spriteUrl: mobTypes[Math.floor(Math.random() * 5)], hp: 10 + (gameTimeRef.current * 0.5) };
      }

      enemiesRef.current.push(entity);
  };

  const fireBullet = () => {
    // Find closest enemy
    let closest = null;
    let minDst = Infinity;
    const p = playerRef.current;

    for (const e of enemiesRef.current) {
        const d = Math.hypot(e.x - p.x, e.y - p.y);
        if (d < minDst) {
            minDst = d;
            closest = e;
        }
    }

    if (closest) {
        const baseAngle = Math.atan2(closest.y - p.y, closest.x - p.x);
        const count = statsRef.current.projectileCount || 1;

        // Multi-shot logic
        for (let i = 0; i < count; i++) {
             // Spread angle: 0.2 radians approx 11 degrees
             const offset = count > 1 ? (i - (count - 1) / 2) * 0.2 : 0;
             const angle = baseAngle + offset;

             projectilesRef.current.push({
                id: Math.random().toString(),
                x: p.x, y: p.y, width: 10, height: 10, type: 'PROJECTILE',
                vx: Math.cos(angle) * statsRef.current.projectileSpeed,
                vy: Math.sin(angle) * statsRef.current.projectileSpeed,
                hp: 1, maxHp: 1, damage: statsRef.current.damage
            });
        }
    }
  };

  const spawnEnemyBullet = (enemy: Entity, target: Entity) => {
      const angle = Math.atan2(target.y - enemy.y, target.x - enemy.x);
      projectilesRef.current.push({
          id: Math.random().toString(),
          x: enemy.x, y: enemy.y, width: 12, height: 12, type: 'ENEMY_PROJECTILE',
          vx: Math.cos(angle) * 4,
          vy: Math.sin(angle) * 4,
          hp: 1, maxHp: 1, damage: 10
      });
  };

  const spawnBossBullets = (boss: Entity) => {
      // Ring of 8
      for (let i = 0; i < 8; i++) {
          const angle = (Math.PI * 2 / 8) * i;
          projectilesRef.current.push({
              id: Math.random().toString(),
              x: boss.x, y: boss.y, width: 16, height: 16, type: 'ENEMY_PROJECTILE',
              vx: Math.cos(angle) * 5,
              vy: Math.sin(angle) * 5,
              hp: 1, maxHp: 1, damage: 15
          });
      }
  };

  const takeDamage = (amount: number) => {
      statsRef.current.hp -= amount;
      if (statsRef.current.hp <= 0) {
          setGameOver(true);
          isPausedRef.current = true;
      }
  };

  const gainXp = (amount: number) => {
      statsRef.current.xp += amount;
      if (statsRef.current.xp >= statsRef.current.xpToNextLevel) {
          triggerLevelUp();
      }
  };

  const triggerLevelUp = () => {
      isPausedRef.current = true;

      // Check cooldown
      if (quizCooldownRef.current <= 0) {
          // Trigger Quiz
          const word = words[Math.floor(Math.random() * words.length)];
          setQuizWord(word);

          // Reset cooldown to random 3-5
          quizCooldownRef.current = Math.floor(Math.random() * 3) + 3;
      } else {
          // Free Upgrade (Skip Quiz)
          quizCooldownRef.current -= 1;
          showUpgradeMenu();
      }
  };

  const showUpgradeMenu = () => {
      const options = [...UPGRADES].sort(() => 0.5 - Math.random()).slice(0, 3);
      setShowUpgrades(options);
  };

  const handleQuizResult = (correct: boolean) => {
      setQuizWord(null);
      if (correct) {
          showUpgradeMenu();
      } else {
          // No upgrade, increase requirement slightly, resume
          statsRef.current.xp = 0;
          statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.2);
          isPausedRef.current = false;
      }
  };

  const applyUpgrade = (opt: UpgradeOption) => {
      statsRef.current = opt.apply(statsRef.current);
      statsRef.current.level += 1;
      statsRef.current.xp = 0;
      statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.2);

      setShowUpgrades(null);
      isPausedRef.current = false;
  };

  // === DRAW ===
  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Background
    ctx.fillStyle = '#f0f9ff'; // Slate-50-ish
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Grid
    ctx.strokeStyle = '#e2e8f0';
    ctx.lineWidth = 1;
    const gridSize = 50;
    for (let x = 0; x < canvas.width; x += gridSize) {
        ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, canvas.height); ctx.stroke();
    }
    for (let y = 0; y < canvas.height; y += gridSize) {
        ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(canvas.width, y); ctx.stroke();
    }

    // Draw Entity Helper
    const drawSprite = (e: Entity, fallbackColor: string) => {
        // Try to find sprite
        const sprite = e.spriteUrl ? spritesRef.current[e.spriteUrl] || spritesRef.current[e.type] : null;

        // If sprite is loaded, draw it
        if (sprite && sprite.complete && sprite.naturalWidth > 0) {
            ctx.drawImage(sprite, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            // Fallback square or circle
            ctx.fillStyle = fallbackColor;
            if (e.type === 'XP') {
                ctx.beginPath();
                ctx.arc(e.x, e.y, e.width/2, 0, Math.PI * 2);
                ctx.fill();
            } else {
                ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
            }
        }
    };

    // XP - Use Gold Color #fbbf24
    xpGemsRef.current.forEach(gem => {
        drawSprite(gem, '#fbbf24');
    });

    // Enemies
    enemiesRef.current.forEach(e => {
        drawSprite(e, e.type === 'BOSS' ? '#dc2626' : '#64748b');
        // HP Bar for Elites/Boss
        if (e.type !== 'MOB') {
            ctx.fillStyle = 'red';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2 - 10, e.width, 4);
            ctx.fillStyle = 'green';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2 - 10, e.width * (e.hp/e.maxHp), 4);
        }
    });

    // Player
    drawSprite(playerRef.current, '#6366f1');

    // Projectiles
    projectilesRef.current.forEach(p => {
        ctx.fillStyle = p.type === 'PROJECTILE' ? '#fbbf24' : '#ef4444';
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2);
        ctx.fill();
    });
  };

  return (
    <div className="fixed inset-0 w-full h-full overflow-hidden bg-slate-900 cursor-crosshair">
      <canvas 
        ref={canvasRef} 
        width={CANVAS_WIDTH} 
        height={CANVAS_HEIGHT}
        className="block"
      />

      {/* HUD */}
      <div className="absolute top-4 left-4 flex flex-col gap-2 pointer-events-none">
        {/* HP Bar */}
        <div className="w-64 h-6 bg-slate-700 rounded-full border-2 border-white overflow-hidden relative">
             <div className="h-full bg-red-500 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-xs font-bold text-white text-shadow">
                 HP {Math.ceil(uiStats.hp)} / {uiStats.maxHp}
             </span>
        </div>
        {/* XP Bar */}
        <div className="w-64 h-4 bg-slate-700 rounded-full border border-white/50 overflow-hidden relative">
             <div className="h-full bg-blue-500 transition-all duration-300" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white text-shadow">
                 LVL {uiStats.level}
             </span>
        </div>
      </div>

      {/* Timer */}
      <div className="absolute top-4 left-1/2 -translate-x-1/2 text-2xl font-black text-white drop-shadow-lg font-mono pointer-events-none">
          {Math.floor(gameTimeDisplay / 60).toString().padStart(2, '0')}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
      </div>

      {/* Quiz Modal */}
      {quizWord && (
          <GameQuizModal 
             word={quizWord} 
             allWords={words} 
             onResult={handleQuizResult} 
          />
      )}

      {/* Upgrade Modal */}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md animate-fade-in">
              <div className="max-w-4xl w-full p-8">
                  <h2 className="text-4xl font-black text-yellow-400 text-center mb-8 uppercase tracking-widest drop-shadow-md">Level Up! 选择升级</h2>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      {showUpgrades.map(opt => (
                          <button 
                            key={opt.id}
                            onClick={() => applyUpgrade(opt)}
                            className="bg-slate-800 border-2 border-slate-600 hover:border-yellow-400 hover:bg-slate-700 p-6 rounded-2xl flex flex-col items-center gap-4 transition-all hover:scale-105 active:scale-95 group"
                          >
                              <div className="text-6xl group-hover:animate-bounce">{opt.icon}</div>
                              <div className="text-2xl font-bold text-white">{opt.name}</div>
                              <div className="text-slate-400 text-center">{opt.description}</div>
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* Game Over Modal */}
      {gameOver && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-red-900/90 backdrop-blur-md">
              <div className="text-center p-12 bg-white rounded-3xl shadow-2xl max-w-lg w-full">
                  <h1 className="text-5xl font-black text-red-600 mb-2">YOU DIED</h1>
                  <p className="text-slate-500 mb-8 text-xl">生存时间: {Math.floor(gameTimeDisplay / 60)}分 {gameTimeDisplay % 60}秒</p>
                  <p className="text-indigo-600 font-bold mb-8">等级: {uiStats.level}</p>

                  <div className="flex gap-4 justify-center">
                    <button onClick={() => window.location.reload()} className="px-8 py-3 bg-slate-800 text-white font-bold rounded-xl hover:bg-slate-700">重试</button>
                    <button onClick={onExit} className="px-8 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700">退出</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { AssetTypes, initGameAssets } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const FPS = 60;
const SPAWN_RATE_INITIAL = 100; // Slower spawn (was 60)
const BASE_XP_REQUIREMENT = 3;

// Upgrade Definitions
const UPGRADES: UpgradeOption[] = [
  { 
    id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪',
    apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
  },
  { 
    id: 'spd_up', name: '疾风步', description: '移动速度 +10%', icon: '👟',
    apply: (s) => ({ ...s, speed: s.speed * 1.1 }) 
  },
  { 
    id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +15%', icon: '🔫',
    apply: (s) => ({ ...s, attackSpeed: Math.max(5, s.attackSpeed * 0.85) }) 
  },
  { 
    id: 'hp_up', name: '坚韧', description: '最大生命 +30, 恢复满血', icon: '❤️',
    apply: (s) => ({ ...s, maxHp: s.maxHp + 30, hp: s.maxHp + 30 }) 
  },
  { 
    id: 'multishot', name: '多重射击', description: '同时发射子弹数 +1', icon: '✨',
    apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
  },
  { 
    id: 'range_up', name: '磁铁', description: '拾取范围 +50%', icon: '🧲',
    apply: (s) => ({ ...s, pickupRange: s.pickupRange * 1.5 }) 
  }
];

// Helper to calculate 16:9 dimensions
const calculateDimensions = () => {
  const winW = window.innerWidth;
  const winH = window.innerHeight;
  const targetRatio = 16 / 9;
  const winRatio = winW / winH;

  let width, height;

  if (winRatio > targetRatio) {
    // Window is wider than 16:9 (Pillarbox)
    height = winH;
    width = height * targetRatio;
  } else {
    // Window is taller than 16:9 (Letterbox)
    width = winW;
    height = width / targetRatio;
  }
  return { width, height };
};

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // -- GAME STATE REFS (Mutable for Performance) --
  // Initialize Dimensions
  const [dimensions, setDimensions] = useState(calculateDimensions());

  const playerRef = useRef<Entity>({
    id: 'hero', 
    x: dimensions.width / 2, 
    y: dimensions.height / 2, 
    width: 48, height: 48, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, attackSpeed: 30, projectileSpeed: 8, pickupRange: 80,
    projectileCount: 1, // Start with 1 bullet
    level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});
  const mouseRef = useRef({ x: 0, y: 0 });
  const gameTimeRef = useRef(0); // Seconds
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);

  // Quiz Pacing Logic
  const quizCooldownRef = useRef(0); 

  // -- ASSETS --
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});

  // -- REACT STATE (UI Only) --
  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameOver, setGameOver] = useState(false);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);

  // Resize Listener
  useEffect(() => {
    const handleResize = () => {
      const newDims = calculateDimensions();
      setDimensions(newDims);
      // Optional: Adjust player position relative to new size if needed, 
      // but loop logic handles bounds automatically.
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Initialize Assets & Inputs
  useEffect(() => {
    // Trigger async asset generation
    initGameAssets((key, url) => {
        const img = new Image();
        img.src = url;
        // Pre-decode for smoother performance
        img.decode().then(() => {
             spritesRef.current[key] = img;
        }).catch(() => {
             spritesRef.current[key] = img;
        });
    });

    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    const handleMouseMove = (e: MouseEvent) => { 
        // We need to adjust mouse coordinates because canvas might be offset due to centering
        const canvas = canvasRef.current;
        if (canvas) {
            const rect = canvas.getBoundingClientRect();
            mouseRef.current = { 
                x: e.clientX - rect.left, 
                y: e.clientY - rect.top 
            };
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousemove', handleMouseMove);

    // Start Loop
    animationFrameId.current = requestAnimationFrame(gameLoop);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousemove', handleMouseMove);
      cancelAnimationFrame(animationFrameId.current);
    };
  }, []);

  // === GAME LOOP ===
  const gameLoop = () => {
    if (gameOver) return;

    if (!isPausedRef.current) {
      update();
    }
    draw();
    animationFrameId.current = requestAnimationFrame(gameLoop);
  };

  // === UPDATE LOGIC ===
  const update = () => {
    const player = playerRef.current;
    const stats = statsRef.current;
    const canvas = canvasRef.current;
    if (!canvas) return;

    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    // 1. Player Movement
    let dx = 0;
    let dy = 0;
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    if (dx !== 0 || dy !== 0) {
      const length = Math.sqrt(dx * dx + dy * dy);
      player.x += (dx / length) * stats.speed;
      player.y += (dy / length) * stats.speed;
    }

    // Boundary check
    player.x = Math.max(0, Math.min(canvas.width, player.x));
    player.y = Math.max(0, Math.min(canvas.height, player.y));

    // 2. Spawning System
    spawnEnemies(canvas);

    // 3. Enemy Logic
    enemiesRef.current.forEach(enemy => {
      // Move towards player
      const angle = Math.atan2(player.y - enemy.y, player.x - enemy.x);
      enemy.vx = Math.cos(angle) * (enemy.type.includes('ELITE') ? 2.5 : enemy.type === 'BOSS' ? 1.5 : 2);
      enemy.vy = Math.sin(angle) * (enemy.type.includes('ELITE') ? 2.5 : enemy.type === 'BOSS' ? 1.5 : 2);

      enemy.x += enemy.vx;
      enemy.y += enemy.vy;

      // Boss Shooting
      if (enemy.type === 'BOSS' && frameCountRef.current % 120 === 0) {
          spawnBossBullets(enemy);
      }
      // Ranged Elite Shooting
      if (enemy.type === 'ELITE_RANGED' && frameCountRef.current % 180 === 0) {
          spawnEnemyBullet(enemy, player);
      }

      // Player Collision (Damage)
      const dist = Math.hypot(player.x - enemy.x, player.y - enemy.y);
      if (dist < (player.width/2 + enemy.width/2)) {
         if (frameCountRef.current % 30 === 0) { // I-frame like mechanism
             takeDamage(enemy.damage);
         }
      }
    });

    // 4. Combat (Auto-fire)
    if (frameCountRef.current % stats.attackSpeed === 0) {
      fireBullet();
    }

    // 5. Projectiles (Player)
    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx;
      p.y += p.vy;

      // Enemy Collision
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width / 2 + 10)) {
              enemy.hp -= p.damage;
              hit = true;
              break; // Single target bullet for now
            }
          }
      } else {
          // Enemy Projectile hits Player
           if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width / 2 + 10)) {
               takeDamage(p.damage);
               hit = true;
           }
      }

      // Out of bounds
      const oob = p.x < 0 || p.x > canvas.width || p.y < 0 || p.y > canvas.height;
      return !oob && !hit;
    });

    // 6. Clean up Dead Enemies & Drop XP
    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        xpGemsRef.current.push({
          id: Math.random().toString(),
          x: e.x, y: e.y, width: 20, height: 20, type: 'XP',
          vx: 0, vy: 0, hp: 1, maxHp: 1, damage: 0
        });
        return false;
      }
      return true;
    });

    // 7. XP Collection
    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const dist = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (dist < stats.pickupRange) {
        // Magnet effect
        gem.x += (player.x - gem.x) * 0.1;
        gem.y += (player.y - gem.y) * 0.1;

        if (dist < 20) {
          gainXp(1);
          return false;
        }
      }
      return true;
    });

    // Sync UI stats infrequently
    if (frameCountRef.current % 10 === 0) {
        setUiStats({...statsRef.current});
    }
  };

  // === HELPERS ===

  const spawnEnemies = (canvas: HTMLCanvasElement) => {
      const time = gameTimeRef.current;
      // Slower spawn rate calculation
      const spawnRate = Math.max(30, SPAWN_RATE_INITIAL - Math.floor(time / 5));

      // Boss Spawn: Minute 2 (120s)
      if (time === 120 && !enemiesRef.current.some(e => e.type === 'BOSS')) {
          spawnEntity(canvas, 'BOSS');
          return;
      }

      if (frameCountRef.current % spawnRate === 0) {
          // Difficulty scaling
          const r = Math.random();
          let type = 'MOB';
          if (time > 30 && r > 0.9) type = 'ELITE';
          if (time > 60 && r > 0.8) type = 'ELITE';

          spawnEntity(canvas, type as any);
      }
  };

  const spawnEntity = (canvas: HTMLCanvasElement, category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4); // 0: top, 1: right, 2: bottom, 3: left
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * canvas.width; y = -50; }
      else if (side === 1) { x = canvas.width + 50; y = Math.random() * canvas.height; }
      else if (side === 2) { x = Math.random() * canvas.width; y = canvas.height + 50; }
      else { x = -50; y = Math.random() * canvas.height; }

      let entity: Entity = {
          id: Math.random().toString(),
          x, y, vx: 0, vy: 0, 
          type: 'MOB', width: 40, height: 40, hp: 10, maxHp: 10, damage: 5
      };

      if (category === 'BOSS') {
          entity = { ...entity, type: 'BOSS', width: 120, height: 120, hp: 2000, maxHp: 2000, damage: 20, spriteUrl: AssetTypes.BOSS };
      } else if (category === 'ELITE') {
          const sub = Math.random();
          if (sub < 0.33) {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_MELEE, hp: 100, damage: 15, width: 60, height: 60 }; // Melee
          } else if (sub < 0.66) {
             entity = { ...entity, type: 'ELITE_RANGED' as any, spriteUrl: AssetTypes.ELITE_RANGED, hp: 60, damage: 10, width: 50, height: 50 }; // Ranged
          } else {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_TANK, hp: 150, damage: 10, width: 70, height: 70 }; // Tank
          }
      } else {
          // Mob
          const mobTypes = [AssetTypes.MOB_1, AssetTypes.MOB_2, AssetTypes.MOB_3, AssetTypes.MOB_4, AssetTypes.MOB_5];
          entity = { ...entity, type: 'MOB', spriteUrl: mobTypes[Math.floor(Math.random() * 5)], hp: 10 + (gameTimeRef.current * 0.5) };
      }

      enemiesRef.current.push(entity);
  };

  const fireBullet = () => {
    // Find closest enemy
    let closest = null;
    let minDst = Infinity;
    const p = playerRef.current;

    for (const e of enemiesRef.current) {
        const d = Math.hypot(e.x - p.x, e.y - p.y);
        if (d < minDst) {
            minDst = d;
            closest = e;
        }
    }

    if (closest) {
        const baseAngle = Math.atan2(closest.y - p.y, closest.x - p.x);
        const count = statsRef.current.projectileCount || 1;

        // Multi-shot logic
        for (let i = 0; i < count; i++) {
             // Spread angle: 0.2 radians approx 11 degrees
             const offset = count > 1 ? (i - (count - 1) / 2) * 0.2 : 0;
             const angle = baseAngle + offset;

             projectilesRef.current.push({
                id: Math.random().toString(),
                x: p.x, y: p.y, width: 10, height: 10, type: 'PROJECTILE',
                vx: Math.cos(angle) * statsRef.current.projectileSpeed,
                vy: Math.sin(angle) * statsRef.current.projectileSpeed,
                hp: 1, maxHp: 1, damage: statsRef.current.damage
            });
        }
    }
  };

  const spawnEnemyBullet = (enemy: Entity, target: Entity) => {
      const angle = Math.atan2(target.y - enemy.y, target.x - enemy.x);
      projectilesRef.current.push({
          id: Math.random().toString(),
          x: enemy.x, y: enemy.y, width: 12, height: 12, type: 'ENEMY_PROJECTILE',
          vx: Math.cos(angle) * 4,
          vy: Math.sin(angle) * 4,
          hp: 1, maxHp: 1, damage: 10
      });
  };

  const spawnBossBullets = (boss: Entity) => {
      // Ring of 8
      for (let i = 0; i < 8; i++) {
          const angle = (Math.PI * 2 / 8) * i;
          projectilesRef.current.push({
              id: Math.random().toString(),
              x: boss.x, y: boss.y, width: 16, height: 16, type: 'ENEMY_PROJECTILE',
              vx: Math.cos(angle) * 5,
              vy: Math.sin(angle) * 5,
              hp: 1, maxHp: 1, damage: 15
          });
      }
  };

  const takeDamage = (amount: number) => {
      statsRef.current.hp -= amount;
      if (statsRef.current.hp <= 0) {
          setGameOver(true);
          isPausedRef.current = true;
      }
  };

  const gainXp = (amount: number) => {
      statsRef.current.xp += amount;
      if (statsRef.current.xp >= statsRef.current.xpToNextLevel) {
          triggerLevelUp();
      }
  };

  const triggerLevelUp = () => {
      isPausedRef.current = true;

      // Check cooldown
      if (quizCooldownRef.current <= 0) {
          // Trigger Quiz
          const word = words[Math.floor(Math.random() * words.length)];
          setQuizWord(word);

          // Reset cooldown to random 3-5
          quizCooldownRef.current = Math.floor(Math.random() * 3) + 3;
      } else {
          // Free Upgrade (Skip Quiz)
          quizCooldownRef.current -= 1;
          showUpgradeMenu();
      }
  };

  const showUpgradeMenu = () => {
      const options = [...UPGRADES].sort(() => 0.5 - Math.random()).slice(0, 3);
      setShowUpgrades(options);
  };

  const handleQuizResult = (correct: boolean) => {
      setQuizWord(null);
      if (correct) {
          showUpgradeMenu();
      } else {
          // No upgrade, increase requirement slightly, resume
          statsRef.current.xp = 0;
          statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.2);
          isPausedRef.current = false;
      }
  };

  const applyUpgrade = (opt: UpgradeOption) => {
      statsRef.current = opt.apply(statsRef.current);
      statsRef.current.level += 1;
      statsRef.current.xp = 0;
      statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.2);

      setShowUpgrades(null);
      isPausedRef.current = false;
  };

  // === DRAW ===
  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Background
    ctx.fillStyle = '#f0f9ff'; // Slate-50-ish
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Grid
    ctx.strokeStyle = '#e2e8f0';
    ctx.lineWidth = 1;
    const gridSize = 50;
    for (let x = 0; x < canvas.width; x += gridSize) {
        ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, canvas.height); ctx.stroke();
    }
    for (let y = 0; y < canvas.height; y += gridSize) {
        ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(canvas.width, y); ctx.stroke();
    }

    // Draw Entity Helper
    const drawSprite = (e: Entity, fallbackColor: string) => {
        // Try to find sprite
        const sprite = e.spriteUrl ? spritesRef.current[e.spriteUrl] || spritesRef.current[e.type] : null;

        // If sprite is loaded, draw it
        if (sprite && sprite.complete && sprite.naturalWidth > 0) {
            ctx.drawImage(sprite, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            // Fallback square or circle
            ctx.fillStyle = fallbackColor;
            if (e.type === 'XP') {
                ctx.beginPath();
                ctx.arc(e.x, e.y, e.width/2, 0, Math.PI * 2);
                ctx.fill();
            } else {
                ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
            }
        }
    };

    // XP - Use Gold Color #fbbf24
    xpGemsRef.current.forEach(gem => {
        drawSprite(gem, '#fbbf24');
    });

    // Enemies
    enemiesRef.current.forEach(e => {
        drawSprite(e, e.type === 'BOSS' ? '#dc2626' : '#64748b');
        // HP Bar for Elites/Boss
        if (e.type !== 'MOB') {
            ctx.fillStyle = 'red';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2 - 10, e.width, 4);
            ctx.fillStyle = 'green';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2 - 10, e.width * (e.hp/e.maxHp), 4);
        }
    });

    // Player
    drawSprite(playerRef.current, '#6366f1');

    // Projectiles
    projectilesRef.current.forEach(p => {
        ctx.fillStyle = p.type === 'PROJECTILE' ? '#fbbf24' : '#ef4444';
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2);
        ctx.fill();
    });
  };

  return (
    <div className="fixed inset-0 w-full h-full overflow-hidden bg-black flex items-center justify-center cursor-crosshair">
      <canvas 
        ref={canvasRef} 
        width={dimensions.width} 
        height={dimensions.height}
        style={{ 
            width: dimensions.width, 
            height: dimensions.height,
            maxWidth: '100%',
            maxHeight: '100%'
        }}
        className="block bg-slate-50 shadow-2xl"
      />

      {/* HUD Container - Absolute relative to window or scaled container? 
          Currently absolute on window, which is fine for overlay.
      */}
      <div className="fixed top-4 left-4 flex flex-col gap-2 pointer-events-none z-10">
        {/* HP Bar */}
        <div className="w-64 h-6 bg-slate-700 rounded-full border-2 border-white overflow-hidden relative shadow-lg">
             <div className="h-full bg-red-500 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-xs font-bold text-white text-shadow">
                 HP {Math.ceil(uiStats.hp)} / {uiStats.maxHp}
             </span>
        </div>
        {/* XP Bar */}
        <div className="w-64 h-4 bg-slate-700 rounded-full border border-white/50 overflow-hidden relative shadow-lg">
             <div className="h-full bg-blue-500 transition-all duration-300" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white text-shadow">
                 LVL {uiStats.level}
             </span>
        </div>
      </div>

      {/* Timer */}
      <div className="fixed top-4 left-1/2 -translate-x-1/2 text-2xl font-black text-white drop-shadow-lg font-mono pointer-events-none z-10">
          {Math.floor(gameTimeDisplay / 60).toString().padStart(2, '0')}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
      </div>

      {/* Quiz Modal */}
      {quizWord && (
          <GameQuizModal 
             word={quizWord} 
             allWords={words} 
             onResult={handleQuizResult} 
          />
      )}

      {/* Upgrade Modal */}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md animate-fade-in">
              <div className="max-w-4xl w-full p-8">
                  <h2 className="text-4xl font-black text-yellow-400 text-center mb-8 uppercase tracking-widest drop-shadow-md">Level Up! 选择升级</h2>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      {showUpgrades.map(opt => (
                          <button 
                            key={opt.id}
                            onClick={() => applyUpgrade(opt)}
                            className="bg-slate-800 border-2 border-slate-600 hover:border-yellow-400 hover:bg-slate-700 p-6 rounded-2xl flex flex-col items-center gap-4 transition-all hover:scale-105 active:scale-95 group"
                          >
                              <div className="text-6xl group-hover:animate-bounce">{opt.icon}</div>
                              <div className="text-2xl font-bold text-white">{opt.name}</div>
                              <div className="text-slate-400 text-center">{opt.description}</div>
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* Game Over Modal */}
      {gameOver && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-red-900/90 backdrop-blur-md">
              <div className="text-center p-12 bg-white rounded-3xl shadow-2xl max-w-lg w-full">
                  <h1 className="text-5xl font-black text-red-600 mb-2">YOU DIED</h1>
                  <p className="text-slate-500 mb-8 text-xl">生存时间: {Math.floor(gameTimeDisplay / 60)}分 {gameTimeDisplay % 60}秒</p>
                  <p className="text-indigo-600 font-bold mb-8">等级: {uiStats.level}</p>

                  <div className="flex gap-4 justify-center">
                    <button onClick={() => window.location.reload()} className="px-8 py-3 bg-slate-800 text-white font-bold rounded-xl hover:bg-slate-700">重试</button>
                    <button onClick={onExit} className="px-8 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700">退出</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { AssetTypes, initGameAssets } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const FPS = 60;
const SPAWN_RATE_INITIAL = 100; // Slower spawn (was 60)
const BASE_XP_REQUIREMENT = 3;

// Upgrade Definitions
const UPGRADES: UpgradeOption[] = [
  { 
    id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪',
    apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
  },
  { 
    id: 'spd_up', name: '疾风步', description: '移动速度 +10%', icon: '👟',
    apply: (s) => ({ ...s, speed: s.speed * 1.1 }) 
  },
  { 
    id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +15%', icon: '🔫',
    apply: (s) => ({ ...s, attackSpeed: Math.max(5, s.attackSpeed * 0.85) }) 
  },
  { 
    id: 'hp_up', name: '坚韧', description: '最大生命 +30, 恢复满血', icon: '❤️',
    apply: (s) => ({ ...s, maxHp: s.maxHp + 30, hp: s.maxHp + 30 }) 
  },
  { 
    id: 'multishot', name: '多重射击', description: '同时发射子弹数 +1', icon: '✨',
    apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
  },
  { 
    id: 'range_up', name: '磁铁', description: '拾取范围 +50%', icon: '🧲',
    apply: (s) => ({ ...s, pickupRange: s.pickupRange * 1.5 }) 
  }
];

// Helper to calculate 16:9 dimensions
const calculateDimensions = () => {
  const winW = window.innerWidth;
  const winH = window.innerHeight;
  const targetRatio = 16 / 9;
  const winRatio = winW / winH;

  let width, height;

  if (winRatio > targetRatio) {
    // Window is wider than 16:9 (Pillarbox)
    height = winH;
    width = height * targetRatio;
  } else {
    // Window is taller than 16:9 (Letterbox)
    width = winW;
    height = width / targetRatio;
  }
  return { width, height };
};

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // -- GAME STATE REFS (Mutable for Performance) --
  // Initialize Dimensions
  const [dimensions, setDimensions] = useState(calculateDimensions());

  const playerRef = useRef<Entity>({
    id: 'hero', 
    x: dimensions.width / 2, 
    y: dimensions.height / 2, 
    width: 48, height: 48, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, attackSpeed: 30, projectileSpeed: 8, pickupRange: 80,
    projectileCount: 1, // Start with 1 bullet
    level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});
  const mouseRef = useRef({ x: 0, y: 0 });
  const gameTimeRef = useRef(0); // Seconds
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);

  // Quiz Pacing Logic
  const quizCooldownRef = useRef(0); 

  // -- ASSETS --
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});

  // -- REACT STATE (UI Only) --
  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameOver, setGameOver] = useState(false);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);

  // Resize Listener
  useEffect(() => {
    const handleResize = () => {
      const newDims = calculateDimensions();
      setDimensions(newDims);
      // Optional: Adjust player position relative to new size if needed, 
      // but loop logic handles bounds automatically.
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Initialize Assets & Inputs
  useEffect(() => {
    // Trigger async asset generation
    initGameAssets((key, url) => {
        const img = new Image();
        img.src = url;
        // Pre-decode for smoother performance
        img.decode().then(() => {
             spritesRef.current[key] = img;
        }).catch(() => {
             spritesRef.current[key] = img;
        });
    });

    const handleKeyDown = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = true; };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.key.toLowerCase()] = false; };
    const handleMouseMove = (e: MouseEvent) => { 
        // We need to adjust mouse coordinates because canvas might be offset due to centering
        const canvas = canvasRef.current;
        if (canvas) {
            const rect = canvas.getBoundingClientRect();
            mouseRef.current = { 
                x: e.clientX - rect.left, 
                y: e.clientY - rect.top 
            };
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousemove', handleMouseMove);

    // Start Loop
    animationFrameId.current = requestAnimationFrame(gameLoop);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousemove', handleMouseMove);
      cancelAnimationFrame(animationFrameId.current);
    };
  }, []);

  // === GAME LOOP ===
  const gameLoop = () => {
    if (gameOver) return;

    if (!isPausedRef.current) {
      update();
    }
    draw();
    animationFrameId.current = requestAnimationFrame(gameLoop);
  };

  // === UPDATE LOGIC ===
  const update = () => {
    const player = playerRef.current;
    const stats = statsRef.current;
    const canvas = canvasRef.current;
    if (!canvas) return;

    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    // 1. Player Movement
    let dx = 0;
    let dy = 0;

    // A. Keyboard Input
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // B. Gamepad Input
    const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
    const gp = gamepads[0]; // Assume Player 1

    if (gp) {
        const deadzone = 0.2;

        // Left Analog Stick (Axes 0, 1)
        if (Math.abs(gp.axes[0]) > deadzone) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > deadzone) dy += gp.axes[1];

        // D-Pad (Standard Layout: Buttons 12, 13, 14, 15)
        // 12: Up, 13: Down, 14: Left, 15: Right
        if (gp.buttons[12]?.pressed) dy -= 1;
        if (gp.buttons[13]?.pressed) dy += 1;
        if (gp.buttons[14]?.pressed) dx -= 1;
        if (gp.buttons[15]?.pressed) dx += 1;
    }

    // Normalize and Move
    if (dx !== 0 || dy !== 0) {
      const length = Math.sqrt(dx * dx + dy * dy);
      // Normalize vector so diagonal movement isn't faster, then apply speed
      // If using analog stick (length < 1), we technically could allow slower movement,
      // but for this game genre, max speed is preferred.
      // However, let's allow analog precision if length < 1 (slow walk) but cap at 1.
      const normalizedFactor = length > 1 ? 1 / length : 1;

      player.x += (dx * normalizedFactor) * stats.speed;
      player.y += (dy * normalizedFactor) * stats.speed;
    }

    // Boundary check
    player.x = Math.max(0, Math.min(canvas.width, player.x));
    player.y = Math.max(0, Math.min(canvas.height, player.y));

    // 2. Spawning System
    spawnEnemies(canvas);

    // 3. Enemy Logic
    enemiesRef.current.forEach(enemy => {
      // Move towards player
      const angle = Math.atan2(player.y - enemy.y, player.x - enemy.x);
      enemy.vx = Math.cos(angle) * (enemy.type.includes('ELITE') ? 2.5 : enemy.type === 'BOSS' ? 1.5 : 2);
      enemy.vy = Math.sin(angle) * (enemy.type.includes('ELITE') ? 2.5 : enemy.type === 'BOSS' ? 1.5 : 2);

      enemy.x += enemy.vx;
      enemy.y += enemy.vy;

      // Boss Shooting
      if (enemy.type === 'BOSS' && frameCountRef.current % 120 === 0) {
          spawnBossBullets(enemy);
      }
      // Ranged Elite Shooting
      if (enemy.type === 'ELITE_RANGED' && frameCountRef.current % 180 === 0) {
          spawnEnemyBullet(enemy, player);
      }

      // Player Collision (Damage)
      const dist = Math.hypot(player.x - enemy.x, player.y - enemy.y);
      if (dist < (player.width/2 + enemy.width/2)) {
         if (frameCountRef.current % 30 === 0) { // I-frame like mechanism
             takeDamage(enemy.damage);
         }
      }
    });

    // 4. Combat (Auto-fire)
    if (frameCountRef.current % stats.attackSpeed === 0) {
      fireBullet();
    }

    // 5. Projectiles (Player)
    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx;
      p.y += p.vy;

      // Enemy Collision
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width / 2 + 10)) {
              enemy.hp -= p.damage;
              hit = true;
              break; // Single target bullet for now
            }
          }
      } else {
          // Enemy Projectile hits Player
           if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width / 2 + 10)) {
               takeDamage(p.damage);
               hit = true;
           }
      }

      // Out of bounds
      const oob = p.x < 0 || p.x > canvas.width || p.y < 0 || p.y > canvas.height;
      return !oob && !hit;
    });

    // 6. Clean up Dead Enemies & Drop XP
    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        xpGemsRef.current.push({
          id: Math.random().toString(),
          x: e.x, y: e.y, width: 20, height: 20, type: 'XP',
          vx: 0, vy: 0, hp: 1, maxHp: 1, damage: 0
        });
        return false;
      }
      return true;
    });

    // 7. XP Collection
    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const dist = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (dist < stats.pickupRange) {
        // Magnet effect
        gem.x += (player.x - gem.x) * 0.1;
        gem.y += (player.y - gem.y) * 0.1;

        if (dist < 20) {
          gainXp(1);
          return false;
        }
      }
      return true;
    });

    // Sync UI stats infrequently
    if (frameCountRef.current % 10 === 0) {
        setUiStats({...statsRef.current});
    }
  };

  // === HELPERS ===

  const spawnEnemies = (canvas: HTMLCanvasElement) => {
      const time = gameTimeRef.current;
      // Slower spawn rate calculation
      const spawnRate = Math.max(30, SPAWN_RATE_INITIAL - Math.floor(time / 5));

      // Boss Spawn: Minute 2 (120s)
      if (time === 120 && !enemiesRef.current.some(e => e.type === 'BOSS')) {
          spawnEntity(canvas, 'BOSS');
          return;
      }

      if (frameCountRef.current % spawnRate === 0) {
          // Difficulty scaling
          const r = Math.random();
          let type = 'MOB';
          if (time > 30 && r > 0.9) type = 'ELITE';
          if (time > 60 && r > 0.8) type = 'ELITE';

          spawnEntity(canvas, type as any);
      }
  };

  const spawnEntity = (canvas: HTMLCanvasElement, category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4); // 0: top, 1: right, 2: bottom, 3: left
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * canvas.width; y = -50; }
      else if (side === 1) { x = canvas.width + 50; y = Math.random() * canvas.height; }
      else if (side === 2) { x = Math.random() * canvas.width; y = canvas.height + 50; }
      else { x = -50; y = Math.random() * canvas.height; }

      let entity: Entity = {
          id: Math.random().toString(),
          x, y, vx: 0, vy: 0, 
          type: 'MOB', width: 40, height: 40, hp: 10, maxHp: 10, damage: 5
      };

      if (category === 'BOSS') {
          entity = { ...entity, type: 'BOSS', width: 120, height: 120, hp: 2000, maxHp: 2000, damage: 20, spriteUrl: AssetTypes.BOSS };
      } else if (category === 'ELITE') {
          const sub = Math.random();
          if (sub < 0.33) {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_MELEE, hp: 100, damage: 15, width: 60, height: 60 }; // Melee
          } else if (sub < 0.66) {
             entity = { ...entity, type: 'ELITE_RANGED' as any, spriteUrl: AssetTypes.ELITE_RANGED, hp: 60, damage: 10, width: 50, height: 50 }; // Ranged
          } else {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_TANK, hp: 150, damage: 10, width: 70, height: 70 }; // Tank
          }
      } else {
          // Mob
          const mobTypes = [AssetTypes.MOB_1, AssetTypes.MOB_2, AssetTypes.MOB_3, AssetTypes.MOB_4, AssetTypes.MOB_5];
          entity = { ...entity, type: 'MOB', spriteUrl: mobTypes[Math.floor(Math.random() * 5)], hp: 10 + (gameTimeRef.current * 0.5) };
      }

      enemiesRef.current.push(entity);
  };

  const fireBullet = () => {
    // Find closest enemy
    let closest = null;
    let minDst = Infinity;
    const p = playerRef.current;

    for (const e of enemiesRef.current) {
        const d = Math.hypot(e.x - p.x, e.y - p.y);
        if (d < minDst) {
            minDst = d;
            closest = e;
        }
    }

    if (closest) {
        const baseAngle = Math.atan2(closest.y - p.y, closest.x - p.x);
        const count = statsRef.current.projectileCount || 1;

        // Multi-shot logic
        for (let i = 0; i < count; i++) {
             // Spread angle: 0.2 radians approx 11 degrees
             const offset = count > 1 ? (i - (count - 1) / 2) * 0.2 : 0;
             const angle = baseAngle + offset;

             projectilesRef.current.push({
                id: Math.random().toString(),
                x: p.x, y: p.y, width: 10, height: 10, type: 'PROJECTILE',
                vx: Math.cos(angle) * statsRef.current.projectileSpeed,
                vy: Math.sin(angle) * statsRef.current.projectileSpeed,
                hp: 1, maxHp: 1, damage: statsRef.current.damage
            });
        }
    }
  };

  const spawnEnemyBullet = (enemy: Entity, target: Entity) => {
      const angle = Math.atan2(target.y - enemy.y, target.x - enemy.x);
      projectilesRef.current.push({
          id: Math.random().toString(),
          x: enemy.x, y: enemy.y, width: 12, height: 12, type: 'ENEMY_PROJECTILE',
          vx: Math.cos(angle) * 4,
          vy: Math.sin(angle) * 4,
          hp: 1, maxHp: 1, damage: 10
      });
  };

  const spawnBossBullets = (boss: Entity) => {
      // Ring of 8
      for (let i = 0; i < 8; i++) {
          const angle = (Math.PI * 2 / 8) * i;
          projectilesRef.current.push({
              id: Math.random().toString(),
              x: boss.x, y: boss.y, width: 16, height: 16, type: 'ENEMY_PROJECTILE',
              vx: Math.cos(angle) * 5,
              vy: Math.sin(angle) * 5,
              hp: 1, maxHp: 1, damage: 15
          });
      }
  };

  const takeDamage = (amount: number) => {
      statsRef.current.hp -= amount;
      if (statsRef.current.hp <= 0) {
          setGameOver(true);
          isPausedRef.current = true;
      }
  };

  const gainXp = (amount: number) => {
      statsRef.current.xp += amount;
      if (statsRef.current.xp >= statsRef.current.xpToNextLevel) {
          triggerLevelUp();
      }
  };

  const triggerLevelUp = () => {
      isPausedRef.current = true;

      // Check cooldown
      if (quizCooldownRef.current <= 0) {
          // Trigger Quiz
          const word = words[Math.floor(Math.random() * words.length)];
          setQuizWord(word);

          // Reset cooldown to random 3-5
          quizCooldownRef.current = Math.floor(Math.random() * 3) + 3;
      } else {
          // Free Upgrade (Skip Quiz)
          quizCooldownRef.current -= 1;
          showUpgradeMenu();
      }
  };

  const showUpgradeMenu = () => {
      const options = [...UPGRADES].sort(() => 0.5 - Math.random()).slice(0, 3);
      setShowUpgrades(options);
  };

  const handleQuizResult = (correct: boolean) => {
      setQuizWord(null);
      if (correct) {
          showUpgradeMenu();
      } else {
          // No upgrade, increase requirement slightly, resume
          statsRef.current.xp = 0;
          statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.2);
          isPausedRef.current = false;
      }
  };

  const applyUpgrade = (opt: UpgradeOption) => {
      statsRef.current = opt.apply(statsRef.current);
      statsRef.current.level += 1;
      statsRef.current.xp = 0;
      statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.2);

      setShowUpgrades(null);
      isPausedRef.current = false;
  };

  // === DRAW ===
  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Background
    ctx.fillStyle = '#f0f9ff'; // Slate-50-ish
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Grid
    ctx.strokeStyle = '#e2e8f0';
    ctx.lineWidth = 1;
    const gridSize = 50;
    for (let x = 0; x < canvas.width; x += gridSize) {
        ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, canvas.height); ctx.stroke();
    }
    for (let y = 0; y < canvas.height; y += gridSize) {
        ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(canvas.width, y); ctx.stroke();
    }

    // Draw Entity Helper
    const drawSprite = (e: Entity, fallbackColor: string) => {
        // Try to find sprite
        const sprite = e.spriteUrl ? spritesRef.current[e.spriteUrl] || spritesRef.current[e.type] : null;

        // If sprite is loaded, draw it
        if (sprite && sprite.complete && sprite.naturalWidth > 0) {
            ctx.drawImage(sprite, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            // Fallback square or circle
            ctx.fillStyle = fallbackColor;
            if (e.type === 'XP') {
                ctx.beginPath();
                ctx.arc(e.x, e.y, e.width/2, 0, Math.PI * 2);
                ctx.fill();
            } else {
                ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
            }
        }
    };

    // XP - Use Gold Color #fbbf24
    xpGemsRef.current.forEach(gem => {
        drawSprite(gem, '#fbbf24');
    });

    // Enemies
    enemiesRef.current.forEach(e => {
        drawSprite(e, e.type === 'BOSS' ? '#dc2626' : '#64748b');
        // HP Bar for Elites/Boss
        if (e.type !== 'MOB') {
            ctx.fillStyle = 'red';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2 - 10, e.width, 4);
            ctx.fillStyle = 'green';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2 - 10, e.width * (e.hp/e.maxHp), 4);
        }
    });

    // Player
    drawSprite(playerRef.current, '#6366f1');

    // Projectiles
    projectilesRef.current.forEach(p => {
        ctx.fillStyle = p.type === 'PROJECTILE' ? '#fbbf24' : '#ef4444';
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2);
        ctx.fill();
    });
  };

  return (
    <div className="fixed inset-0 w-full h-full overflow-hidden bg-black flex items-center justify-center cursor-crosshair">
      <canvas 
        ref={canvasRef} 
        width={dimensions.width} 
        height={dimensions.height}
        style={{ 
            width: dimensions.width, 
            height: dimensions.height,
            maxWidth: '100%',
            maxHeight: '100%'
        }}
        className="block bg-slate-50 shadow-2xl"
      />

      {/* HUD Container - Absolute relative to window or scaled container? 
          Currently absolute on window, which is fine for overlay.
      */}
      <div className="fixed top-4 left-4 flex flex-col gap-2 pointer-events-none z-10">
        {/* HP Bar */}
        <div className="w-64 h-6 bg-slate-700 rounded-full border-2 border-white overflow-hidden relative shadow-lg">
             <div className="h-full bg-red-500 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-xs font-bold text-white text-shadow">
                 HP {Math.ceil(uiStats.hp)} / {uiStats.maxHp}
             </span>
        </div>
        {/* XP Bar */}
        <div className="w-64 h-4 bg-slate-700 rounded-full border border-white/50 overflow-hidden relative shadow-lg">
             <div className="h-full bg-blue-500 transition-all duration-300" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white text-shadow">
                 LVL {uiStats.level}
             </span>
        </div>
      </div>

      {/* Timer */}
      <div className="fixed top-4 left-1/2 -translate-x-1/2 text-2xl font-black text-white drop-shadow-lg font-mono pointer-events-none z-10">
          {Math.floor(gameTimeDisplay / 60).toString().padStart(2, '0')}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
      </div>

      {/* Quiz Modal */}
      {quizWord && (
          <GameQuizModal 
             word={quizWord} 
             allWords={words} 
             onResult={handleQuizResult} 
          />
      )}

      {/* Upgrade Modal */}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md animate-fade-in">
              <div className="max-w-4xl w-full p-8">
                  <h2 className="text-4xl font-black text-yellow-400 text-center mb-8 uppercase tracking-widest drop-shadow-md">Level Up! 选择升级</h2>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      {showUpgrades.map(opt => (
                          <button 
                            key={opt.id}
                            onClick={() => applyUpgrade(opt)}
                            className="bg-slate-800 border-2 border-slate-600 hover:border-yellow-400 hover:bg-slate-700 p-6 rounded-2xl flex flex-col items-center gap-4 transition-all hover:scale-105 active:scale-95 group"
                          >
                              <div className="text-6xl group-hover:animate-bounce">{opt.icon}</div>
                              <div className="text-2xl font-bold text-white">{opt.name}</div>
                              <div className="text-slate-400 text-center">{opt.description}</div>
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* Game Over Modal */}
      {gameOver && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-red-900/90 backdrop-blur-md">
              <div className="text-center p-12 bg-white rounded-3xl shadow-2xl max-w-lg w-full">
                  <h1 className="text-5xl font-black text-red-600 mb-2">YOU DIED</h1>
                  <p className="text-slate-500 mb-8 text-xl">生存时间: {Math.floor(gameTimeDisplay / 60)}分 {gameTimeDisplay % 60}秒</p>
                  <p className="text-indigo-600 font-bold mb-8">等级: {uiStats.level}</p>

                  <div className="flex gap-4 justify-center">
                    <button onClick={() => window.location.reload()} className="px-8 py-3 bg-slate-800 text-white font-bold rounded-xl hover:bg-slate-700">重试</button>
                    <button onClick={onExit} className="px-8 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700">退出</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { AssetTypes, initGameAssets } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const FPS = 60;
const SPAWN_RATE_INITIAL = 100; // Slower spawn (was 60)
const BASE_XP_REQUIREMENT = 3;

// Upgrade Definitions
const UPGRADES: UpgradeOption[] = [
  { 
    id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪',
    apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
  },
  { 
    id: 'spd_up', name: '疾风步', description: '移动速度 +10%', icon: '👟',
    apply: (s) => ({ ...s, speed: s.speed * 1.1 }) 
  },
  { 
    id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +15%', icon: '🔫',
    apply: (s) => ({ ...s, attackSpeed: Math.max(5, s.attackSpeed * 0.85) }) 
  },
  { 
    id: 'hp_up', name: '坚韧', description: '最大生命 +30, 恢复满血', icon: '❤️',
    apply: (s) => ({ ...s, maxHp: s.maxHp + 30, hp: s.maxHp + 30 }) 
  },
  { 
    id: 'multishot', name: '多重射击', description: '同时发射子弹数 +1', icon: '✨',
    apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
  },
  { 
    id: 'range_up', name: '磁铁', description: '拾取范围 +50%', icon: '🧲',
    apply: (s) => ({ ...s, pickupRange: s.pickupRange * 1.5 }) 
  }
];

// Helper to calculate 16:9 dimensions
const calculateDimensions = () => {
  const winW = window.innerWidth;
  const winH = window.innerHeight;
  const targetRatio = 16 / 9;
  const winRatio = winW / winH;

  let width, height;

  if (winRatio > targetRatio) {
    // Window is wider than 16:9 (Pillarbox)
    height = winH;
    width = height * targetRatio;
  } else {
    // Window is taller than 16:9 (Letterbox)
    width = winW;
    height = width / targetRatio;
  }
  return { width, height };
};

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // -- GAME STATE REFS (Mutable for Performance) --
  // Initialize Dimensions
  const [dimensions, setDimensions] = useState(calculateDimensions());

  const playerRef = useRef<Entity>({
    id: 'hero', 
    x: dimensions.width / 2, 
    y: dimensions.height / 2, 
    width: 48, height: 48, 
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 4, damage: 10, attackSpeed: 30, projectileSpeed: 8, pickupRange: 80,
    projectileCount: 1, // Start with 1 bullet
    level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});
  const mouseRef = useRef({ x: 0, y: 0 });
  const gameTimeRef = useRef(0); // Seconds
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);

  // Quiz Pacing Logic
  const quizCooldownRef = useRef(0); 

  // -- ASSETS --
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});

  // -- REACT STATE (UI Only) --
  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameOver, setGameOver] = useState(false);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);

  // Upgrade Menu Selection State
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(0);

  // Resize Listener
  useEffect(() => {
    const handleResize = () => {
      const newDims = calculateDimensions();
      setDimensions(newDims);
      // Optional: Adjust player position relative to new size if needed, 
      // but loop logic handles bounds automatically.
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Gamepad Polling for Upgrade Menu
  useEffect(() => {
    if (!showUpgrades) return;

    let lastAxisX = 0;
    let lastButtonState = false;

    const pollGamepad = () => {
      const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
      const gp = gamepads[0];

      if (gp) {
        // Navigation (D-Pad or Stick)
        const axisX = gp.axes[0];
        const isLeft = axisX < -0.5 || gp.buttons[14]?.pressed;
        const isRight = axisX > 0.5 || gp.buttons[15]?.pressed;

        // Debounce axis movement
        if (isLeft && lastAxisX >= -0.5) {
            setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
        } else if (isRight && lastAxisX <= 0.5) {
            setUpgradeFocusedIndex(prev => Math.min(2, prev + 1));
        }

        lastAxisX = axisX;

        // Selection (Button A/X - usually index 0)
        // We handle button press in a separate check or here if we want instant trigger
      }

      if (showUpgrades) {
        requestAnimationFrame(pollGamepad);
      }
    };

    requestAnimationFrame(pollGamepad);
  }, [showUpgrades, upgradeFocusedIndex]);

  // Separate effect to handle 'Enter' on upgrades with latest state
  useEffect(() => {
    if (!showUpgrades) return;

    let lastButtonState = false;
    const checkButton = () => {
        const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
        const gp = gamepads[0];
        if (gp) {
            if (gp.buttons[0]?.pressed && !lastButtonState) {
                applyUpgrade(showUpgrades[upgradeFocusedIndex]);
            }
            lastButtonState = gp.buttons[0]?.pressed;
        }
        if (showUpgrades) requestAnimationFrame(checkButton);
    };
    requestAnimationFrame(checkButton);
  }, [showUpgrades, upgradeFocusedIndex]);


  // Initialize Assets & Inputs
  useEffect(() => {
    // Trigger async asset generation
    initGameAssets((key, url) => {
        const img = new Image();
        img.src = url;
        // Pre-decode for smoother performance
        img.decode().then(() => {
             spritesRef.current[key] = img;
        }).catch(() => {
             spritesRef.current[key] = img;
        });
    });

    const handleKeyDown = (e: KeyboardEvent) => { 
        // Prevent game control if paused (Quiz or Upgrades open)
        if (isPausedRef.current) return;
        keysRef.current[e.key.toLowerCase()] = true; 
    };
    const handleKeyUp = (e: KeyboardEvent) => { 
        // Always allow keyup to clear state to prevent stuck keys
        keysRef.current[e.key.toLowerCase()] = false; 
    };
    const handleMouseMove = (e: MouseEvent) => { 
        if (isPausedRef.current) return;
        // We need to adjust mouse coordinates because canvas might be offset due to centering
        const canvas = canvasRef.current;
        if (canvas) {
            const rect = canvas.getBoundingClientRect();
            mouseRef.current = { 
                x: e.clientX - rect.left, 
                y: e.clientY - rect.top 
            };
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousemove', handleMouseMove);

    // Start Loop
    animationFrameId.current = requestAnimationFrame(gameLoop);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousemove', handleMouseMove);
      cancelAnimationFrame(animationFrameId.current);
    };
  }, []);

  // === GAME LOOP ===
  const gameLoop = () => {
    if (gameOver) return;

    if (!isPausedRef.current) {
      update();
    }
    draw();
    animationFrameId.current = requestAnimationFrame(gameLoop);
  };

  // === UPDATE LOGIC ===
  const update = () => {
    const player = playerRef.current;
    const stats = statsRef.current;
    const canvas = canvasRef.current;
    if (!canvas) return;

    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    // 1. Player Movement
    let dx = 0;
    let dy = 0;

    // A. Keyboard Input
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // B. Gamepad Input
    const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
    const gp = gamepads[0]; // Assume Player 1

    if (gp) {
        const deadzone = 0.2;

        // Left Analog Stick (Axes 0, 1)
        if (Math.abs(gp.axes[0]) > deadzone) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > deadzone) dy += gp.axes[1];

        // D-Pad (Standard Layout: Buttons 12, 13, 14, 15)
        // 12: Up, 13: Down, 14: Left, 15: Right
        if (gp.buttons[12]?.pressed) dy -= 1;
        if (gp.buttons[13]?.pressed) dy += 1;
        if (gp.buttons[14]?.pressed) dx -= 1;
        if (gp.buttons[15]?.pressed) dx += 1;
    }

    // Normalize and Move
    if (dx !== 0 || dy !== 0) {
      const length = Math.sqrt(dx * dx + dy * dy);
      // Normalize vector so diagonal movement isn't faster, then apply speed
      const normalizedFactor = length > 1 ? 1 / length : 1;

      player.x += (dx * normalizedFactor) * stats.speed;
      player.y += (dy * normalizedFactor) * stats.speed;
    }

    // Boundary check
    player.x = Math.max(0, Math.min(canvas.width, player.x));
    player.y = Math.max(0, Math.min(canvas.height, player.y));

    // 2. Spawning System
    spawnEnemies(canvas);

    // 3. Enemy Logic
    enemiesRef.current.forEach(enemy => {
      // Move towards player
      const angle = Math.atan2(player.y - enemy.y, player.x - enemy.x);
      enemy.vx = Math.cos(angle) * (enemy.type.includes('ELITE') ? 2.5 : enemy.type === 'BOSS' ? 1.5 : 2);
      enemy.vy = Math.sin(angle) * (enemy.type.includes('ELITE') ? 2.5 : enemy.type === 'BOSS' ? 1.5 : 2);

      enemy.x += enemy.vx;
      enemy.y += enemy.vy;

      // Boss Shooting
      if (enemy.type === 'BOSS' && frameCountRef.current % 120 === 0) {
          spawnBossBullets(enemy);
      }
      // Ranged Elite Shooting
      if (enemy.type === 'ELITE_RANGED' && frameCountRef.current % 180 === 0) {
          spawnEnemyBullet(enemy, player);
      }

      // Player Collision (Damage)
      const dist = Math.hypot(player.x - enemy.x, player.y - enemy.y);
      if (dist < (player.width/2 + enemy.width/2)) {
         if (frameCountRef.current % 30 === 0) { // I-frame like mechanism
             takeDamage(enemy.damage);
         }
      }
    });

    // 4. Combat (Auto-fire)
    if (frameCountRef.current % stats.attackSpeed === 0) {
      fireBullet();
    }

    // 5. Projectiles (Player)
    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx;
      p.y += p.vy;

      // Enemy Collision
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width / 2 + 10)) {
              enemy.hp -= p.damage;
              hit = true;
              break; // Single target bullet for now
            }
          }
      } else {
          // Enemy Projectile hits Player
           if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width / 2 + 10)) {
               takeDamage(p.damage);
               hit = true;
           }
      }

      // Out of bounds
      const oob = p.x < 0 || p.x > canvas.width || p.y < 0 || p.y > canvas.height;
      return !oob && !hit;
    });

    // 6. Clean up Dead Enemies & Drop XP
    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        xpGemsRef.current.push({
          id: Math.random().toString(),
          x: e.x, y: e.y, width: 20, height: 20, type: 'XP',
          vx: 0, vy: 0, hp: 1, maxHp: 1, damage: 0
        });
        return false;
      }
      return true;
    });

    // 7. XP Collection
    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const dist = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (dist < stats.pickupRange) {
        // Magnet effect
        gem.x += (player.x - gem.x) * 0.1;
        gem.y += (player.y - gem.y) * 0.1;

        if (dist < 20) {
          gainXp(1);
          return false;
        }
      }
      return true;
    });

    // Sync UI stats infrequently
    if (frameCountRef.current % 10 === 0) {
        setUiStats({...statsRef.current});
    }
  };

  // === HELPERS ===

  const spawnEnemies = (canvas: HTMLCanvasElement) => {
      const time = gameTimeRef.current;
      // Slower spawn rate calculation
      const spawnRate = Math.max(30, SPAWN_RATE_INITIAL - Math.floor(time / 5));

      // Boss Spawn: Minute 2 (120s)
      if (time === 120 && !enemiesRef.current.some(e => e.type === 'BOSS')) {
          spawnEntity(canvas, 'BOSS');
          return;
      }

      if (frameCountRef.current % spawnRate === 0) {
          // Difficulty scaling
          const r = Math.random();
          let type = 'MOB';
          if (time > 30 && r > 0.9) type = 'ELITE';
          if (time > 60 && r > 0.8) type = 'ELITE';

          spawnEntity(canvas, type as any);
      }
  };

  const spawnEntity = (canvas: HTMLCanvasElement, category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4); // 0: top, 1: right, 2: bottom, 3: left
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * canvas.width; y = -50; }
      else if (side === 1) { x = canvas.width + 50; y = Math.random() * canvas.height; }
      else if (side === 2) { x = Math.random() * canvas.width; y = canvas.height + 50; }
      else { x = -50; y = Math.random() * canvas.height; }

      let entity: Entity = {
          id: Math.random().toString(),
          x, y, vx: 0, vy: 0, 
          type: 'MOB', width: 40, height: 40, hp: 10, maxHp: 10, damage: 5
      };

      if (category === 'BOSS') {
          entity = { ...entity, type: 'BOSS', width: 120, height: 120, hp: 2000, maxHp: 2000, damage: 20, spriteUrl: AssetTypes.BOSS };
      } else if (category === 'ELITE') {
          const sub = Math.random();
          if (sub < 0.33) {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_MELEE, hp: 100, damage: 15, width: 60, height: 60 }; // Melee
          } else if (sub < 0.66) {
             entity = { ...entity, type: 'ELITE_RANGED' as any, spriteUrl: AssetTypes.ELITE_RANGED, hp: 60, damage: 10, width: 50, height: 50 }; // Ranged
          } else {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_TANK, hp: 150, damage: 10, width: 70, height: 70 }; // Tank
          }
      } else {
          // Mob
          const mobTypes = [AssetTypes.MOB_1, AssetTypes.MOB_2, AssetTypes.MOB_3, AssetTypes.MOB_4, AssetTypes.MOB_5];
          entity = { ...entity, type: 'MOB', spriteUrl: mobTypes[Math.floor(Math.random() * 5)], hp: 10 + (gameTimeRef.current * 0.5) };
      }

      enemiesRef.current.push(entity);
  };

  const fireBullet = () => {
    // Find closest enemy
    let closest = null;
    let minDst = Infinity;
    const p = playerRef.current;

    for (const e of enemiesRef.current) {
        const d = Math.hypot(e.x - p.x, e.y - p.y);
        if (d < minDst) {
            minDst = d;
            closest = e;
        }
    }

    if (closest) {
        const baseAngle = Math.atan2(closest.y - p.y, closest.x - p.x);
        const count = statsRef.current.projectileCount || 1;

        // Multi-shot logic
        for (let i = 0; i < count; i++) {
             // Spread angle: 0.2 radians approx 11 degrees
             const offset = count > 1 ? (i - (count - 1) / 2) * 0.2 : 0;
             const angle = baseAngle + offset;

             projectilesRef.current.push({
                id: Math.random().toString(),
                x: p.x, y: p.y, width: 10, height: 10, type: 'PROJECTILE',
                vx: Math.cos(angle) * statsRef.current.projectileSpeed,
                vy: Math.sin(angle) * statsRef.current.projectileSpeed,
                hp: 1, maxHp: 1, damage: statsRef.current.damage
            });
        }
    }
  };

  const spawnEnemyBullet = (enemy: Entity, target: Entity) => {
      const angle = Math.atan2(target.y - enemy.y, target.x - enemy.x);
      projectilesRef.current.push({
          id: Math.random().toString(),
          x: enemy.x, y: enemy.y, width: 12, height: 12, type: 'ENEMY_PROJECTILE',
          vx: Math.cos(angle) * 4,
          vy: Math.sin(angle) * 4,
          hp: 1, maxHp: 1, damage: 10
      });
  };

  const spawnBossBullets = (boss: Entity) => {
      // Ring of 8
      for (let i = 0; i < 8; i++) {
          const angle = (Math.PI * 2 / 8) * i;
          projectilesRef.current.push({
              id: Math.random().toString(),
              x: boss.x, y: boss.y, width: 16, height: 16, type: 'ENEMY_PROJECTILE',
              vx: Math.cos(angle) * 5,
              vy: Math.sin(angle) * 5,
              hp: 1, maxHp: 1, damage: 15
          });
      }
  };

  const takeDamage = (amount: number) => {
      statsRef.current.hp -= amount;
      if (statsRef.current.hp <= 0) {
          setGameOver(true);
          isPausedRef.current = true;
      }
  };

  const gainXp = (amount: number) => {
      statsRef.current.xp += amount;
      if (statsRef.current.xp >= statsRef.current.xpToNextLevel) {
          triggerLevelUp();
      }
  };

  const triggerLevelUp = () => {
      isPausedRef.current = true;
      // Clear movement keys so player doesn't keep running when game resumes if keys were held
      keysRef.current = {}; 

      // Check cooldown
      if (quizCooldownRef.current <= 0) {
          // Trigger Quiz
          const word = words[Math.floor(Math.random() * words.length)];
          setQuizWord(word);

          // Reset cooldown to random 3-5
          quizCooldownRef.current = Math.floor(Math.random() * 3) + 3;
      } else {
          // Free Upgrade (Skip Quiz)
          quizCooldownRef.current -= 1;
          showUpgradeMenu();
      }
  };

  const showUpgradeMenu = () => {
      const options = [...UPGRADES].sort(() => 0.5 - Math.random()).slice(0, 3);
      setShowUpgrades(options);
      setUpgradeFocusedIndex(1); // Focus middle option by default
  };

  const handleQuizResult = (correct: boolean) => {
      setQuizWord(null);
      if (correct) {
          showUpgradeMenu();
      } else {
          // No upgrade, increase requirement slightly, resume
          statsRef.current.xp = 0;
          statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.2);
          isPausedRef.current = false;
      }
  };

  const applyUpgrade = (opt: UpgradeOption) => {
      statsRef.current = opt.apply(statsRef.current);
      statsRef.current.level += 1;
      statsRef.current.xp = 0;
      statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.2);

      setShowUpgrades(null);
      isPausedRef.current = false;
  };

  // === DRAW ===
  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Background
    ctx.fillStyle = '#f0f9ff'; // Slate-50-ish
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Grid
    ctx.strokeStyle = '#e2e8f0';
    ctx.lineWidth = 1;
    const gridSize = 50;
    for (let x = 0; x < canvas.width; x += gridSize) {
        ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, canvas.height); ctx.stroke();
    }
    for (let y = 0; y < canvas.height; y += gridSize) {
        ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(canvas.width, y); ctx.stroke();
    }

    // Draw Entity Helper
    const drawSprite = (e: Entity, fallbackColor: string) => {
        // Try to find sprite
        const sprite = e.spriteUrl ? spritesRef.current[e.spriteUrl] || spritesRef.current[e.type] : null;

        // If sprite is loaded, draw it
        if (sprite && sprite.complete && sprite.naturalWidth > 0) {
            ctx.drawImage(sprite, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            // Fallback square or circle
            ctx.fillStyle = fallbackColor;
            if (e.type === 'XP') {
                ctx.beginPath();
                ctx.arc(e.x, e.y, e.width/2, 0, Math.PI * 2);
                ctx.fill();
            } else {
                ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
            }
        }
    };

    // XP - Use Gold Color #fbbf24
    xpGemsRef.current.forEach(gem => {
        drawSprite(gem, '#fbbf24');
    });

    // Enemies
    enemiesRef.current.forEach(e => {
        drawSprite(e, e.type === 'BOSS' ? '#dc2626' : '#64748b');
        // HP Bar for Elites/Boss
        if (e.type !== 'MOB') {
            ctx.fillStyle = 'red';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2 - 10, e.width, 4);
            ctx.fillStyle = 'green';
            ctx.fillRect(e.x - e.width/2, e.y - e.height/2 - 10, e.width * (e.hp/e.maxHp), 4);
        }
    });

    // Player
    drawSprite(playerRef.current, '#6366f1');

    // Projectiles
    projectilesRef.current.forEach(p => {
        ctx.fillStyle = p.type === 'PROJECTILE' ? '#fbbf24' : '#ef4444';
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2);
        ctx.fill();
    });
  };

  return (
    <div className="fixed inset-0 w-full h-full overflow-hidden bg-black flex items-center justify-center cursor-crosshair">
      <canvas 
        ref={canvasRef} 
        width={dimensions.width} 
        height={dimensions.height}
        style={{ 
            width: dimensions.width, 
            height: dimensions.height,
            maxWidth: '100%',
            maxHeight: '100%'
        }}
        className="block bg-slate-50 shadow-2xl"
      />

      {/* HUD Container - Absolute relative to window or scaled container? 
          Currently absolute on window, which is fine for overlay.
      */}
      <div className="fixed top-4 left-4 flex flex-col gap-2 pointer-events-none z-10">
        {/* HP Bar */}
        <div className="w-64 h-6 bg-slate-700 rounded-full border-2 border-white overflow-hidden relative shadow-lg">
             <div className="h-full bg-red-500 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-xs font-bold text-white text-shadow">
                 HP {Math.ceil(uiStats.hp)} / {uiStats.maxHp}
             </span>
        </div>
        {/* XP Bar */}
        <div className="w-64 h-4 bg-slate-700 rounded-full border border-white/50 overflow-hidden relative shadow-lg">
             <div className="h-full bg-blue-500 transition-all duration-300" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white text-shadow">
                 LVL {uiStats.level}
             </span>
        </div>
      </div>

      {/* Timer */}
      <div className="fixed top-4 left-1/2 -translate-x-1/2 text-2xl font-black text-white drop-shadow-lg font-mono pointer-events-none z-10">
          {Math.floor(gameTimeDisplay / 60).toString().padStart(2, '0')}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
      </div>

      {/* Quiz Modal */}
      {quizWord && (
          <GameQuizModal 
             word={quizWord} 
             allWords={words} 
             onResult={handleQuizResult} 
          />
      )}

      {/* Upgrade Modal */}
      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md animate-fade-in">
              <div className="max-w-4xl w-full p-8">
                  <h2 className="text-4xl font-black text-yellow-400 text-center mb-8 uppercase tracking-widest drop-shadow-md">Level Up! 选择升级</h2>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      {showUpgrades.map((opt, index) => (
                          <button 
                            key={opt.id}
                            onClick={() => applyUpgrade(opt)}
                            className={`p-6 rounded-2xl flex flex-col items-center gap-4 transition-all group border-2
                                ${upgradeFocusedIndex === index 
                                    ? 'bg-slate-700 border-yellow-400 scale-110 shadow-xl shadow-yellow-500/20' 
                                    : 'bg-slate-800 border-slate-600 hover:border-yellow-400 hover:bg-slate-700'
                                }`}
                          >
                              <div className={`text-6xl ${upgradeFocusedIndex === index ? 'animate-bounce' : 'group-hover:animate-bounce'}`}>
                                  {opt.icon}
                              </div>
                              <div className="text-2xl font-bold text-white">{opt.name}</div>
                              <div className="text-slate-400 text-center">{opt.description}</div>
                              {upgradeFocusedIndex === index && (
                                  <div className="text-yellow-400 text-sm font-bold mt-2 animate-pulse">[ A ] SELECT</div>
                              )}
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* Game Over Modal */}
      {gameOver && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-red-900/90 backdrop-blur-md">
              <div className="text-center p-12 bg-white rounded-3xl shadow-2xl max-w-lg w-full">
                  <h1 className="text-5xl font-black text-red-600 mb-2">YOU DIED</h1>
                  <p className="text-slate-500 mb-8 text-xl">生存时间: {Math.floor(gameTimeDisplay / 60)}分 {gameTimeDisplay % 60}秒</p>
                  <p className="text-indigo-600 font-bold mb-8">等级: {uiStats.level}</p>

                  <div className="flex gap-4 justify-center">
                    <button onClick={() => window.location.reload()} className="px-8 py-3 bg-slate-800 text-white font-bold rounded-xl hover:bg-slate-700">重试</button>
                    <button onClick={onExit} className="px-8 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700">退出</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { WordData } from '../types';
import { speakText, playSuccessSound, playErrorSound } from '../services/audioService';

interface GameQuizModalProps {
  word: WordData;
  allWords: WordData[];
  onResult: (correct: boolean) => void;
}

type QuizMode = 'SPELL_FROM_DEF' | 'SPELL_FROM_AUDIO' | 'MEANING_FROM_WORD';

export const GameQuizModal: React.FC<GameQuizModalProps> = ({ word, allWords, onResult }) => {
  const [mode, setMode] = useState<QuizMode>('SPELL_FROM_DEF');
  const [input, setInput] = useState('');
  const [choices, setChoices] = useState<WordData[]>([]);
  const [status, setStatus] = useState<'idle' | 'correct' | 'incorrect'>('idle');
  const [focusedChoiceIndex, setFocusedChoiceIndex] = useState(0);

  const inputRef = useRef<HTMLInputElement>(null);

  // Setup
  useEffect(() => {
    const modes: QuizMode[] = ['SPELL_FROM_DEF', 'SPELL_FROM_AUDIO', 'MEANING_FROM_WORD'];
    const selectedMode = modes[Math.floor(Math.random() * modes.length)];
    setMode(selectedMode);

    if (selectedMode === 'MEANING_FROM_WORD') {
      const distractors = allWords
        .filter(w => w.id !== word.id)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      const options = [word, ...distractors].sort(() => 0.5 - Math.random());
      setChoices(options);
    } else if (selectedMode === 'SPELL_FROM_AUDIO') {
      setTimeout(() => speakText(word.word), 300);
    }

    // Auto focus
    setTimeout(() => inputRef.current?.focus(), 100);
  }, [word, allWords]);

  // Gamepad Polling for Multiple Choice
  useEffect(() => {
    if (mode !== 'MEANING_FROM_WORD' || status !== 'idle') return;

    let lastAxisY = 0;
    let lastAxisX = 0;
    let lastButtonState = false;

    const pollGamepad = () => {
        const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
        const gp = gamepads[0];
        if (gp) {
            const axisX = gp.axes[0];
            const axisY = gp.axes[1];

            // Grid is 2x2. 0,1 top row. 2,3 bottom row.

            // Left/Right
            if ((axisX < -0.5 || gp.buttons[14]?.pressed) && lastAxisX >= -0.5) { // Left
                setFocusedChoiceIndex(prev => (prev % 2 === 1) ? prev - 1 : prev); 
            }
            if ((axisX > 0.5 || gp.buttons[15]?.pressed) && lastAxisX <= 0.5) { // Right
                setFocusedChoiceIndex(prev => (prev % 2 === 0) ? Math.min(3, prev + 1) : prev);
            }

            // Up/Down
            if ((axisY < -0.5 || gp.buttons[12]?.pressed) && lastAxisY >= -0.5) { // Up
                setFocusedChoiceIndex(prev => (prev >= 2) ? prev - 2 : prev);
            }
            if ((axisY > 0.5 || gp.buttons[13]?.pressed) && lastAxisY <= 0.5) { // Down
                setFocusedChoiceIndex(prev => (prev < 2) ? prev + 2 : prev);
            }

            lastAxisX = axisX;
            lastAxisY = axisY;

            // Select
            if (gp.buttons[0]?.pressed && !lastButtonState) {
                if (choices[focusedChoiceIndex]) {
                    checkChoice(choices[focusedChoiceIndex].id);
                }
            }
            lastButtonState = gp.buttons[0]?.pressed;
        }

        if (status === 'idle') requestAnimationFrame(pollGamepad);
    };

    requestAnimationFrame(pollGamepad);
  }, [mode, status, focusedChoiceIndex, choices]);


  const handleCorrect = () => {
    setStatus('correct');
    playSuccessSound();
    speakText(word.word);
    setTimeout(() => onResult(true), 1200);
  };

  const handleIncorrect = () => {
    setStatus('incorrect');
    playErrorSound();
    speakText(word.word); // Teach them
    setTimeout(() => onResult(false), 2000); // Longer delay to see answer
  };

  const checkSpelling = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim().toLowerCase() === word.word.toLowerCase()) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  const checkChoice = (selectedId: string) => {
    if (selectedId === word.id) {
      handleCorrect();
    } else {
      handleIncorrect();
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm">
      <div className={`bg-white rounded-2xl p-8 w-full max-w-2xl shadow-2xl border-4 transform transition-all ${status === 'correct' ? 'border-green-500 scale-105' : status === 'incorrect' ? 'border-red-500 animate-shake' : 'border-indigo-500'}`}>

        {/* Header */}
        <div className="text-center mb-6">
          <h2 className="text-2xl font-black text-slate-800 uppercase tracking-widest mb-1">升级挑战</h2>
          <div className="text-slate-500 text-sm">回答正确获得强力属性提升！</div>
        </div>

        {/* Content */}
        <div className="mb-8 min-h-[150px] flex flex-col justify-center items-center">
          {mode === 'SPELL_FROM_DEF' && (
             <>
               <span className="bg-indigo-100 text-indigo-700 px-3 py-1 rounded-full text-xs font-bold mb-4">看义拼词</span>
               <p className="text-2xl font-bold text-slate-800 text-center">{word.definition}</p>
             </>
          )}

          {mode === 'SPELL_FROM_AUDIO' && (
            <>
              <span className="bg-pink-100 text-pink-700 px-3 py-1 rounded-full text-xs font-bold mb-4">听音拼词</span>
              <button 
                onClick={() => speakText(word.word)}
                className="w-20 h-20 bg-indigo-500 rounded-full flex items-center justify-center text-white shadow-lg hover:bg-indigo-600 active:scale-95 transition-all"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"></polygon><path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"></path></svg>
              </button>
            </>
          )}

          {mode === 'MEANING_FROM_WORD' && (
             <h1 className="text-5xl font-black text-slate-800 mb-4">{word.word}</h1>
          )}
        </div>

        {/* Inputs */}
        <div className="w-full">
          {mode === 'MEANING_FROM_WORD' ? (
            <div className="grid grid-cols-2 gap-4">
              {choices.map((choice, index) => (
                <button
                  key={choice.id}
                  onClick={() => checkChoice(choice.id)}
                  disabled={status !== 'idle'}
                  className={`p-4 rounded-xl font-bold text-lg text-left transition-all border-b-4 active:border-b-0 active:translate-y-1 relative
                    ${status === 'correct' && choice.id === word.id ? 'bg-green-500 text-white border-green-700' : 
                      status === 'incorrect' && choice.id === word.id ? 'bg-green-500 text-white border-green-700' : // Show correct answer
                      status === 'incorrect' && choice.id !== word.id ? 'bg-red-100 text-red-400 border-red-200' :
                      focusedChoiceIndex === index ? 'bg-indigo-50 border-indigo-500 ring-2 ring-indigo-300 text-indigo-700 scale-105 z-10' :
                      'bg-slate-100 border-slate-300 hover:bg-indigo-50 hover:border-indigo-300 text-slate-700'}`}
                >
                  {choice.definition}
                  {focusedChoiceIndex === index && status === 'idle' && (
                      <div className="absolute top-1 right-2 text-indigo-400 text-xs font-bold">[A]</div>
                  )}
                </button>
              ))}
            </div>
          ) : (
            <form onSubmit={checkSpelling}>
              <input
                ref={inputRef}
                type="text"
                value={input}
                onChange={e => setInput(e.target.value)}
                disabled={status !== 'idle'}
                placeholder="输入单词..."
                className={`w-full text-center text-4xl font-mono font-bold py-4 border-b-4 bg-transparent outline-none transition-colors
                  ${status === 'correct' ? 'border-green-500 text-green-600' : 
                    status === 'incorrect' ? 'border-red-500 text-red-500' : 'border-slate-300 focus:border-indigo-500 text-slate-800'}`}
                autoComplete="off"
              />
              {status === 'incorrect' && (
                <div className="text-center mt-2 text-red-500 font-bold animate-fade-in">
                  正确答案: {word.word}
                </div>
              )}
            </form>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { AssetTypes, initGameAssets } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const FPS = 60;
const SPAWN_RATE_INITIAL = 100;
const BASE_XP_REQUIREMENT = 3;

// Fixed Logical Resolution (16:9 FHD)
// The canvas will scale via CSS to fit any screen (4K, Mobile, etc.)
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

// Upgrade Definitions
const UPGRADES: UpgradeOption[] = [
  { 
    id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪',
    apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
  },
  { 
    id: 'spd_up', name: '疾风步', description: '移动速度 +10%', icon: '👟',
    apply: (s) => ({ ...s, speed: s.speed * 1.1 }) 
  },
  { 
    id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +15%', icon: '🔫',
    apply: (s) => ({ ...s, attackSpeed: Math.max(5, s.attackSpeed * 0.85) }) 
  },
  { 
    id: 'hp_up', name: '坚韧', description: '最大生命 +30, 恢复满血', icon: '❤️',
    apply: (s) => ({ ...s, maxHp: s.maxHp + 30, hp: s.maxHp + 30 }) 
  },
  { 
    id: 'multishot', name: '多重射击', description: '额外子弹 +1 (叠加)', icon: '✨',
    apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
  },
  { 
    id: 'range_up', name: '磁铁', description: '拾取范围 +50%', icon: '🧲',
    apply: (s) => ({ ...s, pickupRange: s.pickupRange * 1.5 }) 
  }
];

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', 
    x: GAME_WIDTH / 2, 
    y: GAME_HEIGHT / 2, 
    width: 64, height: 64, // Scaled up for 1080p
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 6, // Increased base speed for larger map
    damage: 10, attackSpeed: 30, projectileSpeed: 12, pickupRange: 120,
    projectileCount: 1, 
    level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});
  const mouseRef = useRef({ x: 0, y: 0 });
  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);

  const quizCooldownRef = useRef(0); 
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});

  // -- REACT STATE --
  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameOver, setGameOver] = useState(false);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(0);

  // Gamepad Polling for Upgrade Menu
  useEffect(() => {
    if (!showUpgrades) return;

    let lastAxisX = 0;
    let lastButtonState = false;

    const pollGamepad = () => {
      const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
      const gp = gamepads[0];

      if (gp) {
        const axisX = gp.axes[0];
        const isLeft = axisX < -0.5 || gp.buttons[14]?.pressed;
        const isRight = axisX > 0.5 || gp.buttons[15]?.pressed;

        if (isLeft && lastAxisX >= -0.5) {
            setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
        } else if (isRight && lastAxisX <= 0.5) {
            setUpgradeFocusedIndex(prev => Math.min(2, prev + 1));
        }
        lastAxisX = axisX;
      }
      if (showUpgrades) requestAnimationFrame(pollGamepad);
    };
    requestAnimationFrame(pollGamepad);
  }, [showUpgrades, upgradeFocusedIndex]);

  // Upgrade Selection Listener
  useEffect(() => {
    if (!showUpgrades) return;

    let lastButtonState = false;
    const checkButton = () => {
        const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
        const gp = gamepads[0];
        if (gp) {
            if (gp.buttons[0]?.pressed && !lastButtonState) {
                applyUpgrade(showUpgrades[upgradeFocusedIndex]);
            }
            lastButtonState = gp.buttons[0]?.pressed;
        }
        if (showUpgrades) requestAnimationFrame(checkButton);
    };
    requestAnimationFrame(checkButton);
  }, [showUpgrades, upgradeFocusedIndex]);

  // Initialize Assets & Inputs
  useEffect(() => {
    initGameAssets((key, url) => {
        const img = new Image();
        img.src = url;
        img.decode().then(() => { spritesRef.current[key] = img; }).catch(() => { spritesRef.current[key] = img; });
    });

    const handleKeyDown = (e: KeyboardEvent) => { 
        if (isPausedRef.current) return;
        keysRef.current[e.key.toLowerCase()] = true; 
    };
    const handleKeyUp = (e: KeyboardEvent) => { 
        keysRef.current[e.key.toLowerCase()] = false; 
    };
    const handleMouseMove = (e: MouseEvent) => { 
        if (isPausedRef.current) return;
        const canvas = canvasRef.current;
        if (canvas) {
            const rect = canvas.getBoundingClientRect();
            // Scale mouse position from Screen Pixels to Game Logical Pixels (1920x1080)
            const scaleX = GAME_WIDTH / rect.width;
            const scaleY = GAME_HEIGHT / rect.height;

            mouseRef.current = { 
                x: (e.clientX - rect.left) * scaleX, 
                y: (e.clientY - rect.top) * scaleY
            };
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousemove', handleMouseMove);

    animationFrameId.current = requestAnimationFrame(gameLoop);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousemove', handleMouseMove);
      cancelAnimationFrame(animationFrameId.current);
    };
  }, []);

  // === GAME LOOP ===
  const gameLoop = () => {
    if (gameOver) return;
    if (!isPausedRef.current) update();
    draw();
    animationFrameId.current = requestAnimationFrame(gameLoop);
  };

  // === UPDATE LOGIC ===
  const update = () => {
    const player = playerRef.current;
    const stats = statsRef.current;

    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    // 1. Player Movement
    let dx = 0; let dy = 0;
    // Keyboard
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Gamepad
    const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
    const gp = gamepads[0];
    if (gp) {
        const deadzone = 0.2;
        if (Math.abs(gp.axes[0]) > deadzone) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > deadzone) dy += gp.axes[1];
        if (gp.buttons[12]?.pressed) dy -= 1;
        if (gp.buttons[13]?.pressed) dy += 1;
        if (gp.buttons[14]?.pressed) dx -= 1;
        if (gp.buttons[15]?.pressed) dx += 1;
    }

    if (dx !== 0 || dy !== 0) {
      const length = Math.sqrt(dx * dx + dy * dy);
      const normalizedFactor = length > 1 ? 1 / length : 1;
      player.x += (dx * normalizedFactor) * stats.speed;
      player.y += (dy * normalizedFactor) * stats.speed;
    }

    // Boundary check (Fixed 1920x1080)
    player.x = Math.max(0, Math.min(GAME_WIDTH, player.x));
    player.y = Math.max(0, Math.min(GAME_HEIGHT, player.y));

    // 2. Spawning & Logic
    spawnEnemies();

    enemiesRef.current.forEach(enemy => {
      const angle = Math.atan2(player.y - enemy.y, player.x - enemy.x);
      enemy.vx = Math.cos(angle) * (enemy.type.includes('ELITE') ? 3.5 : enemy.type === 'BOSS' ? 2 : 2.5);
      enemy.vy = Math.sin(angle) * (enemy.type.includes('ELITE') ? 3.5 : enemy.type === 'BOSS' ? 2 : 2.5);
      enemy.x += enemy.vx;
      enemy.y += enemy.vy;

      if (enemy.type === 'BOSS' && frameCountRef.current % 120 === 0) spawnBossBullets(enemy);
      if (enemy.type === 'ELITE_RANGED' && frameCountRef.current % 180 === 0) spawnEnemyBullet(enemy, player);

      const dist = Math.hypot(player.x - enemy.x, player.y - enemy.y);
      if (dist < (player.width/2 + enemy.width/2)) {
         if (frameCountRef.current % 30 === 0) takeDamage(enemy.damage);
      }
    });

    // 4. Combat
    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width / 2 + 15)) {
              enemy.hp -= p.damage;
              hit = true;
              break;
            }
          }
      } else {
           if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width / 2 + 15)) {
               takeDamage(p.damage);
               hit = true;
           }
      }
      const oob = p.x < 0 || p.x > GAME_WIDTH || p.y < 0 || p.y > GAME_HEIGHT;
      return !oob && !hit;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        xpGemsRef.current.push({
          id: Math.random().toString(),
          x: e.x, y: e.y, width: 24, height: 24, type: 'XP',
          vx: 0, vy: 0, hp: 1, maxHp: 1, damage: 0
        });
        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const dist = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (dist < stats.pickupRange) {
        gem.x += (player.x - gem.x) * 0.15;
        gem.y += (player.y - gem.y) * 0.15;
        if (dist < 30) {
          gainXp(1);
          return false;
        }
      }
      return true;
    });

    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  // === HELPERS ===

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const spawnRate = Math.max(20, SPAWN_RATE_INITIAL - Math.floor(time / 2)); // Faster spawn ramp

      if (time === 120 && !enemiesRef.current.some(e => e.type === 'BOSS')) {
          spawnEntity('BOSS');
          return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          let type = 'MOB';
          if (time > 30 && r > 0.9) type = 'ELITE';
          if (time > 60 && r > 0.8) type = 'ELITE';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }

      // Default Entity
      let entity: Entity = {
          id: Math.random().toString(),
          x, y, vx: 0, vy: 0, 
          type: 'MOB', width: 50, height: 50, // Default size
          hp: 2, maxHp: 2, damage: 5 // Default Mob HP = 2
      };

      if (category === 'BOSS') {
          entity = { ...entity, type: 'BOSS', width: 250, height: 250, hp: 100, maxHp: 100, damage: 20, spriteUrl: AssetTypes.BOSS };
      } else if (category === 'ELITE') {
          // Elite HP = 10
          const sub = Math.random();
          if (sub < 0.33) {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_MELEE, hp: 10, maxHp: 10, damage: 15, width: 90, height: 90 }; 
          } else if (sub < 0.66) {
             entity = { ...entity, type: 'ELITE_RANGED' as any, spriteUrl: AssetTypes.ELITE_RANGED, hp: 10, maxHp: 10, damage: 10, width: 80, height: 80 }; 
          } else {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_TANK, hp: 10, maxHp: 10, damage: 10, width: 100, height: 100 }; 
          }
      } else {
          // Mob HP = 2
          const mobTypes = [AssetTypes.MOB_1, AssetTypes.MOB_2, AssetTypes.MOB_3, AssetTypes.MOB_4, AssetTypes.MOB_5];
          entity = { ...entity, type: 'MOB', spriteUrl: mobTypes[Math.floor(Math.random() * 5)], hp: 2, maxHp: 2 };
      }
      enemiesRef.current.push(entity);
  };

  const fireBullet = () => {
    let closest = null; let minDst = Infinity; const p = playerRef.current;
    for (const e of enemiesRef.current) {
        const d = Math.hypot(e.x - p.x, e.y - p.y);
        if (d < minDst) { minDst = d; closest = e; }
    }
    if (closest) {
        const baseAngle = Math.atan2(closest.y - p.y, closest.x - p.x);
        const count = statsRef.current.projectileCount || 1;
        for (let i = 0; i < count; i++) {
             const offset = count > 1 ? (i - (count - 1) / 2) * 0.15 : 0; // Tighter spread
             const angle = baseAngle + offset;
             projectilesRef.current.push({
                id: Math.random().toString(),
                x: p.x, y: p.y, width: 14, height: 14, type: 'PROJECTILE',
                vx: Math.cos(angle) * statsRef.current.projectileSpeed,
                vy: Math.sin(angle) * statsRef.current.projectileSpeed,
                hp: 1, maxHp: 1, damage: statsRef.current.damage
            });
        }
    }
  };

  const spawnEnemyBullet = (enemy: Entity, target: Entity) => {
      const angle = Math.atan2(target.y - enemy.y, target.x - enemy.x);
      projectilesRef.current.push({
          id: Math.random().toString(),
          x: enemy.x, y: enemy.y, width: 20, height: 20, type: 'ENEMY_PROJECTILE',
          vx: Math.cos(angle) * 5, vy: Math.sin(angle) * 5, hp: 1, maxHp: 1, damage: 10
      });
  };

  const spawnBossBullets = (boss: Entity) => {
      for (let i = 0; i < 12; i++) {
          const angle = (Math.PI * 2 / 12) * i;
          projectilesRef.current.push({
              id: Math.random().toString(),
              x: boss.x, y: boss.y, width: 24, height: 24, type: 'ENEMY_PROJECTILE',
              vx: Math.cos(angle) * 6, vy: Math.sin(angle) * 6, hp: 1, maxHp: 1, damage: 15
          });
      }
  };

  const takeDamage = (amount: number) => {
      statsRef.current.hp -= amount;
      if (statsRef.current.hp <= 0) { setGameOver(true); isPausedRef.current = true; }
  };

  const gainXp = (amount: number) => {
      statsRef.current.xp += amount;
      if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp();
  };

  const triggerLevelUp = () => {
      isPausedRef.current = true;
      keysRef.current = {}; 
      if (quizCooldownRef.current <= 0) {
          const word = words[Math.floor(Math.random() * words.length)];
          setQuizWord(word);
          quizCooldownRef.current = Math.floor(Math.random() * 3) + 3;
      } else {
          quizCooldownRef.current -= 1;
          showUpgradeMenu();
      }
  };

  const showUpgradeMenu = () => {
      const options = [...UPGRADES].sort(() => 0.5 - Math.random()).slice(0, 3);
      setShowUpgrades(options);
      setUpgradeFocusedIndex(1);
  };

  const handleQuizResult = (correct: boolean) => {
      setQuizWord(null);
      if (correct) { showUpgradeMenu(); } 
      else {
          statsRef.current.xp = 0;
          statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.2);
          isPausedRef.current = false;
      }
  };

  const applyUpgrade = (opt: UpgradeOption) => {
      statsRef.current = opt.apply(statsRef.current);
      // ALWAYS ADD 1 PROJECTILE ON LEVEL UP (Requirement)
      statsRef.current.projectileCount += 1;

      statsRef.current.level += 1;
      statsRef.current.xp = 0;
      statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.2);
      setShowUpgrades(null);
      isPausedRef.current = false;
  };

  const toggleFullscreen = () => {
      if (!document.fullscreenElement) {
          document.documentElement.requestFullscreen();
      } else {
          document.exitFullscreen();
      }
  };

  // === DRAW ===
  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Background
    ctx.fillStyle = '#f0f9ff'; 
    ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);

    // Grid
    ctx.strokeStyle = '#e2e8f0';
    ctx.lineWidth = 1;
    const gridSize = 100;
    for (let x = 0; x < GAME_WIDTH; x += gridSize) {
        ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke();
    }
    for (let y = 0; y < GAME_HEIGHT; y += gridSize) {
        ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke();
    }

    const drawSprite = (e: Entity, fallbackColor: string) => {
        const sprite = e.spriteUrl ? spritesRef.current[e.spriteUrl] || spritesRef.current[e.type] : null;
        if (sprite && sprite.complete && sprite.naturalWidth > 0) {
            ctx.drawImage(sprite, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = fallbackColor;
            if (e.type === 'XP') {
                ctx.beginPath(); ctx.arc(e.x, e.y, e.width/2, 0, Math.PI * 2); ctx.fill();
            } else {
                ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
            }
        }
    };

    xpGemsRef.current.forEach(gem => drawSprite(gem, '#fbbf24'));
    enemiesRef.current.forEach(e => {
        drawSprite(e, e.type === 'BOSS' ? '#dc2626' : '#64748b');
        if (e.type !== 'MOB') {
            ctx.fillStyle = 'red'; ctx.fillRect(e.x - e.width/2, e.y - e.height/2 - 15, e.width, 6);
            ctx.fillStyle = 'green'; ctx.fillRect(e.x - e.width/2, e.y - e.height/2 - 15, e.width * (e.hp/e.maxHp), 6);
        }
    });
    drawSprite(playerRef.current, '#6366f1');
    projectilesRef.current.forEach(p => {
        ctx.fillStyle = p.type === 'PROJECTILE' ? '#fbbf24' : '#ef4444';
        ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill();
    });
  };

  return (
    <div className="fixed inset-0 w-full h-full bg-black flex items-center justify-center cursor-crosshair">
      <canvas 
        ref={canvasRef} 
        width={GAME_WIDTH} 
        height={GAME_HEIGHT}
        className="bg-slate-50 shadow-2xl"
        style={{
            width: '100%',
            height: '100%',
            objectFit: 'contain',
            aspectRatio: '16/9'
        }}
      />

      {/* Fullscreen Toggle */}
      <button 
        onClick={toggleFullscreen}
        className="fixed top-4 right-4 z-50 bg-white/20 hover:bg-white/40 text-white p-2 rounded-lg backdrop-blur-sm transition-all"
        title="Toggle Fullscreen"
      >
        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M8 3H5a2 2 0 0 0-2 2v3m18 0V5a2 2 0 0 0-2-2h-3m0 18h3a2 2 0 0 0 2-2v-3M3 16v3a2 2 0 0 0 2 2h3"/></svg>
      </button>

      {/* HUD Container */}
      <div className="fixed top-4 left-4 flex flex-col gap-2 pointer-events-none z-10">
        <div className="w-64 h-6 bg-slate-700 rounded-full border-2 border-white overflow-hidden relative shadow-lg">
             <div className="h-full bg-red-500 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-xs font-bold text-white text-shadow">
                 HP {Math.ceil(uiStats.hp)} / {uiStats.maxHp}
             </span>
        </div>
        <div className="w-64 h-4 bg-slate-700 rounded-full border border-white/50 overflow-hidden relative shadow-lg">
             <div className="h-full bg-blue-500 transition-all duration-300" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white text-shadow">
                 LVL {uiStats.level} (Bullets: {uiStats.projectileCount})
             </span>
        </div>
      </div>

      <div className="fixed top-4 left-1/2 -translate-x-1/2 text-2xl font-black text-white drop-shadow-lg font-mono pointer-events-none z-10">
          {Math.floor(gameTimeDisplay / 60).toString().padStart(2, '0')}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}

      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md animate-fade-in">
              <div className="max-w-4xl w-full p-8">
                  <h2 className="text-4xl font-black text-yellow-400 text-center mb-2 uppercase tracking-widest drop-shadow-md">Level Up!</h2>
                  <p className="text-center text-yellow-200 mb-8 font-bold">+1 额外子弹 (被动获取)</p>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      {showUpgrades.map((opt, index) => (
                          <button 
                            key={opt.id}
                            onClick={() => applyUpgrade(opt)}
                            className={`p-6 rounded-2xl flex flex-col items-center gap-4 transition-all group border-2
                                ${upgradeFocusedIndex === index 
                                    ? 'bg-slate-700 border-yellow-400 scale-110 shadow-xl shadow-yellow-500/20' 
                                    : 'bg-slate-800 border-slate-600 hover:border-yellow-400 hover:bg-slate-700'
                                }`}
                          >
                              <div className={`text-6xl ${upgradeFocusedIndex === index ? 'animate-bounce' : 'group-hover:animate-bounce'}`}>{opt.icon}</div>
                              <div className="text-2xl font-bold text-white">{opt.name}</div>
                              <div className="text-slate-400 text-center">{opt.description}</div>
                              {upgradeFocusedIndex === index && (
                                  <div className="text-yellow-400 text-sm font-bold mt-2 animate-pulse">[ A ] SELECT</div>
                              )}
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameOver && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-red-900/90 backdrop-blur-md">
              <div className="text-center p-12 bg-white rounded-3xl shadow-2xl max-w-lg w-full">
                  <h1 className="text-5xl font-black text-red-600 mb-2">YOU DIED</h1>
                  <p className="text-slate-500 mb-8 text-xl">生存时间: {Math.floor(gameTimeDisplay / 60)}分 {gameTimeDisplay % 60}秒</p>
                  <p className="text-indigo-600 font-bold mb-8">等级: {uiStats.level}</p>
                  <div className="flex gap-4 justify-center">
                    <button onClick={() => window.location.reload()} className="px-8 py-3 bg-slate-800 text-white font-bold rounded-xl hover:bg-slate-700">重试</button>
                    <button onClick={onExit} className="px-8 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700">退出</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

// Singleton AudioContext to avoid hitting mobile browser limits
let audioCtx: AudioContext | null = null;

const getAudioContext = () => {
  if (!audioCtx) {
    const Ctx = window.AudioContext || (window as any).webkitAudioContext;
    if (Ctx) {
      audioCtx = new Ctx();
    }
  }
  return audioCtx;
};

// Call this on user interaction (e.g. click) to unlock audio on iOS
export const resumeAudioContext = () => {
  const ctx = getAudioContext();
  if (ctx && ctx.state === 'suspended') {
    ctx.resume().catch(e => console.error("Audio resume failed", e));
  }
};

// Simple synth sounds to avoid external dependencies
export const playSuccessSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const now = ctx.currentTime;

  // Helper to play a bell-like note
  const playNote = (freq: number, startTime: number, duration: number) => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = 'sine'; // Sine wave for a pure bell tone
    osc.frequency.setValueAtTime(freq, startTime);

    // Envelope for bell sound: fast attack, exponential decay
    gain.gain.setValueAtTime(0, startTime);
    gain.gain.linearRampToValueAtTime(0.15, startTime + 0.02); // Quick attack
    gain.gain.exponentialRampToValueAtTime(0.001, startTime + duration); // Long decay

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(startTime);
    osc.stop(startTime + duration);
  };

  // Play "Ding" (High Note, e.g., E5)
  playNote(659.25, now, 0.8);

  // Play "Dong" (Lower Note, e.g., C5) slightly later
  playNote(523.25, now + 0.25, 1.2);
};

export const playErrorSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  osc.type = 'sawtooth';
  osc.frequency.setValueAtTime(200, ctx.currentTime);
  osc.frequency.linearRampToValueAtTime(100, ctx.currentTime + 0.2);

  gain.gain.setValueAtTime(0.1, ctx.currentTime);
  gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.3);

  osc.connect(gain);
  gain.connect(ctx.destination);

  osc.start();
  osc.stop(ctx.currentTime + 0.3);
};

export const playVictorySound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const now = ctx.currentTime;

  const playNote = (freq: number, startTime: number, duration: number, type: OscillatorType = 'triangle') => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = type;
    osc.frequency.setValueAtTime(freq, startTime);

    gain.gain.setValueAtTime(0, startTime);
    gain.gain.linearRampToValueAtTime(0.2, startTime + 0.05);
    gain.gain.linearRampToValueAtTime(0, startTime + duration);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(startTime);
    osc.stop(startTime + duration);
  };

  // C Major Arpeggio fanfare
  playNote(523.25, now, 0.2);       // C5
  playNote(659.25, now + 0.15, 0.2); // E5
  playNote(783.99, now + 0.30, 0.2); // G5
  playNote(1046.50, now + 0.45, 0.8, 'sine'); // C6 (Long)

  // Confetti sound (noise burst)
  const bufferSize = ctx.sampleRate * 1; 
  const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
  const data = buffer.getChannelData(0);
  for (let i = 0; i < bufferSize; i++) {
    data[i] = Math.random() * 2 - 1;
  }
  const noise = ctx.createBufferSource();
  noise.buffer = buffer;
  const noiseGain = ctx.createGain();
  noiseGain.gain.setValueAtTime(0.1, now + 0.45);
  noiseGain.gain.exponentialRampToValueAtTime(0.001, now + 1.0);
  noise.connect(noiseGain);
  noiseGain.connect(ctx.destination);
  noise.start(now + 0.45);
};

export const playShootSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const now = ctx.currentTime;
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  // Retro "Pew" sound: Square wave with fast frequency drop
  osc.type = 'square';
  osc.frequency.setValueAtTime(800, now);
  osc.frequency.exponentialRampToValueAtTime(100, now + 0.1);

  // Short, punchy envelope
  gain.gain.setValueAtTime(0.05, now);
  gain.gain.exponentialRampToValueAtTime(0.001, now + 0.1);

  osc.connect(gain);
  gain.connect(ctx.destination);

  osc.start(now);
  osc.stop(now + 0.1);
};

export const speakText = (text: string, rate: number = 1.0) => {
  if (!('speechSynthesis' in window)) return;

  // Cancel any ongoing speech
  window.speechSynthesis.cancel();

  const utterance = new SpeechSynthesisUtterance(text);
  utterance.lang = 'en-US';
  utterance.rate = rate; 

  // Adjust pitch slightly higher to sound "younger"
  utterance.pitch = 1.15; 

  const voices = window.speechSynthesis.getVoices();

  // Priority list for female-sounding voices
  // 'Samantha' (iOS/Mac), 'Google US English' (Android/Chrome), 'Microsoft Zira' (Windows), 'Jenny'
  const preferredNames = ['Samantha', 'Google US English', 'Zira', 'Jenny', 'Susan', 'Vicki', 'Kathy'];

  const femaleVoice = voices.find(v => 
    preferredNames.some(name => v.name.includes(name)) && v.lang.startsWith('en')
  );

  // Fallback: try to find any English voice
  const fallbackVoice = voices.find(v => v.lang.startsWith('en'));

  if (femaleVoice) {
    utterance.voice = femaleVoice;
  } else if (fallbackVoice) {
    utterance.voice = fallbackVoice;
  }

  window.speechSynthesis.speak(utterance);
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { AssetTypes, initGameAssets } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { playShootSound } from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const FPS = 60;
const SPAWN_RATE_INITIAL = 100;
const BASE_XP_REQUIREMENT = 3;

// Fixed Logical Resolution (16:9 FHD)
// The canvas will scale via CSS to fit any screen (4K, Mobile, etc.)
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

// Upgrade Definitions
const UPGRADES: UpgradeOption[] = [
  { 
    id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪',
    apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
  },
  { 
    id: 'spd_up', name: '疾风步', description: '移动速度 +10%', icon: '👟',
    apply: (s) => ({ ...s, speed: s.speed * 1.1 }) 
  },
  { 
    id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +15%', icon: '🔫',
    apply: (s) => ({ ...s, attackSpeed: Math.max(5, s.attackSpeed * 0.85) }) 
  },
  { 
    id: 'hp_up', name: '坚韧', description: '最大生命 +30, 恢复满血', icon: '❤️',
    apply: (s) => ({ ...s, maxHp: s.maxHp + 30, hp: s.maxHp + 30 }) 
  },
  { 
    id: 'multishot', name: '多重射击', description: '额外子弹 +1 (叠加)', icon: '✨',
    apply: (s) => ({ ...s, projectileCount: s.projectileCount + 1 }) 
  },
  { 
    id: 'range_up', name: '磁铁', description: '拾取范围 +50%', icon: '🧲',
    apply: (s) => ({ ...s, pickupRange: s.pickupRange * 1.5 }) 
  }
];

export const GameArena: React.FC<GameArenaProps> = ({ words, onExit }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // -- GAME STATE REFS --
  const playerRef = useRef<Entity>({
    id: 'hero', 
    x: GAME_WIDTH / 2, 
    y: GAME_HEIGHT / 2, 
    width: 64, height: 64, // Scaled up for 1080p
    type: 'HERO', vx: 0, vy: 0, hp: 100, maxHp: 100, damage: 10
  });

  const statsRef = useRef<PlayerStats>({
    hp: 100, maxHp: 100, speed: 6, // Increased base speed for larger map
    damage: 10, attackSpeed: 30, projectileSpeed: 12, pickupRange: 120,
    projectileCount: 1, 
    level: 1, xp: 0, xpToNextLevel: BASE_XP_REQUIREMENT
  });

  const enemiesRef = useRef<Entity[]>([]);
  const projectilesRef = useRef<Entity[]>([]);
  const xpGemsRef = useRef<Entity[]>([]);
  const frameCountRef = useRef(0);
  const keysRef = useRef<Record<string, boolean>>({});
  const mouseRef = useRef({ x: 0, y: 0 });
  const gameTimeRef = useRef(0);
  const isPausedRef = useRef(false);
  const animationFrameId = useRef<number>(0);

  const quizCooldownRef = useRef(0); 
  const spritesRef = useRef<Record<string, HTMLImageElement>>({});

  // -- REACT STATE --
  const [uiStats, setUiStats] = useState<PlayerStats>(statsRef.current);
  const [gameOver, setGameOver] = useState(false);
  const [quizWord, setQuizWord] = useState<WordData | null>(null);
  const [showUpgrades, setShowUpgrades] = useState<UpgradeOption[] | null>(null);
  const [gameTimeDisplay, setGameTimeDisplay] = useState(0);
  const [upgradeFocusedIndex, setUpgradeFocusedIndex] = useState(0);

  // Gamepad Polling for Upgrade Menu
  useEffect(() => {
    if (!showUpgrades) return;

    let lastAxisX = 0;
    let lastButtonState = false;

    const pollGamepad = () => {
      const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
      const gp = gamepads[0];

      if (gp) {
        const axisX = gp.axes[0];
        const isLeft = axisX < -0.5 || gp.buttons[14]?.pressed;
        const isRight = axisX > 0.5 || gp.buttons[15]?.pressed;

        if (isLeft && lastAxisX >= -0.5) {
            setUpgradeFocusedIndex(prev => Math.max(0, prev - 1));
        } else if (isRight && lastAxisX <= 0.5) {
            setUpgradeFocusedIndex(prev => Math.min(2, prev + 1));
        }
        lastAxisX = axisX;
      }
      if (showUpgrades) requestAnimationFrame(pollGamepad);
    };
    requestAnimationFrame(pollGamepad);
  }, [showUpgrades, upgradeFocusedIndex]);

  // Upgrade Selection Listener
  useEffect(() => {
    if (!showUpgrades) return;

    let lastButtonState = false;
    const checkButton = () => {
        const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
        const gp = gamepads[0];
        if (gp) {
            if (gp.buttons[0]?.pressed && !lastButtonState) {
                applyUpgrade(showUpgrades[upgradeFocusedIndex]);
            }
            lastButtonState = gp.buttons[0]?.pressed;
        }
        if (showUpgrades) requestAnimationFrame(checkButton);
    };
    requestAnimationFrame(checkButton);
  }, [showUpgrades, upgradeFocusedIndex]);

  // Initialize Assets & Inputs
  useEffect(() => {
    initGameAssets((key, url) => {
        const img = new Image();
        img.src = url;
        img.decode().then(() => { spritesRef.current[key] = img; }).catch(() => { spritesRef.current[key] = img; });
    });

    const handleKeyDown = (e: KeyboardEvent) => { 
        if (isPausedRef.current) return;
        keysRef.current[e.key.toLowerCase()] = true; 
    };
    const handleKeyUp = (e: KeyboardEvent) => { 
        keysRef.current[e.key.toLowerCase()] = false; 
    };
    const handleMouseMove = (e: MouseEvent) => { 
        if (isPausedRef.current) return;
        const canvas = canvasRef.current;
        if (canvas) {
            const rect = canvas.getBoundingClientRect();
            // Scale mouse position from Screen Pixels to Game Logical Pixels (1920x1080)
            const scaleX = GAME_WIDTH / rect.width;
            const scaleY = GAME_HEIGHT / rect.height;

            mouseRef.current = { 
                x: (e.clientX - rect.left) * scaleX, 
                y: (e.clientY - rect.top) * scaleY
            };
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousemove', handleMouseMove);

    animationFrameId.current = requestAnimationFrame(gameLoop);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousemove', handleMouseMove);
      cancelAnimationFrame(animationFrameId.current);
    };
  }, []);

  // === GAME LOOP ===
  const gameLoop = () => {
    if (gameOver) return;
    if (!isPausedRef.current) update();
    draw();
    animationFrameId.current = requestAnimationFrame(gameLoop);
  };

  // === UPDATE LOGIC ===
  const update = () => {
    const player = playerRef.current;
    const stats = statsRef.current;

    frameCountRef.current++;
    if (frameCountRef.current % 60 === 0) {
        gameTimeRef.current++;
        setGameTimeDisplay(gameTimeRef.current);
    }

    // 1. Player Movement
    let dx = 0; let dy = 0;
    // Keyboard
    if (keysRef.current['w'] || keysRef.current['arrowup']) dy -= 1;
    if (keysRef.current['s'] || keysRef.current['arrowdown']) dy += 1;
    if (keysRef.current['a'] || keysRef.current['arrowleft']) dx -= 1;
    if (keysRef.current['d'] || keysRef.current['arrowright']) dx += 1;

    // Gamepad
    const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
    const gp = gamepads[0];
    if (gp) {
        const deadzone = 0.2;
        if (Math.abs(gp.axes[0]) > deadzone) dx += gp.axes[0];
        if (Math.abs(gp.axes[1]) > deadzone) dy += gp.axes[1];
        if (gp.buttons[12]?.pressed) dy -= 1;
        if (gp.buttons[13]?.pressed) dy += 1;
        if (gp.buttons[14]?.pressed) dx -= 1;
        if (gp.buttons[15]?.pressed) dx += 1;
    }

    if (dx !== 0 || dy !== 0) {
      const length = Math.sqrt(dx * dx + dy * dy);
      const normalizedFactor = length > 1 ? 1 / length : 1;
      player.x += (dx * normalizedFactor) * stats.speed;
      player.y += (dy * normalizedFactor) * stats.speed;
    }

    // Boundary check (Fixed 1920x1080)
    player.x = Math.max(0, Math.min(GAME_WIDTH, player.x));
    player.y = Math.max(0, Math.min(GAME_HEIGHT, player.y));

    // 2. Spawning & Logic
    spawnEnemies();

    enemiesRef.current.forEach(enemy => {
      const angle = Math.atan2(player.y - enemy.y, player.x - enemy.x);
      enemy.vx = Math.cos(angle) * (enemy.type.includes('ELITE') ? 3.5 : enemy.type === 'BOSS' ? 2 : 2.5);
      enemy.vy = Math.sin(angle) * (enemy.type.includes('ELITE') ? 3.5 : enemy.type === 'BOSS' ? 2 : 2.5);
      enemy.x += enemy.vx;
      enemy.y += enemy.vy;

      if (enemy.type === 'BOSS' && frameCountRef.current % 120 === 0) spawnBossBullets(enemy);
      if (enemy.type === 'ELITE_RANGED' && frameCountRef.current % 180 === 0) spawnEnemyBullet(enemy, player);

      const dist = Math.hypot(player.x - enemy.x, player.y - enemy.y);
      if (dist < (player.width/2 + enemy.width/2)) {
         if (frameCountRef.current % 30 === 0) takeDamage(enemy.damage);
      }
    });

    // 4. Combat
    if (frameCountRef.current % stats.attackSpeed === 0) fireBullet();

    projectilesRef.current = projectilesRef.current.filter(p => {
      p.x += p.vx; p.y += p.vy;
      let hit = false;
      if (p.type === 'PROJECTILE') {
          for (const enemy of enemiesRef.current) {
            if (Math.hypot(p.x - enemy.x, p.y - enemy.y) < (enemy.width / 2 + 15)) {
              enemy.hp -= p.damage;
              hit = true;
              break;
            }
          }
      } else {
           if (Math.hypot(p.x - player.x, p.y - player.y) < (player.width / 2 + 15)) {
               takeDamage(p.damage);
               hit = true;
           }
      }
      const oob = p.x < 0 || p.x > GAME_WIDTH || p.y < 0 || p.y > GAME_HEIGHT;
      return !oob && !hit;
    });

    enemiesRef.current = enemiesRef.current.filter(e => {
      if (e.hp <= 0) {
        xpGemsRef.current.push({
          id: Math.random().toString(),
          x: e.x, y: e.y, width: 24, height: 24, type: 'XP',
          vx: 0, vy: 0, hp: 1, maxHp: 1, damage: 0
        });
        return false;
      }
      return true;
    });

    xpGemsRef.current = xpGemsRef.current.filter(gem => {
      const dist = Math.hypot(player.x - gem.x, player.y - gem.y);
      if (dist < stats.pickupRange) {
        gem.x += (player.x - gem.x) * 0.15;
        gem.y += (player.y - gem.y) * 0.15;
        if (dist < 30) {
          gainXp(1);
          return false;
        }
      }
      return true;
    });

    if (frameCountRef.current % 10 === 0) setUiStats({...statsRef.current});
  };

  // === HELPERS ===

  const spawnEnemies = () => {
      const time = gameTimeRef.current;
      const spawnRate = Math.max(20, SPAWN_RATE_INITIAL - Math.floor(time / 2)); // Faster spawn ramp

      if (time === 120 && !enemiesRef.current.some(e => e.type === 'BOSS')) {
          spawnEntity('BOSS');
          return;
      }
      if (frameCountRef.current % spawnRate === 0) {
          const r = Math.random();
          let type = 'MOB';
          if (time > 30 && r > 0.9) type = 'ELITE';
          if (time > 60 && r > 0.8) type = 'ELITE';
          spawnEntity(type as any);
      }
  };

  const spawnEntity = (category: 'MOB' | 'ELITE' | 'BOSS') => {
      const side = Math.floor(Math.random() * 4);
      let x = 0, y = 0;
      if (side === 0) { x = Math.random() * GAME_WIDTH; y = -100; }
      else if (side === 1) { x = GAME_WIDTH + 100; y = Math.random() * GAME_HEIGHT; }
      else if (side === 2) { x = Math.random() * GAME_WIDTH; y = GAME_HEIGHT + 100; }
      else { x = -100; y = Math.random() * GAME_HEIGHT; }

      // Default Entity
      let entity: Entity = {
          id: Math.random().toString(),
          x, y, vx: 0, vy: 0, 
          type: 'MOB', width: 50, height: 50, // Default size
          hp: 2, maxHp: 2, damage: 5 // Default Mob HP = 2
      };

      if (category === 'BOSS') {
          entity = { ...entity, type: 'BOSS', width: 250, height: 250, hp: 100, maxHp: 100, damage: 20, spriteUrl: AssetTypes.BOSS };
      } else if (category === 'ELITE') {
          // Elite HP = 10
          const sub = Math.random();
          if (sub < 0.33) {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_MELEE, hp: 10, maxHp: 10, damage: 15, width: 90, height: 90 }; 
          } else if (sub < 0.66) {
             entity = { ...entity, type: 'ELITE_RANGED' as any, spriteUrl: AssetTypes.ELITE_RANGED, hp: 10, maxHp: 10, damage: 10, width: 80, height: 80 }; 
          } else {
             entity = { ...entity, type: 'ELITE', spriteUrl: AssetTypes.ELITE_TANK, hp: 10, maxHp: 10, damage: 10, width: 100, height: 100 }; 
          }
      } else {
          // Mob HP = 2
          const mobTypes = [AssetTypes.MOB_1, AssetTypes.MOB_2, AssetTypes.MOB_3, AssetTypes.MOB_4, AssetTypes.MOB_5];
          entity = { ...entity, type: 'MOB', spriteUrl: mobTypes[Math.floor(Math.random() * 5)], hp: 2, maxHp: 2 };
      }
      enemiesRef.current.push(entity);
  };

  const fireBullet = () => {
    let closest = null; let minDst = Infinity; const p = playerRef.current;
    for (const e of enemiesRef.current) {
        const d = Math.hypot(e.x - p.x, e.y - p.y);
        if (d < minDst) { minDst = d; closest = e; }
    }
    if (closest) {
        playShootSound();
        const baseAngle = Math.atan2(closest.y - p.y, closest.x - p.x);
        const count = statsRef.current.projectileCount || 1;
        for (let i = 0; i < count; i++) {
             const offset = count > 1 ? (i - (count - 1) / 2) * 0.15 : 0; // Tighter spread
             const angle = baseAngle + offset;
             projectilesRef.current.push({
                id: Math.random().toString(),
                x: p.x, y: p.y, width: 14, height: 14, type: 'PROJECTILE',
                vx: Math.cos(angle) * statsRef.current.projectileSpeed,
                vy: Math.sin(angle) * statsRef.current.projectileSpeed,
                hp: 1, maxHp: 1, damage: statsRef.current.damage
            });
        }
    }
  };

  const spawnEnemyBullet = (enemy: Entity, target: Entity) => {
      const angle = Math.atan2(target.y - enemy.y, target.x - enemy.x);
      projectilesRef.current.push({
          id: Math.random().toString(),
          x: enemy.x, y: enemy.y, width: 20, height: 20, type: 'ENEMY_PROJECTILE',
          vx: Math.cos(angle) * 5, vy: Math.sin(angle) * 5, hp: 1, maxHp: 1, damage: 10
      });
  };

  const spawnBossBullets = (boss: Entity) => {
      for (let i = 0; i < 12; i++) {
          const angle = (Math.PI * 2 / 12) * i;
          projectilesRef.current.push({
              id: Math.random().toString(),
              x: boss.x, y: boss.y, width: 24, height: 24, type: 'ENEMY_PROJECTILE',
              vx: Math.cos(angle) * 6, vy: Math.sin(angle) * 6, hp: 1, maxHp: 1, damage: 15
          });
      }
  };

  const takeDamage = (amount: number) => {
      statsRef.current.hp -= amount;
      if (statsRef.current.hp <= 0) { setGameOver(true); isPausedRef.current = true; }
  };

  const gainXp = (amount: number) => {
      statsRef.current.xp += amount;
      if (statsRef.current.xp >= statsRef.current.xpToNextLevel) triggerLevelUp();
  };

  const triggerLevelUp = () => {
      isPausedRef.current = true;
      keysRef.current = {}; 
      if (quizCooldownRef.current <= 0) {
          const word = words[Math.floor(Math.random() * words.length)];
          setQuizWord(word);
          quizCooldownRef.current = Math.floor(Math.random() * 3) + 3;
      } else {
          quizCooldownRef.current -= 1;
          showUpgradeMenu();
      }
  };

  const showUpgradeMenu = () => {
      const options = [...UPGRADES].sort(() => 0.5 - Math.random()).slice(0, 3);
      setShowUpgrades(options);
      setUpgradeFocusedIndex(1);
  };

  const handleQuizResult = (correct: boolean) => {
      setQuizWord(null);
      if (correct) { showUpgradeMenu(); } 
      else {
          statsRef.current.xp = 0;
          statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.2);
          isPausedRef.current = false;
      }
  };

  const applyUpgrade = (opt: UpgradeOption) => {
      statsRef.current = opt.apply(statsRef.current);
      // ALWAYS ADD 1 PROJECTILE ON LEVEL UP (Requirement)
      statsRef.current.projectileCount += 1;

      statsRef.current.level += 1;
      statsRef.current.xp = 0;
      statsRef.current.xpToNextLevel = Math.ceil(statsRef.current.xpToNextLevel * 1.2);
      setShowUpgrades(null);
      isPausedRef.current = false;
  };

  const toggleFullscreen = () => {
      if (!document.fullscreenElement) {
          document.documentElement.requestFullscreen();
      } else {
          document.exitFullscreen();
      }
  };

  // === DRAW ===
  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Background
    ctx.fillStyle = '#f0f9ff'; 
    ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);

    // Grid
    ctx.strokeStyle = '#e2e8f0';
    ctx.lineWidth = 1;
    const gridSize = 100;
    for (let x = 0; x < GAME_WIDTH; x += gridSize) {
        ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, GAME_HEIGHT); ctx.stroke();
    }
    for (let y = 0; y < GAME_HEIGHT; y += gridSize) {
        ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(GAME_WIDTH, y); ctx.stroke();
    }

    const drawSprite = (e: Entity, fallbackColor: string) => {
        const sprite = e.spriteUrl ? spritesRef.current[e.spriteUrl] || spritesRef.current[e.type] : null;
        if (sprite && sprite.complete && sprite.naturalWidth > 0) {
            ctx.drawImage(sprite, e.x - e.width/2, e.y - e.height/2, e.width, e.height);
        } else {
            ctx.fillStyle = fallbackColor;
            if (e.type === 'XP') {
                ctx.beginPath(); ctx.arc(e.x, e.y, e.width/2, 0, Math.PI * 2); ctx.fill();
            } else {
                ctx.fillRect(e.x - e.width/2, e.y - e.height/2, e.width, e.height);
            }
        }
    };

    xpGemsRef.current.forEach(gem => drawSprite(gem, '#fbbf24'));
    enemiesRef.current.forEach(e => {
        drawSprite(e, e.type === 'BOSS' ? '#dc2626' : '#64748b');
        if (e.type !== 'MOB') {
            ctx.fillStyle = 'red'; ctx.fillRect(e.x - e.width/2, e.y - e.height/2 - 15, e.width, 6);
            ctx.fillStyle = 'green'; ctx.fillRect(e.x - e.width/2, e.y - e.height/2 - 15, e.width * (e.hp/e.maxHp), 6);
        }
    });
    drawSprite(playerRef.current, '#6366f1');
    projectilesRef.current.forEach(p => {
        ctx.fillStyle = p.type === 'PROJECTILE' ? '#fbbf24' : '#ef4444';
        ctx.beginPath(); ctx.arc(p.x, p.y, p.width/2, 0, Math.PI*2); ctx.fill();
    });
  };

  return (
    <div className="fixed inset-0 w-full h-full bg-black flex items-center justify-center cursor-crosshair">
      <canvas 
        ref={canvasRef} 
        width={GAME_WIDTH} 
        height={GAME_HEIGHT}
        className="bg-slate-50 shadow-2xl"
        style={{
            width: '100%',
            height: '100%',
            objectFit: 'contain',
            aspectRatio: '16/9'
        }}
      />

      {/* Fullscreen Toggle */}
      <button 
        onClick={toggleFullscreen}
        className="fixed top-4 right-4 z-50 bg-white/20 hover:bg-white/40 text-white p-2 rounded-lg backdrop-blur-sm transition-all"
        title="Toggle Fullscreen"
      >
        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M8 3H5a2 2 0 0 0-2 2v3m18 0V5a2 2 0 0 0-2-2h-3m0 18h3a2 2 0 0 0 2-2v-3M3 16v3a2 2 0 0 0 2 2h3"/></svg>
      </button>

      {/* HUD Container */}
      <div className="fixed top-4 left-4 flex flex-col gap-2 pointer-events-none z-10">
        <div className="w-64 h-6 bg-slate-700 rounded-full border-2 border-white overflow-hidden relative shadow-lg">
             <div className="h-full bg-red-500 transition-all duration-300" style={{ width: `${(uiStats.hp / uiStats.maxHp) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-xs font-bold text-white text-shadow">
                 HP {Math.ceil(uiStats.hp)} / {uiStats.maxHp}
             </span>
        </div>
        <div className="w-64 h-4 bg-slate-700 rounded-full border border-white/50 overflow-hidden relative shadow-lg">
             <div className="h-full bg-blue-500 transition-all duration-300" style={{ width: `${(uiStats.xp / uiStats.xpToNextLevel) * 100}%` }}></div>
             <span className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white text-shadow">
                 LVL {uiStats.level} (Bullets: {uiStats.projectileCount})
             </span>
        </div>
      </div>

      <div className="fixed top-4 left-1/2 -translate-x-1/2 text-2xl font-black text-white drop-shadow-lg font-mono pointer-events-none z-10">
          {Math.floor(gameTimeDisplay / 60).toString().padStart(2, '0')}:{(gameTimeDisplay % 60).toString().padStart(2, '0')}
      </div>

      {quizWord && <GameQuizModal word={quizWord} allWords={words} onResult={handleQuizResult} />}

      {showUpgrades && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md animate-fade-in">
              <div className="max-w-4xl w-full p-8">
                  <h2 className="text-4xl font-black text-yellow-400 text-center mb-2 uppercase tracking-widest drop-shadow-md">Level Up!</h2>
                  <p className="text-center text-yellow-200 mb-8 font-bold">+1 额外子弹 (被动获取)</p>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      {showUpgrades.map((opt, index) => (
                          <button 
                            key={opt.id}
                            onClick={() => applyUpgrade(opt)}
                            className={`p-6 rounded-2xl flex flex-col items-center gap-4 transition-all group border-2
                                ${upgradeFocusedIndex === index 
                                    ? 'bg-slate-700 border-yellow-400 scale-110 shadow-xl shadow-yellow-500/20' 
                                    : 'bg-slate-800 border-slate-600 hover:border-yellow-400 hover:bg-slate-700'
                                }`}
                          >
                              <div className={`text-6xl ${upgradeFocusedIndex === index ? 'animate-bounce' : 'group-hover:animate-bounce'}`}>{opt.icon}</div>
                              <div className="text-2xl font-bold text-white">{opt.name}</div>
                              <div className="text-slate-400 text-center">{opt.description}</div>
                              {upgradeFocusedIndex === index && (
                                  <div className="text-yellow-400 text-sm font-bold mt-2 animate-pulse">[ A ] SELECT</div>
                              )}
                          </button>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {gameOver && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-red-900/90 backdrop-blur-md">
              <div className="text-center p-12 bg-white rounded-3xl shadow-2xl max-w-lg w-full">
                  <h1 className="text-5xl font-black text-red-600 mb-2">YOU DIED</h1>
                  <p className="text-slate-500 mb-8 text-xl">生存时间: {Math.floor(gameTimeDisplay / 60)}分 {gameTimeDisplay % 60}秒</p>
                  <p className="text-indigo-600 font-bold mb-8">等级: {uiStats.level}</p>
                  <div className="flex gap-4 justify-center">
                    <button onClick={() => window.location.reload()} className="px-8 py-3 bg-slate-800 text-white font-bold rounded-xl hover:bg-slate-700">重试</button>
                    <button onClick={onExit} className="px-8 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700">退出</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

// Singleton AudioContext to avoid hitting mobile browser limits
let audioCtx: AudioContext | null = null;

const getAudioContext = () => {
  if (!audioCtx) {
    const Ctx = window.AudioContext || (window as any).webkitAudioContext;
    if (Ctx) {
      audioCtx = new Ctx();
    }
  }
  return audioCtx;
};

// Call this on user interaction (e.g. click) to unlock audio on iOS
export const resumeAudioContext = () => {
  const ctx = getAudioContext();
  if (ctx && ctx.state === 'suspended') {
    ctx.resume().catch(e => console.error("Audio resume failed", e));
  }
};

// Simple synth sounds to avoid external dependencies
export const playSuccessSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const now = ctx.currentTime;

  // Helper to play a bell-like note
  const playNote = (freq: number, startTime: number, duration: number) => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = 'sine'; // Sine wave for a pure bell tone
    osc.frequency.setValueAtTime(freq, startTime);

    // Envelope for bell sound: fast attack, exponential decay
    gain.gain.setValueAtTime(0, startTime);
    gain.gain.linearRampToValueAtTime(0.15, startTime + 0.02); // Quick attack
    gain.gain.exponentialRampToValueAtTime(0.001, startTime + duration); // Long decay

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(startTime);
    osc.stop(startTime + duration);
  };

  // Play "Ding" (High Note, e.g., E5)
  playNote(659.25, now, 0.8);

  // Play "Dong" (Lower Note, e.g., C5) slightly later
  playNote(523.25, now + 0.25, 1.2);
};

export const playErrorSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  osc.type = 'sawtooth';
  osc.frequency.setValueAtTime(200, ctx.currentTime);
  osc.frequency.linearRampToValueAtTime(100, ctx.currentTime + 0.2);

  gain.gain.setValueAtTime(0.1, ctx.currentTime);
  gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.3);

  osc.connect(gain);
  gain.connect(ctx.destination);

  osc.start();
  osc.stop(ctx.currentTime + 0.3);
};

export const playVictorySound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const now = ctx.currentTime;

  const playNote = (freq: number, startTime: number, duration: number, type: OscillatorType = 'triangle') => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = type;
    osc.frequency.setValueAtTime(freq, startTime);

    gain.gain.setValueAtTime(0, startTime);
    gain.gain.linearRampToValueAtTime(0.2, startTime + 0.05);
    gain.gain.linearRampToValueAtTime(0, startTime + duration);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(startTime);
    osc.stop(startTime + duration);
  };

  // C Major Arpeggio fanfare
  playNote(523.25, now, 0.2);       // C5
  playNote(659.25, now + 0.15, 0.2); // E5
  playNote(783.99, now + 0.30, 0.2); // G5
  playNote(1046.50, now + 0.45, 0.8, 'sine'); // C6 (Long)

  // Confetti sound (noise burst)
  const bufferSize = ctx.sampleRate * 1; 
  const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
  const data = buffer.getChannelData(0);
  for (let i = 0; i < bufferSize; i++) {
    data[i] = Math.random() * 2 - 1;
  }
  const noise = ctx.createBufferSource();
  noise.buffer = buffer;
  const noiseGain = ctx.createGain();
  noiseGain.gain.setValueAtTime(0.1, now + 0.45);
  noiseGain.gain.exponentialRampToValueAtTime(0.001, now + 1.0);
  noise.connect(noiseGain);
  noiseGain.connect(ctx.destination);
  noise.start(now + 0.45);
};

export const playShootSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const now = ctx.currentTime;
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  // Retro "Pew" sound: Square wave with fast frequency drop
  osc.type = 'square';
  osc.frequency.setValueAtTime(800, now);
  osc.frequency.exponentialRampToValueAtTime(100, now + 0.1);

  // Short, punchy envelope
  gain.gain.setValueAtTime(0.05, now);
  gain.gain.exponentialRampToValueAtTime(0.001, now + 0.1);

  osc.connect(gain);
  gain.connect(ctx.destination);

  osc.start(now);
  osc.stop(now + 0.1);
};

export const playHitSound = () => {
  const ctx = getAudioContext();
  if (!ctx) return;

  const t = ctx.currentTime;

  // Impact noise (thud/splat)
  const bufferSize = ctx.sampleRate * 0.1; // 100ms
  const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
  const data = buffer.getChannelData(0);
  for (let i = 0; i < bufferSize; i++) {
    data[i] = Math.random() * 2 - 1;
  }
  const noise = ctx.createBufferSource();
  noise.buffer = buffer;

  // Lowpass filter to make it sound like a solid hit rather than hiss
  const filter = ctx.createBiquadFilter();
  filter.type = 'lowpass';
  filter.frequency.setValueAtTime(1000, t);
  filter.frequency.linearRampToValueAtTime(100, t + 0.1);

  const gain = ctx.createGain();
  gain.gain.setValueAtTime(0.2, t);
  gain.gain.exponentialRampToValueAtTime(0.001, t + 0.1);

  noise.connect(filter);
  filter.connect(gain);
  gain.connect(ctx.destination);

  noise.start(t);
};

export const speakText = (text: string, rate: number = 1.0) => {
  if (!('speechSynthesis' in window)) return;

  // Cancel any ongoing speech
  window.speechSynthesis.cancel();

  const utterance = new SpeechSynthesisUtterance(text);
  utterance.lang = 'en-US';
  utterance.rate = rate; 

  // Adjust pitch slightly higher to sound "younger"
  utterance.pitch = 1.15; 

  const voices = window.speechSynthesis.getVoices();

  // Priority list for female-sounding voices
  // 'Samantha' (iOS/Mac), 'Google US English' (Android/Chrome), 'Microsoft Zira' (Windows), 'Jenny'
  const preferredNames = ['Samantha', 'Google US English', 'Zira', 'Jenny', 'Susan', 'Vicki', 'Kathy'];

  const femaleVoice = voices.find(v => 
    preferredNames.some(name => v.name.includes(name)) && v.lang.startsWith('en')
  );

  // Fallback: try to find any English voice
  const fallbackVoice = voices.find(v => v.lang.startsWith('en'));

  if (femaleVoice) {
    utterance.voice = femaleVoice;
  } else if (fallbackVoice) {
    utterance.voice = fallbackVoice;
  }

  window.speechSynthesis.speak(utterance);
};

import React, { useRef, useEffect, useState } from 'react';
import { WordData, Entity, PlayerStats, UpgradeOption } from '../types';
import { AssetTypes, initGameAssets } from '../services/gameAssetService';
import { GameQuizModal } from './GameQuizModal';
import { playShootSound, playHitSound } from '../services/audioService';

interface GameArenaProps {
  words: WordData[];
  onExit: () => void;
}

// === CONFIGURATION ===
const FPS = 60;
const SPAWN_RATE_INITIAL = 100;
const BASE_XP_REQUIREMENT = 3;

// Fixed Logical Resolution (16:9 FHD)
// The canvas will scale via CSS to fit any screen (4K, Mobile, etc.)
const GAME_WIDTH = 1920;
const GAME_HEIGHT = 1080;

// Upgrade Definitions
const UPGRADES: UpgradeOption[] = [
  { 
    id: 'dmg_up', name: '肌肉强化', description: '伤害 +20%', icon: '💪',
    apply: (s) => ({ ...s, damage: Math.ceil(s.damage * 1.2) }) 
  },
  { 
    id: 'spd_up', name: '疾风步', description: '移动速度 +10%', icon: '👟',
    apply: (s) => ({ ...s, speed: s.speed * 1.1 }) 
  },
  { 
    id: 'atk_spd', name: '疯狂射击', description: '攻击速度 +15%', icon: '🔫',
    apply: (s) => ({ ...s, attackSpeed: Math.max(5, s.attackSpeed * 0.85) }) 
  },
  { 
