export const initGameAssets = (onAssetLoaded: (key: string, url: string) => void) => {
  // Load assets one by one with delay to avoid rate limits
  const keys = Object.keys(Prompts);

  const loadNext = (index: number) => {
    if (index >= keys.length) return;

    const key = keys[index];
    const cached = localStorage.getItem(`asset_${key}`);

    if (cached) {
      onAssetLoaded(key, cached);
      loadNext(index + 1);
    } else {
      // 1.5s delay between generations
      setTimeout(async () => {
        try {
          const url = await generateGameAsset(Prompts[key]);
          if (url) {
            try {
              localStorage.setItem(`asset_${key}`, url);
            } catch (e) {
              // Storage full, ignore
            }
            onAssetLoaded(key, url);
          }
        } catch (e) {
          console.warn(`Failed to load asset ${key}`, e);
        }
        loadNext(index + 1);
      }, 1500);
    }
  };

  loadNext(0);
};

import React, { useState, useEffect } from 'react';
import { GameArena } from './components/GameArena';
import { WordInput } from './components/WordInput';
import { WordData, AppState } from './types';
import { Toaster, toast } from 'react-hot-toast';
import { streamVocabularyEnrichment } from './services/geminiService';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.INPUT); 
  const [words, setWords] = useState<WordData[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [showInput, setShowInput] = useState(true);

  // Initial Load - Check LocalStorage
  useEffect(() => {
    const savedWords = localStorage.getItem('lexi_week_words');
    const savedTime = localStorage.getItem('lexi_week_start');

    if (savedWords && savedTime) {
       // Optional: Check if it's a new week (e.g., > 7 days)
       // For now, just load if it exists
       try {
           const parsed = JSON.parse(savedWords);
           if (parsed.length > 0) {
               setWords(parsed);
               setShowInput(false);
           }
       } catch (e) {
           console.error("Failed to load words", e);
       }
    }
  }, []);

  const handleWordSubmit = async (rawWords: string[]) => {
      setIsLoading(true);
      const newWords: WordData[] = [];
      // Clear previous words if overwriting
      setWords([]); 

      try {
          await streamVocabularyEnrichment(rawWords, (word) => {
              newWords.push(word);
              setWords(prev => [...prev, word]);
          });

          // Save to local storage
          localStorage.setItem('lexi_week_words', JSON.stringify(newWords));
          localStorage.setItem('lexi_week_start', Date.now().toString());

          toast.success(`成功生成 ${newWords.length} 个单词的词库！`);
          setShowInput(false);
      } catch (e: any) {
          toast.error("生成失败: " + (e.message || "未知错误"));
          // Restore if failed? Or just leave empty to try again
      } finally {
          setIsLoading(false);
      }
  };

  const handleReset = () => {
      if (window.confirm("确定要重新输入本周词汇吗？当前进度将重置。")) {
          setWords([]);
          localStorage.removeItem('lexi_week_words');
          setShowInput(true);
          setAppState(AppState.INPUT);
      }
  };

  // Gamepad Polling for Start Screen
  useEffect(() => {
    if (appState !== AppState.INPUT || showInput) return;

    let rafId: number;
    let lastButtonState = false;

    const pollGamepad = () => {
      const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
      const gp = gamepads[0];

      if (gp) {
        // Button 0 is usually A (Xbox) / X (PS) / B (Nintendo)
        if (gp.buttons[0]?.pressed && !lastButtonState) {
          setAppState(AppState.GAME);
          return; 
        }
        lastButtonState = gp.buttons[0]?.pressed;
      }
      rafId = requestAnimationFrame(pollGamepad);
    };

    rafId = requestAnimationFrame(pollGamepad);
    return () => cancelAnimationFrame(rafId);
  }, [appState, showInput]);

  return (
    <div className="w-full h-screen bg-slate-900 overflow-hidden relative text-slate-100 font-sans">

      {appState === AppState.INPUT && (
        <div className="w-full h-full flex flex-col items-center justify-center p-4 bg-pattern relative">
             <div className="absolute inset-0 bg-slate-900 opacity-90 z-0"></div>

             <div className="relative z-10 w-full max-w-4xl">
                 {showInput ? (
                     <WordInput 
                        onSubmit={handleWordSubmit} 
                        isLoading={isLoading} 
                        hasExistingData={words.length > 0}
                        onCancel={words.length > 0 ? () => setShowInput(false) : undefined}
                     />
                 ) : (
                     <div className="bg-white rounded-2xl p-8 shadow-2xl text-center animate-fade-in-up">
