import React, { useState, useEffect } from 'react';
import { GameArena } from './components/GameArena';
import { WordInput } from './components/WordInput';
import { Dashboard } from './components/Dashboard';
import { QuizSession } from './components/QuizSession';
import { WordData, AppState, QuizResult } from './types';
import { Toaster, toast } from 'react-hot-toast';
import { streamVocabularyEnrichment } from './services/geminiService';

const WEEK_MS = 7 * 24 * 60 * 60 * 1000;

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.INPUT); 
  const [words, setWords] = useState<WordData[]>([]);
  const [cycleStart, setCycleStart] = useState<number>(0);
  const [isLoading, setIsLoading] = useState(false);
  const [isQuizMode, setIsQuizMode] = useState(false);

  // Initial Load - Check LocalStorage safely
  useEffect(() => {
    const savedWords = localStorage.getItem('lexi_week_words');
    const savedTime = localStorage.getItem('lexi_week_start');

    if (savedWords && savedTime) {
       try {
           const startTime = parseInt(savedTime, 10);
           const now = Date.now();

           // Check for Data Corruption by parsing first
           const parsedWords = JSON.parse(savedWords);

           // Check for Weekly Expiry
           if (now - startTime > WEEK_MS) {
               console.log("Week expired, resetting...");
               localStorage.removeItem('lexi_week_words');
               localStorage.removeItem('lexi_week_start');
               setAppState(AppState.INPUT);
           } else {
               // Load Data
               if (Array.isArray(parsedWords) && parsedWords.length > 0) {
                   setWords(parsedWords);
                   setCycleStart(startTime);
                   // If we have words, we are technically in "Input" state but showing the Dashboard
                   // The Dashboard is part of the INPUT state in this simplified view, or we can add a DASHBOARD state.
                   // For now, let's say if words exist, we show the dashboard view within the input wrapper or change state logic.
                   // To keep types simple, we'll use a boolean flag in render or just use state.
               }
           }
       } catch (e) {
           console.error("Data corruption detected, resetting storage.", e);
           localStorage.removeItem('lexi_week_words');
           localStorage.removeItem('lexi_week_start');
           setWords([]);
           setAppState(AppState.INPUT);
       }
    }
  }, []);

  const handleWordSubmit = async (rawWords: string[]) => {
      setIsLoading(true);
      const newWords: WordData[] = [];
      setWords([]); // Clear current view

      try {
          await streamVocabularyEnrichment(rawWords, (word) => {
              newWords.push(word);
              setWords(prev => [...prev, word]);
          });

          const now = Date.now();
          setCycleStart(now);

          // Save to local storage safely
          try {
             localStorage.setItem('lexi_week_words', JSON.stringify(newWords));
             localStorage.setItem('lexi_week_start', now.toString());
          } catch (e) {
             toast.error("存储空间不足，部分数据可能未保存");
          }

          toast.success(`成功生成 ${newWords.length} 个单词的词库！`);
      } catch (e: any) {
          toast.error("生成失败: " + (e.message || "未知错误"));
      } finally {
          setIsLoading(false);
      }
  };

  const handleReset = () => {
      if (window.confirm("确定要重新输入本周词汇吗？当前进度将重置。")) {
          setWords([]);
          setCycleStart(0);
          localStorage.removeItem('lexi_week_words');
          localStorage.removeItem('lexi_week_start');
          setAppState(AppState.INPUT);
      }
  };

  const handleUpdateWord = (id: string, updates: Partial<WordData>) => {
      const updatedWords = words.map(w => w.id === id ? { ...w, ...updates } : w);
      setWords(updatedWords);
      localStorage.setItem('lexi_week_words', JSON.stringify(updatedWords));
  };

  // Gamepad Polling for Dashboard Start
  useEffect(() => {
    if (appState !== AppState.INPUT || words.length === 0 || isQuizMode) return;

    let rafId: number;
    let lastButtonState = false;

    const pollGamepad = () => {
      const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
      const gp = gamepads[0];

      if (gp) {
        // Button 0 (A/X) to Start Game
        if (gp.buttons[0]?.pressed && !lastButtonState) {
          setAppState(AppState.GAME);
        }
        lastButtonState = gp.buttons[0]?.pressed;
      }
      rafId = requestAnimationFrame(pollGamepad);
    };

    rafId = requestAnimationFrame(pollGamepad);
    return () => cancelAnimationFrame(rafId);
  }, [appState, words.length, isQuizMode]);

  return (
    <div className="w-full h-screen bg-slate-900 overflow-hidden relative text-slate-100 font-sans">

      {appState === AppState.INPUT && (
        <div className="w-full h-full flex flex-col items-center justify-center p-4 bg-pattern relative overflow-y-auto">
             <div className="absolute inset-0 bg-slate-900 opacity-90 z-0 pointer-events-none"></div>

             <div className="relative z-10 w-full max-w-4xl py-8">
                 {isQuizMode ? (
                     <QuizSession 
                        words={words}
                        onComplete={() => setIsQuizMode(false)}
                        onUpdateWord={handleUpdateWord}
                        onExit={() => setIsQuizMode(false)}
                     />
                 ) : words.length > 0 ? (
                     <Dashboard 
                        words={words}
                        cycleStart={cycleStart}
                        onStartQuiz={() => setIsQuizMode(true)}
                        onNewWeek={handleReset}
                     />
                 ) : (
                     <WordInput 
                        onSubmit={handleWordSubmit} 
                        isLoading={isLoading} 
                        hasExistingData={false}
                     />
                 )}

                 {/* Game Start Overlay for Dashboard */}
                 {!isQuizMode && words.length > 0 && (
                     <div className="mt-8 text-center animate-fade-in">
                         <button 
                            onClick={() => setAppState(AppState.GAME)}
                            className="group relative py-4 px-12 bg-indigo-600 text-white font-bold rounded-xl text-xl shadow-lg hover:bg-indigo-700 hover:scale-105 transition-all overflow-hidden"
                         >
                             <span className="relative z-10 flex items-center gap-2">
                                ⚔️ 进入生存挑战
                             </span>
                             <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform"></div>
                         </button>
                         <div className="mt-3 text-slate-500 text-xs font-mono tracking-widest">
                            按 [ A ] 键或点击开始
                         </div>
                     </div>
                 )}
             </div>
        </div>
      )}

      {appState === AppState.GAME && (
        <GameArena 
          words={words} 
          onExit={() => setAppState(AppState.INPUT)}
        />
      )}

      <Toaster position="top-center" toastOptions={{
          style: {
              background: '#1e293b',
              color: '#fff',
              border: '1px solid #334155'
          }
      }} />
    </div>
  );
};

