// Prompts for pixel art assets
const Prompts: Record<string, string> = {
  [AssetTypes.HERO]: "pixel art sprite sheet of a warrior character walking, horizontal strip, 6 frames, white background, isolated, RPG style",
  [AssetTypes.HERO_DOWN]: "pixel art sprite sheet of a warrior character walking towards camera, horizontal strip, 6 frames, white background, isolated, RPG style",
  [AssetTypes.HERO_UP]: "pixel art sprite sheet of a warrior character walking away from camera, horizontal strip, 6 frames, white background, isolated, RPG style",
  [AssetTypes.HERO_LEFT]: "pixel art sprite sheet of a warrior character walking left, horizontal strip, 6 frames, white background, isolated, RPG style",
  [AssetTypes.HERO_RIGHT]: "pixel art sprite sheet of a warrior character walking right, horizontal strip, 6 frames, white background, isolated, RPG style",

  [AssetTypes.MOB_1]: "pixel art slime monster, green, simple, white background, isolated, RPG style",
  [AssetTypes.MOB_2]: "pixel art bat monster, black, flying, white background, isolated, RPG style",
  [AssetTypes.MOB_3]: "pixel art skeleton warrior, tiny, white background, isolated, RPG style",
  [AssetTypes.MOB_4]: "pixel art goblin with dagger, tiny, green, white background, isolated, RPG style",
  [AssetTypes.MOB_5]: "pixel art ghost, transparent, tiny, white background, isolated, RPG style",

  [AssetTypes.ELITE_MELEE]: "pixel art large orc warrior with axe, elite enemy, white background, isolated, RPG style",
  [AssetTypes.ELITE_RANGED]: "pixel art dark mage casting spell, elite enemy, purple robes, white background, isolated, RPG style",
  [AssetTypes.ELITE_TANK]: "pixel art iron golem, heavy armor, elite enemy, white background, isolated, RPG style",

  [AssetTypes.BOSS]: "pixel art giant dragon boss, menacing, red, white background, isolated, RPG style",
  [AssetTypes.PROJECTILE]: "pixel art fireball projectile, small, round, orange, white background, isolated, RPG style",
  [AssetTypes.XP]: "pixel art experience gem, blue crystal, shiny, white background, isolated, RPG style"
};

export const initGameAssets = (onAssetLoaded: (key: string, url: string) => void) => {
  // We prioritize Hero and a few mobs to get the game running fast
  const priorityKeys = [AssetTypes.HERO, AssetTypes.MOB_1, AssetTypes.PROJECTILE];
  const allKeys = Object.keys(Prompts);

  // Sort keys so priority ones are first
  const sortedKeys = [...priorityKeys, ...allKeys.filter(k => !priorityKeys.includes(k))];

  const loadNext = (index: number) => {
    if (index >= sortedKeys.length) return;

    const key = sortedKeys[index];
    let cached = null;

    try {
        cached = localStorage.getItem(`asset_${key}`);
    } catch (e) {
        console.warn("Local storage error reading asset", e);
    }

    if (cached) {
      onAssetLoaded(key, cached);
      // Fast track for cached items
      setTimeout(() => loadNext(index + 1), 50);
    } else {
      // 2s delay between generations to be safe with rate limits
      setTimeout(async () => {
        try {
          // Only generate if we don't have it
          const url = await generateGameAsset(Prompts[key]);
          if (url) {
            try {
              localStorage.setItem(`asset_${key}`, url);
            } catch (e) {
              console.warn("Storage full, cannot cache asset", key);
            }
            onAssetLoaded(key, url);
          }
        } catch (e) {
          console.warn(`Failed to load asset ${key}`, e);
        }
        loadNext(index + 1);
      }, 2000);
    }
  };

  loadNext(0);
};

