  const [appState] = useState<AppState>(AppState.GAME); 
  const [words] = useState<WordData[]>(DEFAULT_WORDS);

  return (
    <div className="w-full h-screen bg-slate-900 overflow-hidden relative text-slate-100 font-sans">

      {appState === AppState.GAME && (
        <GameArena 
          words={words} 
          // 游戏结束或退出时刷新页面重新开始
          onExit={() => window.location.reload()}
        />
      )}

      <Toaster position="top-center" toastOptions={{
          style: {
              background: '#1e293b',
              color: '#fff',
              border: '1px solid #334155'
          }
      }} />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { GameArena } from './components/GameArena';
import { WordInput } from './components/WordInput';
import { Dashboard } from './components/Dashboard';
import { WordData, AppState } from './types';
import { Toaster, toast } from 'react-hot-toast';
import { streamVocabularyEnrichment } from './services/geminiService';

// 默认的14个单词，包含释义、词性和例句
const DEFAULT_WORDS: WordData[] = [
  { id: '1', word: 'serendipity', definition: 'n. 意外发现珍奇事物的本领；机缘凑巧', partOfSpeech: 'noun', exampleSentence: 'It was pure serendipity that we met.', correctCount: 0, quote: { english: "Serendipity is looking for a needle in a haystack and finding a farmer's daughter.", chinese: "机缘就是在草堆里找针，结果找到了农夫的女儿。" } },
  { id: '2', word: 'ephemeral', definition: 'adj. 短暂的；朝生暮死的', partOfSpeech: 'adjective', exampleSentence: 'Fashions are ephemeral, changing with every season.', correctCount: 0 },
  { id: '3', word: 'resilient', definition: 'adj. 有弹性的；能复原的；适应力强的', partOfSpeech: 'adjective', exampleSentence: 'She is resilient and quick to recover from setbacks.', correctCount: 0 },
  { id: '4', word: 'oblivion', definition: 'n. 遗忘；湮没；无意识', partOfSpeech: 'noun', exampleSentence: 'He drank himself into oblivion.', correctCount: 0 },
  { id: '5', word: 'solitude', definition: 'n. 独处；独居', partOfSpeech: 'noun', exampleSentence: 'He enjoyed the solitude of the quiet morning.', correctCount: 0 },
  { id: '6', word: 'aesthetic', definition: 'adj. 美学的；审美的', partOfSpeech: 'adjective', exampleSentence: 'The building has little aesthetic appeal.', correctCount: 0 },
  { id: '7', word: 'ineffable', definition: 'adj. 不可言喻的；难以形容的', partOfSpeech: 'adjective', exampleSentence: 'The beauty of the sunset was ineffable.', correctCount: 0 },
  { id: '8', word: 'sonder', definition: 'n. (新词) 意识到过客也有自己复杂生活的时刻', partOfSpeech: 'noun', exampleSentence: 'He felt a moment of sonder watching the crowd.', correctCount: 0 },
  { id: '9', word: 'mellifluous', definition: 'adj. (声音) 甜美的；流畅的', partOfSpeech: 'adjective', exampleSentence: 'She had a rich, mellifluous voice.', correctCount: 0 },
  { id: '10', word: 'limerence', definition: 'n. 迷恋；神魂颠倒', partOfSpeech: 'noun', exampleSentence: 'The state of limerence can be overwhelming.', correctCount: 0 },
  { id: '11', word: 'petrichor', definition: 'n. 雨后泥土的芬芳', partOfSpeech: 'noun', exampleSentence: 'I love the smell of petrichor after a storm.', correctCount: 0 },
  { id: '12', word: 'luminescence', definition: 'n. 冷光；发光', partOfSpeech: 'noun', exampleSentence: 'The bioluminescence of the plankton lit up the waves.', correctCount: 0 },
  { id: '13', word: 'ethereal', definition: 'adj. 飘渺的；超凡的', partOfSpeech: 'adjective', exampleSentence: 'Her beauty was ethereal, almost unearthly.', correctCount: 0 },
  { id: '14', word: 'epiphany', definition: 'n. 顿悟；显现', partOfSpeech: 'noun', exampleSentence: 'I had an epiphany about how to solve the problem.', correctCount: 0 }
];

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.INPUT); 
  // 默认直接加载 DEFAULT_WORDS，这样用户直接看到仪表盘，不用输入
  const [words, setWords] = useState<WordData[]>(DEFAULT_WORDS);
  const [cycleStart, setCycleStart] = useState<number>(Date.now());
  const [isLoading, setIsLoading] = useState(false);

  // 手柄监听：在 INPUT 界面按 A 键进入游戏
  useEffect(() => {
    if (appState !== AppState.INPUT) return;

    let rafId: number;
    let lastButtonState = false;

    const pollGamepad = () => {
      const gamepads = navigator.getGamepads ? navigator.getGamepads() : [];
      const gp = gamepads[0];

      if (gp) {
        // Button 0 (A/X/Cross) 
        if (gp.buttons[0]?.pressed && !lastButtonState) {
          // 如果有单词，则开始游戏
          if (words.length > 0) {
            setAppState(AppState.GAME);
          }
        }
        lastButtonState = gp.buttons[0]?.pressed;
      }
      rafId = requestAnimationFrame(pollGamepad);
    };

    rafId = requestAnimationFrame(pollGamepad);
    return () => cancelAnimationFrame(rafId);
  }, [appState, words.length]);

  const handleWordSubmit = async (rawWords: string[]) => {
      setIsLoading(true);
      setWords([]); 

      try {
          const newWords: WordData[] = [];
          await streamVocabularyEnrichment(rawWords, (word) => {
              newWords.push(word);
              setWords(prev => [...prev, word]);
          });
          setCycleStart(Date.now());
          toast.success(`生成成功！`);
      } catch (e: any) {
          toast.error("生成失败: " + e.message);
          // 失败时恢复默认
          setWords(DEFAULT_WORDS);
      } finally {
          setIsLoading(false);
      }
  };

  const handleReset = () => {
      if (window.confirm("确定要清空当前词库并重新输入吗？")) {
          setWords([]);
          setCycleStart(0);
      }
  };

  return (
    <div className="w-full h-screen bg-slate-900 overflow-hidden relative text-slate-100 font-sans">

      {appState === AppState.INPUT && (
        <div className="w-full h-full flex flex-col items-center justify-center p-4 bg-pattern relative overflow-y-auto">
             <div className="absolute inset-0 bg-slate-900 opacity-90 z-0 pointer-events-none"></div>

             <div className="relative z-10 w-full max-w-4xl py-8">
                 {words.length > 0 ? (
                     <>
                        <Dashboard 
                            words={words}
                            cycleStart={cycleStart}
                            onStartQuiz={() => setAppState(AppState.GAME)}
                            onNewWeek={handleReset}
                        />
                        {/* 手柄提示覆盖层 */}
                        <div className="mt-8 text-center animate-pulse">
                             <div className="inline-flex items-center gap-3 bg-indigo-900/50 border border-indigo-500/30 px-6 py-3 rounded-full backdrop-blur-md">
                                <div className="w-8 h-8 rounded-full bg-yellow-400 text-slate-900 font-black flex items-center justify-center shadow-lg transform scale-110 border-2 border-yellow-200">
                                    A
                                </div>
                                <span className="font-bold text-indigo-100 tracking-wide">按手柄 A 键开始生存挑战</span>
                             </div>
                        </div>
                     </>
                 ) : (
                     <WordInput 
                        onSubmit={handleWordSubmit} 
                        isLoading={isLoading} 
                        hasExistingData={false}
                     />
                 )}
             </div>
        </div>
      )}

      {appState === AppState.GAME && (
        <GameArena 
          words={words} 
          onExit={() => setAppState(AppState.INPUT)}
        />
      )}

      <Toaster position="top-center" toastOptions={{
          style: {
              background: '#1e293b',
              color: '#fff',
              border: '1px solid #334155'
          }
      }} />
    </div>
  );
};

export default App;
